INSERT INTO `honeybee1` VALUES ('2008-12-01 18:56:51', 'AG', -159.653320, 22.106377, 'We took a loop walk through Kokee State Park overlooking Waimea Canyon starting and ending at the YWCA campground. Can''t give exact location of feral hive but was about half way round the loop 30 feet downhill from the trail about 10 feet up a tree. Looked like a thriving hive. No idea how long it has been there.', 'Living Tree', 'Bee Keeper', 'rospletha@gmail.com', 'HI', 'Kokee State Park', '', '', 'Entered by Ann Grace', '978-952-6753', 'Yes', 2);
INSERT INTO `honeybee1` VALUES ('2010-07-01 15:18:28', 'Kevin Hansen', -155.448685, 20.036257, 'Colony in a big flowering tree alive in a hole about 10+ meters up. We filmed this hive with a telephoto video lens - at dawn pretty good footage - nice colony! It was quiet at Kalopa park and the humming of the bees made the forest hum too.', 'Living Tree', 'Concerned Citiz', 'hankaiwen@gmail.com', 'HI', 'Kalopa State Recreat', 'Honoka''a', 'unknown', '', '505-818-7217 ', 'Yes', 3);
INSERT INTO `honeybee1` VALUES ('2008-07-22 02:01:12', 'Bill Whitson', -123.823387, 46.982975, 'A small hive in a fallen tree bridging a ravine. On the border between a private yard and a park. Apparently has been there for several years. The tree fell in the Dec 2007 wind storm. Removal was not possible. Left a swarm trap.', 'Dead Tree', 'Bee Keeper', 'billspamcan@gmail.co', 'WA', '1200 Spur Street', 'Aberdeen', '98520', '', '360-589-4614', 'Yes', 4);
INSERT INTO `honeybee1` VALUES ('2008-07-22 02:08:16', 'Bill Whitson', -123.781113, 46.954773, 'A small hive in a living red cedar tree in the middle of a private driveway. Apparently new this year. About seven feet off the ground. Removal not possible.', 'Living Tree', 'Bee Keeper', 'billspamcan@gmail.co', 'WA', '921 Cowper St.', 'Cosmopolis', '98537', '', '360-589-4614', 'Yes', 5);
INSERT INTO `honeybee1` VALUES ('2009-12-15 22:17:57', 'Chambers', -123.461220, 42.452595, '20ft from ground in oak tree near gate that enters property. Hive was noticed in spring 2009', 'Living Tree', 'Concerned Citiz', 'rodc@oigp.net', 'OR', '8500 Lower River Rd', 'Grants Pass', '97526', '', '541-476-0088', 'Yes', 6);
INSERT INTO `honeybee1` VALUES ('2011-02-21 23:02:42', 'Debra Heidrich', -123.071808, 45.319744, 'Hive is approx. 25 ft. off the ground in a broken ash tree. tree is 15ft east of Chehalem creek. This hive has been here for at least 70 years.', 'Living Tree', 'Bee Keeper', 'heidrichick@yahoo.co', 'OR', '14495 NE Worden Hill', 'Newberg', '97132', '', '5035382555', 'Yes', 7);
INSERT INTO `honeybee1` VALUES ('2008-10-05 19:49:58', 'ROBERT MCAVOY', -123.018082, 43.815075, '1 FOOT OFF GROUND IN BASE OF OAK TREEBEEN THERE SINCE THIS SUMMER 2008IT''S RIGHT NEXT TO OUR DRIVEWAY IN A GOAT PADDOCK.', 'Living Tree', 'Concerned Citiz', 'HELMACK@AOL.COM', 'OR', '33546 MOLITOR RANCH ', 'COTTAGE GROVE', '97424', '', '5417673333', 'Yes', 8);
INSERT INTO `honeybee1` VALUES ('2008-11-04 18:19:56', 'Duane', -122.988800, 43.982319, 'Hive is at the base of an old tree at the SE corner of a pasture at Deerwood Rd. and Matthews Rd. The entrance is at the base of the tree facing east. Facing south was a ground yellow jacket nest also.', 'Living Tree', 'Bee Keeper', 'duaack@yahoo.com', 'OR', '', 'Glenwood', '97116', '', '', 'Yes', 9);
INSERT INTO `honeybee1` VALUES ('2010-02-18 14:29:54', 'Andrew Van Atta', -122.987305, 44.020164, 'Three feet off the ground in a medium sized Acer macrophyllum. Been checking it for the last two years. Very active. Not sure of size.', 'Living Tree', 'Other', 'avanatta@uoregon.edu', 'OR', 'Mt Pisgah Arboretum', 'Eugene', '97401', 'Behind the Arboretum Greenhouses (west northwest) aprox. 100 meters.', '541-688-1029', 'Yes', 10);
INSERT INTO `honeybee1` VALUES ('2008-11-28 02:25:44', 'Larry Edwards', -122.982277, 42.407421, 'Removed from a birdhouse. At most only a couple of years old according to the home owners.', 'Manmade Beehive', 'Bee Keeper', 'ledwards8@earthlink.', 'OR', '6225 Tamarack Lane', 'Central Point', '97502', '', '5416645839', 'Yes', 11);
INSERT INTO `honeybee1` VALUES ('2008-11-28 02:22:58', 'Larry Edwards', -122.982239, 42.407436, 'Removed from a tree which had been cut down. It is not known how long they were in the tree. (The people cutting the tree down did not even know of its existence until the tree was on the ground.)', 'Manmade Beehive', 'Bee Keeper', 'ledwards8@earthlink.', 'OR', '6225 Tamarack Lane', 'Central Point', '97502', '', '5416645839', 'Yes', 12);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Ernie Schmidt', -122.854958, 47.106472, 'Aprox. 10-12 feet off ground. First year of intentional establishment of manmade feral hive.', 'Manmade structure', 'Bee Keeper', 'Eschmidt158@aol.com', 'NC', '5439 lemon Rd NE', 'Olympia', '98506', 'In the interest of establishing a feral population of bees Foxglove Farm has installed a Conservatorial Hive in a forested acreage area of the farm. The farm keeps domestic bees under natural conditions for honey production and understands the importance of preserving the wild bee strains. ', '360-352-7449', 'Yes', 13);
INSERT INTO `honeybee1` VALUES ('2011-05-06 23:53:03', 'Martha McCabe', -122.782387, 38.353909, 'Brand New hive- went from unnoticeable to the size of a three gallon bucket in 2-3 days. Today is day 4 and it is growing more slowly now. Bees are very docile. Hive is in a tree about 6 feet off the ground at bottom of hive; 7.5 to eight feet at the top. Call me to locate. It is in my front yard behind a wood fence.', 'Living Tree', 'Concerned Citiz', 'onegreenspirit@aol.c', 'CA', '5245 Hutchinson Rd', 'Sebastopol', '95472', '', '707-696-4952', 'Yes', 14);
INSERT INTO `honeybee1` VALUES ('2009-09-20 02:32:23', 'David Orgish', -122.665092, 38.451954, 'Hive is inside hollow tree trunk. Entry is about 9'' off the ground. I noticed the hive about 6 months ago. ', 'Living Tree', 'Concerned Citiz', 'Dorgish@earthlink.ne', 'CA', '4895 Medica Rd', 'Santa Rosa', '95405', '', '707-292-9728', 'Yes', 15);
INSERT INTO `honeybee1` VALUES ('2008-10-27 14:17:40', 'Adam Kinsey', -122.625511, 38.209488, 'East side of I St Eucalyptus tree 3 ft off the ground. I''ve seen it there for 2 seasons.', 'Living Tree', 'Bee Keeper', 'suburbanapis@gmail.c', 'CA', '', 'Petaluma', '94952', '', '415.794.2695', 'Yes', 16);
INSERT INTO `honeybee1` VALUES ('2011-06-28 23:26:06', 'Volker Ackermann', -122.505615, 37.981277, 'enter the trailhead at Magarita & 255 Highland Ave. Walk down the trail / fireroad for about 300+ yards arround two bents. In one bent look up to your you see a 30 diameter eucalyptus above you to the right at about 12'' high. The hive enterance is in the middle of the stump. We know this to bee active since 2005. This winter 2010-11 it was active assuming it survived rather then taken over by a new swarm in spring. ', 'Dead Tree', 'Bee Keeper', 'volker@netwrkbiz.com', 'CA', 'Margarita', 'San Rafael', '94901', '', '4154560201', 'Yes', 17);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Patrick Schlemmer', -122.503624, 37.734604, 'This hive is at ground level under the stairs leading to the side door of the Mother''s Building. It appears to be a large healthy colony. The bees come and go through a crack in the side of the cement staircase. It has been there for at least four years.', 'Manmade structure', 'Bee Keeper', 'JKodiak@earthlink.ne', 'CA', '1 Zoo Rd. ', 'San Francisco', '94132', '', '(415) 681-7290', 'Yes', 18);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Patrick Schlemmer', -122.502541, 37.732491, 'This hive is within the hollow wall at the west end of the Pachyderm building. Probably about 20 feet off the ground. There has been a hive here for over ten years though I''m not sure if it has been the same colony or if it has been periodically repopulated. It is pretty active and visible from the front of the exhibit.', 'Manmade structure', 'Bee Keeper', 'JKodiak@earthlink.ne', 'CA', '1 Zoo Rd. ', 'San Francisco', '94114', '', '(415) 681-7290', 'Yes', 19);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Patrick Schlemmer', -122.502541, 37.732491, 'This hive is within the hollow wall at the west end of the Pachyderm building. Probably about 20 feet off the ground. There has been a hive here for over ten years though I''m not sure if it has been the same colony or if it has been periodically repopulated. It is pretty active and visible from the front of the exhibit.', 'Manmade structure', 'Bee Keeper', 'JKodiak@earthlink.ne', 'CA', '1 Zoo Rd. ', 'San Francisco', '94132', '', '(415) 681-7290', 'Yes', 20);
INSERT INTO `honeybee1` VALUES ('2008-10-27 15:13:24', 'Patrick Schlemmer', -122.501373, 37.732803, 'In a natural hole in a cypress tree just east of the Pachyderm Building about 20 feet off the ground. I first noticed it in 2007.', 'Living Tree', 'Bee Keeper', 'JKodiak@earthlink.ne', 'CA', '1 Zoo Rd. ', 'San Francisco', '94132', '', '(415) 681-7290', 'Yes', 21);
INSERT INTO `honeybee1` VALUES ('2011-04-05 19:55:11', 'Scott', -122.440918, 37.737701, 'Hardy colony at least four years in this knothole of a sycamore tree about 8 ft. off the ground. Appear to be Carniolan but have not verified this. Easy to find - on the edge of the dog run behind the Glen Park Canyon rec center on the path up to the fire road. Look for the tree nearest the giant Eucalyptus that is inside the triangle of paths/roads where the creek goes into a culvert. The colony entrance is facing the rec center. On a warm day you can easily smell their honey.', 'Living Tree', 'Bee Keeper', 'smattoon@pacbell.net', 'CA', 'Elk @ Chenery Street', 'San Francisco', '94131', '', '415-601-7101', 'Yes', 22);
INSERT INTO `honeybee1` VALUES ('2010-08-04 11:29:10', 'Dan Brehmer', -122.254692, 37.472553, '10'' off ground in live oak tree', 'Living Tree', 'Concerned Citiz', 'dan@brehmer.org', 'CA', '775 Hillcrest Dr', 'Redwood City', '94062', '', '650-924-1892', 'Yes', 23);
INSERT INTO `honeybee1` VALUES ('2011-05-26 15:10:29', 'David Greenleaf', -122.223587, 48.151428, 'In a living cedar tree acouple feet off the ground real small entrance', 'Living Tree', 'Bee Keeper', 'stilly_river_guy04@h', 'WA', 'Lakewood Rd', 'lakewood', '98271', '', '360-913-2786', 'Yes', 24);
INSERT INTO `honeybee1` VALUES ('2010-07-11 19:19:25', 'Michael Shantz', -122.192291, 37.463322, '20 feet up in large knot hole in huge live oak near playground and picnic area.', 'Living Tree', 'Bee Keeper', 'michaelshantz@sbcglo', 'CA', 'Holbrook-Palmer Park', 'Menlo Park', '94027', '', '408-996-8474', 'Yes', 25);
INSERT INTO `honeybee1` VALUES ('2011-05-30 02:44:01', 'Anna Messerschmidt', -122.184303, 37.388100, 'the hive is about 4-5 feet off the ground in a living tree the entrance faces southwest and is about the size of a quarter according to friends the hive has been around for more than one year good activity around it', 'Living Tree', 'Bee Keeper', 'annaMesserschmidt@gm', 'CA', 'Arastradero Road', 'Palo Alto', '94028', '', '650-853 1153', 'Yes', 26);
INSERT INTO `honeybee1` VALUES ('2011-07-16 15:19:33', 'Dan Brehmer', -122.169716, 37.360901, 'About 3'' off the ground in a large oak. Appears to be a very large and active hive.', 'Living Tree', 'Concerned Citiz', 'dan@brehmer.org', 'CA', 'Buena Vista Drive', 'Los Altos Hills', '94022', '', '650-924-1892', 'Yes', 27);
INSERT INTO `honeybee1` VALUES ('2010-05-14 20:55:33', 'Dan Brehmer', -122.163284, 37.457008, 'In olive tree 18 off the ground. Hole in the tree is about 2 across. It has been here for a few months but I think it was here once before years ago.', 'Living Tree', 'Concerned Citiz', 'dan@brehmer.org', 'CA', '207 Willow Road', 'Menlo Park', '94025', 'If someone would like to come extract them they are welcome to try. I understand that is not easy but we don''t want them to be harmed.', '650-924-1892', 'Yes', 28);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Phil Deering', -122.160652, 37.726173, 'Hives (+/- 5 separate units) are located within the walls of my garage. They enter from the outside and have taken up residence between the studs. The interior is paneled with 1/4 plywood which serves as a barrier so I can use my garage while they do their thing. The live of 2 side of the building east and south facing side of the garage. They swarm occasionally and we captured one this spring and now lives in the neighbors garden in a more conventional bee box. Its hard to say how large these hives are but you can smell the hiney scent when inside the garage. Was going to have them removed but the pestman said they would just come back unless we sealed the whole bldg. which has too many holes so there are now joint tenants and we share the bldg.', 'Manmade structure', 'Bee Keeper', 'radicalfil@aol.com', 'CA', '458 arroyo ave', 'san leandro', '94577', '', '510-872-2124', 'Yes', 29);
INSERT INTO `honeybee1` VALUES ('2008-10-31 23:41:25', 'S2 ', -122.156853, 37.459667, 'aprox 20 feet above ground in the hollow of a dead tree of unknown species. The tree is at the intersection of the park/school driveway and Pope Street.', 'Dead Tree', 'Bee Keeper', 'dept8@greatleapforwa', 'CA', 'Pope Street', 'Menlo Park', '94025', '', '', 'Yes', 30);
INSERT INTO `honeybee1` VALUES ('2012-01-06 19:39:12', 'mike', -122.147629, 38.221367, 'In Oak Tree along creek - been there at least two years.', 'Living Tree', 'Bee Keeper', 'vaughnm55@hardinflat', 'CA', 'Pavilion Dr.', 'Fairfield', '94534', '', '707 864 1459', 'Yes', 31);
INSERT INTO `honeybee1` VALUES ('2010-04-23 21:22:01', 'Michael Shantz', -122.064941, 37.293716, 'hollow oak tree (quercus agrifolia) entrance 3ft off ground been there more than 1 year right beside Regnart road.', 'Living Tree', 'Bee Keeper', 'michaelshantz@sbcglo', 'CA', '22345 Regnart Road', 'Cupertino', '', '', '408-996-8474', 'Yes', 32);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Michael Shantz', -122.060081, 37.290760, 'On the ground in a ravine in an old rusted metal tank been there more than two years beside the trail in Fremont Older open space preserve.', 'Manmade structure', 'Bee Keeper', 'michaelshantz@sbcglo', 'CA', '', 'Cupertino', '95014', '', '408-996-8474', 'Yes', 33);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Elaine Lea-Chou', -122.054611, 37.343262, 'couple years old between 2 studes in garage wall space from floor to ceiling using existing 4-inch hole as entrance live removal of entire colony performed by local beekeeper on 9-21-09', 'Manmade structure', 'Concerned Citiz', 'elaine@elc-bio.com', 'CA', '991 Edmonds Way', 'Sunnyvale', '94087', '', '408-749-9644', 'Yes', 34);
