INSERT INTO `honeybee1` VALUES ('2008-10-11 10:32:33', 'R Withers', -121.504204, 38.575790, 'I''ve noticed bees flying in and out of an opening in the trunk of an old elm tree for about three years now. The tree is on the northeast corner of P St. and 4th St. and the opening in the tree trunk the bees use is about 25 feet up the tree. ', 'Living Tree', 'Bee Keeper', 'rswithers@comcast.ne', 'CA', '400 P Street', 'Sacramento', '95814', '', '2093341666', 'Yes', 41);
INSERT INTO `honeybee1` VALUES ('2011-02-16 01:15:06', 'Ivy G', -121.454430, 38.593464, 'In a live tree in a field off the American River Parkway about 8 feet off the ground. There''s a huge hole in the side of the tree and it''s easy to see into this large hive. ', 'Living Tree', 'Concerned Citiz', 'iglasgo@yahoocom', 'CA', 'unknown', 'Sacramento', '95833', '', '', 'Yes', 42);
INSERT INTO `honeybee1` VALUES ('2008-10-26 11:48:04', 'T Harper', -120.965721, 38.955391, 'On west side of oak tree at ground level. On south side of Foresthill Divide Trail 1/4 mile east of where it crosses dirt road to Upper Clementine.', 'Living Tree', 'Bee Keeper', 'tomharper@att.net', 'CA', 'Foresthill Road', 'Auburn', '95603', '', '', 'Yes', 43);
INSERT INTO `honeybee1` VALUES ('2008-10-08 04:34:59', 'Steven Ames', -120.845985, 35.355087, 'Entrance is on the west side of a tree trunk about 5 feet off the ground in Bayside Bluffs Park.', 'Living Tree', 'Bee Keeper', 'stevena@apisindustri', 'CA', 'Bayshore Drive', 'Morro Bay', '93442', 'I caught 3 spring swarms from the colony in 2008; one absconded 2 are thriving. ', '805-528-5973', 'Yes', 44);
