INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David White', -119.331200, 46.299622, 'The Tapteal Greenway Association asked me to remove a feral colony in the wall of an old shed that had been displaced by a flood a decade earlier. Upon arrival I discovered two colonies and sucsessfully moved them to regular hives the Summer of 2008. The shed was being torn down and they did not want the bees killed. ', 'Manmade structure', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '', 'West Richland', '', '', '509-948-5216', 'Yes', 81);
INSERT INTO `honeybee1` VALUES ('2009-04-11 21:21:26', 'Scott Conley', -119.285965, 46.254539, '3'' off the ground. Is an established healthy and well populated colony with good brood pattern. ', 'Dead Tree', 'Bee Keeper', 'sc222@charter.net', 'WA', '', 'Richland', '99352', '', '5095826623', 'Yes', 82);
INSERT INTO `honeybee1` VALUES ('2008-10-27 19:07:15', 'Jerry Hiatt', -119.259506, 36.299217, 'Hive located in old tree located on the northeast corner of intersection along the canal. Base of tree has small opening and bees live inside hollow part. Five years plus old.', 'Living Tree', 'Bee Keeper', 'mj_hiatt@yahoo.com', 'CA', 'Lovers Lane @ Caldwe', 'Visalia', '93292', '', '559 232 1617', 'Yes', 83);
INSERT INTO `honeybee1` VALUES ('2008-10-04 14:56:53', 'David White', -119.232315, 46.261410, 'In a tree approx. 3 to 8 feet off ground. At house on the corner of Court Street and Road 108. This tree is severely weakened by disease or pests and must be cut down. Home owner has asked me to relocate to save them. This will probably be done the week of October 6-11 2008. This is for information on where I have been called about feral colonies. Please do not bother the home owner!!!!', 'Living Tree', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '', 'Pasco', '99301', '', '509-948-5216', 'Yes', 84);
INSERT INTO `honeybee1` VALUES ('2008-10-04 15:20:35', 'D', -119.170952, 46.205841, 'This is my housed where I have about 5-6 colonies. Not feral. Just mine.', 'Manmade Beehive', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '3623 W. 4th Ave', 'Kennewick', '99336', '', '509-948-5216', 'Yes', 85);
INSERT INTO `honeybee1` VALUES ('2008-10-04 15:24:04', 'David White', -119.170952, 46.205841, 'This is my housed where I have about 5-6 colonies. Not feral. Just mine.', 'Manmade Beehive', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '3623 W. 4th Ave', 'Kennewick', '99336', '', '509-948-5216', 'Yes', 86);
INSERT INTO `honeybee1` VALUES ('2008-10-04 15:12:37', 'David White', -119.166229, 46.220322, 'My brother-in law also a beekeeper got a call about a feral colony in a tree at about this location. About 5 feet up. As far as I know they are still there unless homeowner had them exterminated. No way to hive these without cutting down the tree. Approx June 2008.', 'Living Tree', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '', 'Kennewick', '99336', '', '509-948-5216', 'Yes', 87);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David White', -119.159973, 46.186749, 'In the floor of this shed. This business uses this area and requested I remove them. Employee safety was the concern. Summer 0f 2008.', 'Manmade structure', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', '', 'Kennewick', '99336', '', '509-948-5216', 'Yes', 88);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David White', -119.138145, 46.235447, 'A rather new colony of honey bees in a chimney of a one story house. Near the bottom close to the insert the home owner installed. He is not too concerned as he does not use this fireplace and it is blocked off. A feral swarm may have issued from the neighbors house next door. See the information on that.', 'Manmade structure', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', 'Rd 36 and Sylvester ', 'Pasco', '99301', '', '509-948-5216', 'Yes', 89);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David White', -119.138016, 46.234734, 'Feral colony in a 2 story home chimney. I have not personally gone up yet to investigate the exact depth. Very high and steep roof. I believe this colony is well established and has issued a number of swarms over the years due to swarm calls in the past and may have issued the swarm that is in the house just to the north.', 'Manmade structure', 'Bee Keeper', 'Davidabeemaster@yaho', 'WA', 'Rd.36 and Sylvester ', 'Pasco', '99301', '', '509-948-5216', 'Yes', 90);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David White', -119.128494, 46.171509, 'Feral colony in a decorative barrel section in a garden. Home owner would like to have the honeybees removed in the spring to ensure they are well taken care of next year by a beekeeper. I will return in the spring to remove and relocate them.', 'Manmade structure', 'Concerned Citiz', 'Davidabeemaster@yaho', 'WA', 'W 42nd and Ione Stre', 'Kennewick', '99336', '', '509-948-5216', 'Yes', 91);
