INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'frankie correia', -117.841759, 33.880390, 'My hive is 2-3 ft. from ground in a hollow space made of motar and river rock. It is enclosed on all sides and a sheet of wood on top. Beginning of April a swarm started took residence and has never left.', 'Manmade structure', 'Other', 'baileyboyone@msn.com', 'CA', '16660 carriage cir.', 'yorba linda', '92886', 'I had a hive 2 yrs. ago in the same space and hired someone to capture the bees and relocate them. Comb at the largest 9 in. long comb filled with honey. Non aggressive bees hardly had to smoke them. In Oct. 2011 had another swarm took residence there 2 months later found hundreds of dead bees all over yard and patio. Looked like these bees were poisoned just from how they were acting before they died. I was very upset and left the space alone thinking bees wouldn''t take to that spot again. I leave them alone and let them do what comes naturally they don''t distrub my family or my dogs. I would love to start a backyard hive but not sure it its to late to get them into one.', '714 422 6752', 'Yes', 113);
