INSERT INTO `honeybee1` VALUES ('2009-05-11 23:10:37', 'Chula Vista beekeepe', -117.063042, 32.633141, 'bottom of old pepper tree trunk by roots. small size hole. probably within the last month. city tree between sidewalk and street. my dog found this hive and one other at a nearby city park but someone killed the park hive by filling it with insulation foam. non-aggressive honey bees.', 'Living Tree', 'Bee Keeper', '', 'CA', 'hilltop ave.', 'chula vista ', '91910', '', '', 'Yes', 126);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'BJK', -117.051979, 32.686069, 'The hive has been under a storage cabinet in the back yard at ground level for many years. Homeowner recently asked it be removed and on August 15 2009 it the hive was extracted and moved into a Langstroth where they are happy. ', 'Manmade structure', 'Bee Keeper', 'info4britt@yahoo.com', 'CA', 'Alta View', 'San Diego', '92139', '', '', 'Yes', 127);
INSERT INTO `honeybee1` VALUES ('2012-01-30 16:56:46', 'Bryan Zublin', -117.028908, 32.992935, 'Bees in utility box in the ground.', 'In the ground', 'Bee Keeper', 'bryan.zublin@motorol', 'CA', 'Northcrest Lane', 'Poway', '92064', '', '858-404-2724', 'Yes', 128);
INSERT INTO `honeybee1` VALUES ('2010-10-16 22:28:54', 'Michael Stanton', -117.015594, 32.951038, 'We have two seperate feral hives on our property one in same railroad ties and another in a CMU wall sperating our property', 'In the ground', 'Other', 'mstanton1@live.com', 'CA', '12941 Sunderland St.', 'Poway', '92064', '', '6196663912', 'Yes', 129);
