INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Suzanne', -116.928864, 32.823635, 'In a hole in a low cement wall. Faces east. Organic area with lots of food and water. Been here a few years. Produces several swarms a year. Not Africanized. Not infested. Friendly peaceful bees. If an organic gardener or farmer wants a swarm email me--they will be swarming again soon as there is a tremendous amount of pollen for them right now.', 'Manmade structure', 'Concerned Citiz', 'suzanne@orden.net', 'CA', '', 'El Cajon', '92021', '', '', 'Yes', 133);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Megan Martin', -116.764587, 33.593533, '"Feral hive loated in the wall of Trip Flats fire station equipment barn. will be trapped out to remove them from the wall may lose queen in the process. aprox 12'' up in a woodpecker hole.\rwill be relocated to my bee yard."', 'Manmade structure', 'Bee Keeper', 'meganm@sprynet.com', 'CA', '54495 Mitchell Rd', 'Anza', '92539', '', '909 518-5224', 'Yes', 134);
INSERT INTO `honeybee1` VALUES ('2008-07-14 09:30:16', 'Megan Martin', -116.712097, 33.569256, 'Feral hive cutout relocated from Trip Flats firestation cabin near Anza. currently housed in Lang hive. ', 'Manmade Beehive', 'Bee Keeper', 'meganm@sprynet.com', 'CA', '54495 Mitchell Rd', 'Anza', '92539', 'some of the brood from this hive distributed to San Diego cutouts that may be queenless.', '909 518-5224', 'Yes', 135);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Megan Martin', -116.665192, 33.572578, '"Feral hive loated in the exterior and interior walls of a house access under eaves and through vent. will be trapped out. may lose queen in process.\rwill be relocated to my bee yard."', 'Manmade structure', 'Bee Keeper', 'meganm@sprynet.com', 'CA', 'Hill St', 'Anza', '92539', '', '909 518-5224', 'Yes', 136);
INSERT INTO `honeybee1` VALUES ('2009-01-11 23:38:46', 'Tom Glenn', -116.419357, 33.365101, 'In rocks in middle of Anza-Borrego Desert. Probably africanized bees but not aggressive. First found in 1997 and observed to be occupied once every year in winter to 2009. South facing large opening hot summer sun melts much comb every year.', 'In the ground', 'Bee Keeper', 'glennapiaries@gmail.', 'CA', '', 'Borrego Springs', '92004', 'Samples of wax sent to Judy Wu at WSU for studies of wax contamination. Samples of bees sent to David Schneider at Stanford Univ. for testing for Wolbachia bacterium.', '760 728 3731', 'Yes', 137);
INSERT INTO `honeybee1` VALUES ('2009-01-12 00:35:52', 'Tom Glenn', -116.404221, 33.357777, 'In rocks in Anza-Borrego desert. North facing entrance. No comb visible. Probably africanized', 'In the ground', 'Bee Keeper', 'glennapiaries@gmail.', 'CA', '', 'Borrego Springs', '92004', 'Sample of bees sent to David Schneider at Stanford Univ. for testing for Wolbachia bacterium.', '760 728 3731', 'Yes', 138);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jon P.', -116.316193, 43.633434, 'The hive is at least two years old. It is located on the western side of the auto parts store in the eave that hangs over the sidewalk. It is about 15 feet off the ground.', 'Manmade structure', 'Bee Keeper', 'jpsbees@gmail.com', 'ID', 'Off of Ustick close ', 'Boise', '83713', 'The hive is at least two years old. ', '208-371-2200', 'Yes', 139);
INSERT INTO `honeybee1` VALUES ('2011-10-01 15:48:24', 'Chris Bevington', -116.198402, 43.638939, 'Ground hive at the intersection of the 15th Street Trailhead and Red Fox Trail. It is in the grassy area surrounded by the trails. Not sure how long it has been there or condition.', 'In the ground', 'Other', 'chrisbev23@hotmail.c', 'ID', '15th Street Trail He', 'Boise', '83702', 'none', '2086953170', 'Yes', 140);
INSERT INTO `honeybee1` VALUES ('2008-10-29 18:47:04', 'Betsy Arnold', -114.634033, 32.723049, 'Total of 4 hives in an app. 2 acre urbanish setting. 2 in large pecan trees. One in the wall of an old shed(this is a Large! hive) and one in a fallen stump. 2 of them have been here for at least 8 years that I know of. The bees are gentleno one at our house has ever been stung. They are wonderful pollinators of our home orchard and garden.', 'Living Tree', 'Other', 'betsychip@msn.com', 'AZ', '1213 W. 2nd St', 'Yuma', '85364', 'I am willing to help with this project and would love to know how to protect and manage the hives I have. I would also like to know how to move feral hives. Thanks Betsy Arnold', '928-782-1852', 'Yes', 141);
INSERT INTO `honeybee1` VALUES ('2009-03-04 18:27:23', 'Leslie Bell', -114.580032, 34.863312, 'Hive is about 8 - 10 feet off the ground in a Tamarisk tree. Don''t know how long it''s been there just found it today. There is old honeycomb on the ground and I don''t know what that means. The hive is on my property and is behind a garage. I would like to keep them alive if possible.', 'Living Tree', 'Concerned Citiz', 'mohaveag@aol.com', 'NC', '2005 Regents Road', '', '86440', '', '9287159440', 'Yes', 142);
INSERT INTO `honeybee1` VALUES ('2012-03-14 17:49:52', 'Paul Villiard', -114.400635, 32.648624, '12'' above ground on branch of mesquite treeabout 8diameter at top about 8tall been here 2 days that I know about. Look up and you will see it on south side of tree', 'Living Tree', 'Concerned Citiz', 'paul@paulvr.com', 'AZ', '10614 Ave 14 1/2E', 'Yuma', '85367', '', '9283056251', 'Yes', 143);
INSERT INTO `honeybee1` VALUES ('2010-08-11 00:12:40', 'Roy Adams', -113.601997, 37.061077, 'The hive is about 12 feet off the ground. It is in a crevice of a giant boulder. The bees are real pricks. They stung us 6 times. ', 'In the ground', 'Concerned Citiz', 'royneiladams@gmail.c', 'UT', 'Ash Circle', 'St. George', '84790', '', '8019799609', 'Yes', 144);
INSERT INTO `honeybee1` VALUES ('2008-08-06 22:31:06', 'Bruce Bell', -112.649261, 34.273460, ' Several Africanized colonies located in trees old structures and outcroppings in locations in the area', 'Living Tree', 'Bee Keeper', 'beemused47@yahoo.com', 'AZ', 'no address here', 'Kirkland', '86427', '"Have not inspected these closely as they are a little testy and I don''t have a \rKevlar beesuit. They will run you off heavy equipment without a cab."', '970-385-7131', 'Yes', 145);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'MICHAEL KING', -111.813599, 33.295181, 'The hive is approx 7 feet off the ground under our eaves in the entry way to our house. Its been there for about 5 months. It is shaped in flat half circles and it consists of 6 of these half circles in a row. ', 'Manmade structure', 'Concerned Citiz', 'KINGMICK13@YAHOO.COM', 'AZ', '1585 E. MORELOS ST', 'CHANDLER', '85225', '', '480-329-2463', 'Yes', 146);
INSERT INTO `honeybee1` VALUES ('2009-03-22 18:16:29', 'Gilbert', -111.710930, 33.265434, '4 ft from grond in a small tree there is so many its bending the tree over', 'Living Tree', 'Concerned Citiz', '', 'AZ', '3654 e simpson ct', 'gilbert', '85297', '', '', 'Yes', 147);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Tod', -111.454926, 34.383678, '"Hive is inside a stack of old fencing or wall nailed together wood. The wood stack is about 4'' high by 4''x4''.\rThe bee''s arent aggressive in any way. The hive is in an empty wild grass covered lot across from my home."', 'Manmade structure', 'Concerned Citiz', 'jontod1@gmail.com', 'AZ', '6249 West Prince Dri', 'Pine', '85544', '', '480-250-1006', 'Yes', 148);
INSERT INTO `honeybee1` VALUES ('2009-08-09 00:36:08', 'jerry shue', -109.561195, 38.585934, 'six feet up in box elder tree three inch opening swarmed may 2009', 'Living Tree', 'Bee Keeper', 'shue.jerry@gmail.com', 'UT', '', 'Moab', '84532', '', '435-259-7541', 'Yes', 149);
INSERT INTO `honeybee1` VALUES ('2008-08-06 22:10:13', 'Bruce Bell', -107.495728, 37.028870, 'Located in the base of a huge cottonwood tree. Over 4 feet in diameter. Entrance is at less than a foot of ground level. Lots of activity approx 20 bees per 10 second interval or greater. Gray color and large bodied. Comb bottom barely visible through opening. Heavy bearding in late afternoon.', 'Living Tree', 'Bee Keeper', 'beemused47@yahoo.com', 'CO', 'milepost 11 Hwy 151', 'Allison', '81137', 'Property owner wants them removed due to grandchildren in area. Due to size of colony they have bee there longer than owner realized yet no one has been stung. My son and I observed them with no protection to within a foot of entrance and no alarm. They acted like we were posts which they flew around.', '970-385-3171', 'Yes', 150);
INSERT INTO `honeybee1` VALUES ('2009-05-21 19:12:51', 'rene bencomo', -106.311996, 31.797295, '19ft above ground on pine tree but not inits hanging probly been there for bout 2 days its may 21st now', 'Living Tree', 'Other', 'tyrenecus@yahoo.com', 'TX', 'beckenridge 3712', 'el paso', '79936', '', '', 'Yes', 151);
INSERT INTO `honeybee1` VALUES ('2008-08-04 12:17:44', 'Don Koch', -106.270828, 34.738548, 'The hive is under an old rusted steel bucket by an abandon oil tank on a ranch in the foot hills of the Manzano Mountains in New Mexico. The ranch owner says it''s been there for at least 4 years. He also said he lifted the bucket once and the hive was in the ground. It''s a rocky place so the hive could be in between some large rocks. The hive was very active so I was unable to verify the exact location of the comb. The ranch is very remote and in an arid climate that had recently received some rain so there was a proliferation of wild flowers. I have photos of hive bees and many of the flowers. If needed I can instruct the ranch owner on sample methods and have a sample sent via UPS. ', 'In the ground', 'Concerned Citiz', 'don.koch@gmail.com', 'NM', '101 Rosewood Road', 'Tajique', '87016', '', '919-649-0447', 'Yes', 152);
INSERT INTO `honeybee1` VALUES ('2010-10-24 23:25:03', 'Ryan', -106.258392, 38.130775, 'The hive is in a tree 8ft.+ off the ground. It has been there for many years. It is in the yard at the ranch behind the shop. The mechanic told me it swarms about every two years.', 'Living Tree', 'Concerned Citiz', 'bendriftin@yahoo.com', 'CO', '40924 County Rd. CC ', 'Saguache', '81049', '', '719-580-4022', 'Yes', 153);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Fran Nicholson', -105.886314, 35.480381, '5 feet off the ground in a cinderblock retaining wall. The hive has been there two years has one 1 inch wide entrance. The bees are not agressive. Private property.', 'Manmade structure', 'Bee Keeper', 'frannicholson@msn.co', 'NM', '13 Lime Kiln Rd.', 'Lamy', '87540', 'After watching this hive I was inspired to build a Top Bar Hive and get my own colony of Russian Carneolans from Honeybee Genetics in CA. in Spring of 2010.I had a friend build my second Top Bar Hive and will get another colony this May. ', '5059821922', 'Yes', 154);
INSERT INTO `honeybee1` VALUES ('2009-02-28 12:37:19', 'plantit', -105.328590, 39.624401, '2 2 deep super hives est. 2006', 'Manmade Beehive', 'Bee Keeper', 'patriciastefaniw@yah', 'CO', 'hwy 73', 'evergreen', '80439', '', '', 'Yes', 155);
