INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Debby McAllister', -105.063499, 39.688232, '"The hive is in an old brick incineratorand bees have been there on an off for over 20 years. The structure is about 4 feet high and 18inch x 20 around.\rIt is in my back yard."', 'Manmade structure', 'Concerned Citiz', 'debbymcallister@hotm', 'CO', '1576 S Ingalls St.', 'Lakewood', '80232', '', '303-804-0422', 'Yes', 159);
