INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Ricki Douglas', -104.313622, 39.738213, 'Hive is located under an aging wooden bridge. There is some large abandoned honeycomb near an entrance into a wooden beam where the bees enter and exit.', 'Manmade structure', 'Bee Keeper', 'ridou3@gmail.com', 'CO', '', 'Strasburg', '80136', '', '3032299862', 'Yes', 161);
