INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Larry Harwood', -97.833565, 39.361000, 'Hive is in the west facing roof of an abandoned house', 'Manmade structure', 'Bee Keeper', 'larry.harwood@gmail.', 'KS', '405 Main St.', 'Glasco', '67445', 'I collected a swarm from this hive this spring that is thriving. I have two hives one from this swarm and one from a package I bought this spring. The bees from the swarm are healthy and have heavy natural stores going into this winter. Mite counts are less than 10 in 48 hours while the package hive needed treating to lower the mite count (125 in 48 hours).', '7855682515', 'Yes', 167);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Larry Harwood', -97.832253, 39.361595, 'beehive', 'Manmade structure', 'Bee Keeper', 'larry.harwood@gmail.', 'KS', '', 'Glasco', '67445', 'The bees are in the wall of an old wooden shed.', '', 'Yes', 168);
INSERT INTO `honeybee1` VALUES ('2009-12-06 12:59:56', 'Nick Crites', -97.579536, 32.981091, 'This hive is 10 ft off the ground. It has been there for 3 years. It is also on a friend''s property. He is not concerned about the bees bothering his family. The bee tree is in a field.', 'Living Tree', 'Bee Keeper', 'cowboybees@aol.com', 'TX', 'New Hope Rd', 'Springtown', '76082', '', '817-721-4467', 'Yes', 169);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Judy Larry Kelley', -97.562904, 35.517467, 'Hive is on the side of a wooden squirrel box in an oak tree about 12 feet off the ground in our backyard. The bees appear to cluster around the entry hole. They were noticed only this week; no idea how long they''ve used the box. There is no visible hive and we have yet to investigate further. ', 'Manmade structure', 'Concerned Citiz', 'judy-kelley@ouhsc.ed', 'OK', '2721 NW 45', 'Oklahoma City', '73112', '', '405-948-8577', 'Yes', 170);
INSERT INTO `honeybee1` VALUES ('2011-01-13 08:43:35', 'Anon A. Moose', -97.436081, 35.472179, 'base of large oak tree inches above ground several years', 'Living Tree', 'Bee Keeper', '', 'NC', '4501 NE 4th', 'Del City', '73117', '', '', 'No', 171);
INSERT INTO `honeybee1` VALUES ('2008-10-27 21:45:14', 'J. Baker', -97.412682, 34.579731, 'Unknown location. Have been feeding them sugar water in the fall for several years this year topping two quarts a day. Travel time from first scout departure to return of main body approximately 2min 30sec so must be fairly close.', 'Dead Tree', 'Concerned Citiz', 'jlbaker@msbit.net', 'OK', '', 'Elmore City', '73433', '', '4054265377', 'Yes', 172);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Thomas Barker', -97.239777, 32.570145, 'Known to be 3 years old', 'Manmade structure', 'Student', '', 'TX', '', '', '', '', '', 'Yes', 173);
INSERT INTO `honeybee1` VALUES ('2008-10-08 09:30:26', 'Garry Cate', -97.070419, 28.073931, 'Live oak tree 15ft up back of lot near lot line of lot 12 and 13', 'Living Tree', 'Bee Keeper', 'GarryCate@hotmail.co', 'TX', '510 Sanctuary', 'Rockport', '', '', '361-729-9707', 'Yes', 174);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Develon Puckett', -96.332764, 40.776382, '6 x Top Bar Hives installed 2004.', 'Manmade structure', 'Bee Keeper', 'irsqu911@yahoo.com', 'NE', '14th Road', 'Palmyra', '68418', '"-All organic no mites or diseases. Occasional wax moth problem.\r-Lost 3 hives due to extended cold spell winter 09-10. "', '402-780-5233', 'Yes', 175);
INSERT INTO `honeybee1` VALUES ('2010-03-19 18:12:50', 'Develon Puckett', -96.326515, 40.769478, '"TBH swarm followed spring of 09 setting up in hollow locust tree. \rbuilt box to cover hole to protect from wildlife"', 'Living Tree', 'Bee Keeper', 'irsqu911@yahoo.com', 'NE', 'B road', 'Palmyra', '68418', '', '402-780-5233', 'Yes', 176);
INSERT INTO `honeybee1` VALUES ('2012-06-04 03:01:49', 'Shantell Kersten', -96.051460, 41.281998, 'Bumblebees underground.', 'In the ground', 'Concerned Citiz', 'shanann79@yahoo.com', 'NE', '8830 Lake ST', 'Omaha', '68134', 'I was moving a wood pile that had been in existence for at least a decade or two. I noticed a few bumblebees flying out from under a log. I moved the log closer to my hummingbird/butterfly flower garden thinking that''s where their hive was. Then when I went to rake the area they swarmed a bit. It seems that the bumblebees have a colony underground. I placed a raised piece of wood from a project to shelter it until I can figure out how to preserve it safely.', '402-881-6362', 'Yes', 177);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'R. L. Jones', -96.018028, 33.781212, '1 foot off ground in wooded area inside an old Chevy truck cab (behind driver seat) attached to cab wall', 'Manmade structure', 'Concerned Citiz', 'hmicj@aol.com', 'TX', '', 'Telephone', '75488', '', '', 'Yes', 178);
INSERT INTO `honeybee1` VALUES ('2009-11-02 20:58:42', 'melissa', -95.621567, 30.128345, 'I have not seen the hive but have had approx 1000 bees feeding on my porch for the past couple of days. About 50 or so started out on my humming bird feeders but as I increased the sugar content to at thicker syrup more bees came. I now go through 12 pounds of sugar a day.', 'Living Tree', 'Concerned Citiz', 'msalmon@waterskraus.', 'TX', '13303 spring hollow ', 'tomball', '77375', '', '2812552977', 'Yes', 179);
INSERT INTO `honeybee1` VALUES ('2011-03-22 06:29:38', 'michael mcelroy', -95.298157, 32.347191, '"of the ground 7 years with no intervention other than esential oils \rnow have 4 hives all feral hives a combination of buckfast all american and ferel bees. Dark black bees with attitude but do well with mites beetles"', 'Manmade Beehive', 'Bee Keeper', 'mdm106@yahoo.com', 'TX', 'rowland place', 'tyler', '75701', '', '9038059396', 'Yes', 180);
INSERT INTO `honeybee1` VALUES ('2011-03-22 06:27:20', 'michael mcelroy', -95.289917, 32.345161, '"of the ground 7 years with no intervention other than esential oils \rnow have 4 hives all feral hives a combination of buckfast all american and ferel bees. Dark black bees with attitude but do well with mites beetles"', 'Manmade Beehive', 'Bee Keeper', 'mdm106@yahoo.com', 'TX', 'rowland place', 'tyler', '75701', '', '9038059396', 'Yes', 181);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Shannon H.', -94.823341, 39.839600, '4'' off the ground on a bush by the fince in Dekalb Mo. 2nd time the H.S. Principal called with a swarm of Bee''s.', 'Manmade structure', 'Bee Keeper', 'holcomb_shannon@yaho', 'MO', 'Walden Oaks', 'Country Club Village', '64506', '', '816-261-8647', 'Yes', 182);
INSERT INTO `honeybee1` VALUES ('2009-08-28 22:05:37', 'steve', -94.675743, 38.687279, 'about 8 inches off the ground we have two hives and they have been going about 5 months', 'Manmade Beehive', 'Bee Keeper', 'dixieroadie@yahoo.co', 'KS', '247th', 'louisburg', '66053', 'PRIVATE HONEY HIVES NO TRESPASSING WITHOUT PERMISSION FIRST', '785-214-9913', 'Yes', 183);
INSERT INTO `honeybee1` VALUES ('2008-10-30 20:33:54', 'Sean Lee', -94.517960, 37.092224, 'Living Catalpa tree with the hive entrance approximately 3 feet from the ground facing east. It had been there at least 3 years. The owner of the lot was having a problem with the bees stinging when the lawn was mowed. I trapped them out in Spring 2008. He planned on cutting the tree down.', 'Living Tree', 'Bee Keeper', 'sglee425@yahoo.com', 'MO', '', 'Joplin', '64801', '', '417-776-4071', 'Yes', 184);
INSERT INTO `honeybee1` VALUES ('2008-10-30 20:47:08', 'Sean Lee', -94.454353, 37.335293, 'Approximately 20 feet off the ground in a living Oak tree. Loggers cut the tree down and found the bees September 2005. No one knew how long it had been there. I transfered the bees to one of my hives.', 'Living Tree', 'Bee Keeper', 'sglee425@yahoo.com', 'MO', '', 'Jasper', '64855', '', '417-776-4071', 'Yes', 185);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'C Cannaday', -94.237976, 34.542763, 'In the wall of an outbuilding. entrance is 2 feet off the ground. Have been there for over 20 years. Old man used to keep bees. quit over 20 years ago.', 'Manmade structure', 'Bee Keeper', 'cattleman@hughes.net', 'AR', '204 Polk 648', 'Mena', '71953', '', '7192347674', 'Yes', 186);
