INSERT INTO `honeybee1` VALUES ('2008-10-30 19:47:26', 'Sean Lee', -94.147255, 36.782890, 'Approximately 25 feet off the ground in a dead tree. The owners did not know the hive was there until they cut the tree down for firewood. They called me to remove the bees. I was told that another bee tree was cut down in the same wood lot earlier in the year.', 'Dead Tree', 'Bee Keeper', 'sglee425@yahoo.com', 'MO', 'Near intersection of', 'Stella', '64867', '', '417-776-4071', 'Yes', 188);
INSERT INTO `honeybee1` VALUES ('2011-06-30 11:16:07', 'Donald Shrader', -94.087318, 36.473095, 'The hive is about 8 inches off the ground inside a living oak tree on the hill side of one of our fields. I noticed this hive just this spring. ', 'Living Tree', 'Concerned Citiz', 'dlshrad@hotmail.com', 'AR', '13128 Dale Shrader R', 'Pea Ridge', '72751', 'we have people in the area that will go out and take our wild bees and sell them to raise honey. We keep out hives hidden from these people. ', '479-381-8965', 'Yes', 189);
INSERT INTO `honeybee1` VALUES ('2011-06-30 11:16:18', 'Donald Shrader', -94.087318, 36.473095, 'The hive is about 8 inches off the ground inside a living oak tree on the hill side of one of our fields. I noticed this hive just this spring. ', 'Living Tree', 'Concerned Citiz', 'dlshrad@hotmail.com', 'AR', '13128 Dale Shrader R', 'Pea Ridge', '72751', 'we have people in the area that will go out and take our wild bees and sell them to raise honey. We keep out hives hidden from these people. ', '479-381-8965', 'Yes', 190);
INSERT INTO `honeybee1` VALUES ('2011-07-19 00:06:47', 'Mary Bruffett', -93.797516, 37.694706, 'The mature soft Maple tree just East of our house is now a home to a new batch of ?feral? honeybees. The hive moved in early this spring; the opening to hive is located approx 4 ft above ground level. I have placed a sign on the tree Honey Bee Home Do Not Disturb. There is quite a bit of sap running out of the tree at the opening of the hive. The bees look like pictures of the dark European Honeybees. They are very gentle and easy to get close to and watch. They are quite interesting as I have never been able to observe wild honeybees before. I want to protect these bees yet I know one day the tree will break apart... The local beekeeper I found on the internet is now retired and assured me that the bees are no Problem... but I would like to find a nearby beekeeper I could call in the event of the tree giving out... I would even be interested in learning about beekeeping myself! I do consider myself an amateur naturalist interested in all wild creatures and plants.', 'Living Tree', 'Concerned Citiz', 'marybruffett@yahoo.c', 'MO', '510 S High St', 'Stockton', '65785', '', '417-629-8902', 'Yes', 191);
INSERT INTO `honeybee1` VALUES ('2009-07-05 21:42:00', 'Dal Moreau', -93.745644, 30.157661, '7 feet off ground in shrubbery. 6 weeks. round. not in a tree or building. Looks like the stereotypic Winnie the Pooh bee hive.', 'Living Tree', 'Concerned Citiz', 'dmoreau3@sbcglobal.n', 'TX', '1201 Redbud Cr', 'Orange', '77632', '', '409.988.3161', 'Yes', 192);
INSERT INTO `honeybee1` VALUES ('2008-10-27 12:32:21', 'Marshall Nealy', -93.501892, 32.995995, '30 inches high in an oak tree. Been there at least 3 years.', 'Living Tree', 'Bee Keeper', 'mrnealy1930@hotmail.', 'LA', 'Thimothy Church Road', 'Springhill', '71075', '', '318-539-2780', 'Yes', 193);
INSERT INTO `honeybee1` VALUES ('2009-01-13 02:01:47', 'TRF', -93.283539, 36.284134, 'aprox. 16'' up a tree 2yrs + size unknown (it''s inside a hole in the tree) in the tree with the rope swing in front of the house.', 'Living Tree', 'Concerned Citiz', 'tr.ferguson@yahoo.co', 'AR', '206 S. Denver St', 'Alpena', '72611', 'the bees are very friendly I can handle them if they happen to get trapped inside the screened-in front porch by coaxing them onto my hand to be returned outside.', '', 'Yes', 194);
