INSERT INTO `honeybee1` VALUES ('2008-10-27 22:20:32', 'bruce scharwath', -90.904251, 30.234173, 'THE HIVE IS IN A FRIENDS BACK YARD.IT BEEN THERE 5 YEARS. IT WAS IN A LIVE OAK TREEAND THE ENTRANCE OF THE HIVE WAS 12 FT.HURRICANE GUSTAV KNOCKED DOWN THE TREE. ITS A LARGE HIVE.I WILL ADD THEM TO MY COLONYS.THIS IS THE 4TH HIVE I GOT FROM FALLEN TREES', 'Living Tree', 'Bee Keeper', '3410sugarhouse st', 'LA', 'roddy rd', 'gonzales', '', '', '225-806-2655', 'Yes', 203);
INSERT INTO `honeybee1` VALUES ('2011-02-14 01:03:38', 'Doyle Ramey', -90.844597, 35.315975, 'In a live tree entrance is about 17 foot up. Do not know how large of a hive it is but know they have been there for 2 years now. ', 'Living Tree', 'Bee Keeper', 'dlramey@hotmail.com', 'AR', '2051 Hwy 364', 'cherry valley', '72324', '', '', 'Yes', 204);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Betty Arnold', -90.765839, 29.423199, 'There are two hives located in Bayou DuLarge Baptist Church building at the above location. These hives have been there for many years. They are thriving. I have spoken to the pastor of that church and he says there are several more feral hives in that area.', 'Manmade structure', 'Bee Keeper', 'bettone100@hotmail.c', 'LA', '2567 Bayou DuLarge R', 'Theriot', '70397', '', '601-261-1102', 'Yes', 205);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jesalyn Keziah', -90.721321, 33.747959, '1.5 feet off of the ground in brick wall where bricks are missing wall covered in trumpet vine. Behind Hey Joe''s in the gravel parking lot between Hey Joe''s and the Warehouse.', 'Manmade structure', 'Bee Keeper', 'jesalynk@gmail.com', 'MS', '118 E Sunflower Rd', 'Cleveland', '38732', '', '7046217234', 'Yes', 206);
INSERT INTO `honeybee1` VALUES ('2008-10-27 11:36:26', 'Steven Williams', -90.439888, 36.766861, 'The colony is in a tree approximately 20'' off the ground. Time there unknown. Discovered when the tree was blown over in a severe windstorm and a yard service came to cut up and remove the downed tree.', 'Dead Tree', 'Bee Keeper', 'sgw@semo.net', 'MO', 'Kanell Boulevard', 'Poplar Bluff', '63901', 'To save the bees and their genetics I have stabilized the feral colony and am leaving them alone as they were just discovered and I fear if I moved them they would not survive the winter. So I am going to retrieve them in the spring hive them and let them generate their own queens and swarm as they will in the future. My attempt to replenish the feral population.', '573-776-1817', 'Yes', 207);
INSERT INTO `honeybee1` VALUES ('2011-03-07 19:34:43', 'jim pierson', -90.250725, 39.710587, '"15 feet above ground tulip popular tree\r20 feet from mausoleum in diamond grove cemetery been there 2 years swarmed in june of 2010 ( i captured swarm )still alive march 2011"', 'Living Tree', 'Bee Keeper', 'jspierson@frontier.c', 'IL', '1601 lincoln ave.', 's. jacksonville', '62650', '', '217-370-7212', 'Yes', 208);
INSERT INTO `honeybee1` VALUES ('2010-07-24 13:55:44', 'jim snyder', -89.910004, 40.516998, 'it is in a wild cherry tree about 4 foot above the ground. it is on the sw side of the tree. the hive has been there at least 3 years', 'Living Tree', 'Bee Keeper', 'vari1eze@yahoo.com', 'IL', '28100 east illinois ', 'banner', '61520', '', '309 647 7557', 'Yes', 209);
INSERT INTO `honeybee1` VALUES ('2008-10-01 18:55:07', 'Rich Dreschel', -89.886803, 40.539585, 'Cherry tree about 8ft. up 3 years old.', 'Living Tree', 'Bee Keeper', 'dreschel@glastel.net', 'IL', '29392 E. Mission Cam', 'Banner', '61520', 'I watched this swarm leave one of my hives and followed it to my nieghbors tree.', '(309) 389-4308', 'Yes', 210);
INSERT INTO `honeybee1` VALUES ('2009-05-18 22:40:09', 'Kae Schmitt', -89.671951, 38.780750, 'I just discovered the hive three days ago. It''s in a maple tree in my yard. The hole is approximately seven feet from the ground facing east.', 'Living Tree', 'Other', 'kaeschmitt@charter.n', 'IL', '3438 State Route 160', 'Highland', '62249', 'I am pleased to find this hive as I was wanting to begin beekeeping. I have a large yard of perennial and annual flowers that I have protected from pesticides. I want to keep the hive healthy from mites and need to know what should be done.', '618-654-4228', 'Yes', 211);
INSERT INTO `honeybee1` VALUES ('2008-06-24 20:57:23', 'Connie Brown', -89.604492, 34.529186, 'This colony is in a large cypress tree main entrance is about 8 feet from ground with a smaller second entrance about 7 feet from ground. Bees are not agressive. Owner asked if we would like to remove them from his woods but we are not able to trasport them 500 miles after educating the owner on bees he is happy letting them just bee there. We visited this tbee tree in Dec 07 March 08 and May 08 we will check on them again in August. ', 'Living Tree', 'Bee Keeper', '', 'MS', '', '', '', '', '', 'No', 212);
INSERT INTO `honeybee1` VALUES ('2010-01-03 00:50:13', 'Scott Martin', -89.583092, 37.737175, 'Entance at base of tree. Been there at least 4 years. ', 'Living Tree', 'Bee Keeper', 'soilcon@mchsi.com', 'NC', 'Hollman Lane', 'Gorham', '62940', '', '618-687-2513', 'Yes', 213);
INSERT INTO `honeybee1` VALUES ('2010-01-03 01:12:28', 'Scott Martin', -89.351562, 37.762608, 'Hive in live tree north of the school bus garage. Entrance is at least 10 feet off the ground large tree maybe 28+ inches DBH. Hive has been there for at least three years.', 'Living Tree', 'Bee Keeper', 'soilcon@mchsi.com', 'IL', '300 South 22nd Stree', 'Murphysboro', '62966', 'I collected three swarms in swarms traps from this hive in 2009. ', '618-687-2513', 'Yes', 214);
INSERT INTO `honeybee1` VALUES ('2012-06-12 15:50:19', 'David Easley', -88.876137, 33.606972, 'the hive is at ground level at the base of a (hollow) mature cedar tree.', 'Living Tree', 'Concerned Citiz', 'deasley7@gmail.com', 'MS', '3646 Henryville Road', 'Cedar Bluff', '39741', '', '662-418-5984', 'Yes', 215);
INSERT INTO `honeybee1` VALUES ('2010-05-21 11:01:22', 'james', -88.791504, 40.010788, '"hive # 1 in a tree about 4 ft obove the ground\r\rhive # 2 in a hive ( I captured a swarm)\r\rI now have two hives + the tree hive"', 'Living Tree', 'Bee Keeper', 'snyder', 'IL', '28100 east illinois ', 'banner', '61520', '', '', 'Yes', 216);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Glenn Uecker', -88.372421, 44.260521, 'This hive is inside a small cedar birdhouse approx. 6x6x8 mounted on the fence about 5 feet off the ground facing south in our backyard. It''s in the midst of my wifes flower garden. We''ve had birds here previous years but noticed the bees here this summer.', 'Manmade structure', 'Concerned Citiz', 'guecker@new.rr.com', 'WI', '2200 E Lucille St', 'Appleton', '54915-3132', 'My wife would like the bee hive to go away I''d like to get some honey once in awhile. If someone would be interested in moving the hive away I would be happy to discuss. We believe they''re honeybees because on hot days the little guys fan the opening to the birdhouse to cool the interior. They seem to be completely oblivious of us being in the yard nearby.', '920-731-0935', 'Yes', 217);
INSERT INTO `honeybee1` VALUES ('2008-10-29 18:41:36', 'Don DeVaul', -88.371277, 36.080181, 'this feral colony is in a huge log that was erected by the owner as a squirrel tree. the owner wanted it moved out but not killed..we moved log and all to our apiary some miles south..near Natchez Trace State Park. i guess the bees didn''t like there new location and left taking everything with them. so we know there is a feral colony near us.', 'Dead Tree', 'Bee Keeper', 'fubar777@hotmail.com', 'TN', 'Browning Highway', 'Huntingdon', '38387', '', '731.986.8034', 'Yes', 218);
INSERT INTO `honeybee1` VALUES ('2012-05-12 08:58:07', 'Jeff Heider', -88.341194, 41.872395, 'Near top of evergreen tree about the size of a football. Formed afternoon of 5/10/12', 'Living Tree', 'Concerned Citiz', 'jeff.heider@att.net', 'IL', '1542 S Randall Rd', 'Geneva', '60134', '', '8157934982', 'Yes', 219);
INSERT INTO `honeybee1` VALUES ('2010-04-12 11:54:02', 'Elizabeth Blaney', -88.049751, 44.527351, 'Has only been there for a few days. The bee''s are underground.', 'In the ground', 'Concerned Citiz', 'eblaney1@new.rr.com', 'WI', '1352 Reed Street', 'Green Bay', '54303', '', '920-217-1205', 'Yes', 220);
INSERT INTO `honeybee1` VALUES ('2009-04-21 20:59:39', 'tim ramey', -87.973022, 35.634975, 'about 10 feet high in a black locust tree measuring 35 inches diameter at breast height.just found it this march.', 'Living Tree', 'Concerned Citiz', 'timramey@tds.net', 'TN', 'highway 438', 'linden', '37096', '', '931-589-2802', 'Yes', 221);
INSERT INTO `honeybee1` VALUES ('2009-01-21 08:54:49', 'tim ramey', -87.959686, 35.599682, 'about 30 feet high in hollow red oak.found it 3 years ago. lots of bees going in and out.looks like a strong colony. located in large red oak directly beside marsh creek road on property owned by the tennessee valley authority (tva)', 'Living Tree', 'Concerned Citiz', 'timramey@tds.net', 'TN', '5808 marsh creek roa', 'linden', '37096', '', '931-589-2802', 'Yes', 222);
INSERT INTO `honeybee1` VALUES ('2012-06-15 15:00:02', 'Jerry Destree', -87.868652, 44.480831, 'a swarm on a branch of our plum tree!', 'Living Tree', 'Concerned Citiz', 'jerrdestree@yahoo.co', 'WI', '4903 E. Ronsman Road', 'New Franken', '54229', '', '920-866-1168', 'Yes', 223);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Linda', -87.834145, 44.348526, '16 feet plus off the ground been around about 2.5 years.', 'Manmade structure', 'Concerned Citiz', 'lgroskopf@charter.ne', 'WI', '418 Green Bay Rd', 'Denmark', '54208', '', '920-863-8847', 'Yes', 224);
INSERT INTO `honeybee1` VALUES ('2008-10-27 13:52:36', 'Doc Bullard', -87.332558, 30.461399, 'Hive entrance at base of large live oak tree. Convinced property owner to leave it alone away from traffic. Not known how long they have been there. ', 'Living Tree', 'Bee Keeper', 'mrflabee@cox.net', 'FL', 'Saufley Field Rd', 'Pensacola', '32507', '', '850-478-7690', 'Yes', 225);
INSERT INTO `honeybee1` VALUES ('2008-11-26 13:02:54', 'Craig & Michelle Law', -87.325241, 40.416225, 'The hive is located in a dead oak tree with a circumference of approximately 100inches at the entrances. We first noticed the hive in the spring of 2006. The tree has been dead since spring 2004. The tree is located at the end of a fence row at the south end of our property. It is a solitary tree. The hive entrances (2) are on the south side of the tree and are approximately 6ft from the ground. The two holes lie in a vertical line about 10in apart. The lower hole is about 2in in diameter and the upper is about 1.5in long x .5in wide. Michelle''s father identified the bees as Italian honey bees. They seem to be a very robust and mild tempered colony.', 'Dead Tree', 'Bee Keeper', 'IHFARM@hotmail.com', 'IN', '267 West Briscoe Roa', 'Rainsville', '47993', 'We have removed all lower branches back to the trunk and plan to remove the upper portion of the tree and then cover the top of the trunk to protect if from splitting/weathering. We are unsure how much of the tree contains hive and will top the tree conservatively to avoid cutting into the hive. We also plan to set up an empty hive with used comb with hopes to entice any swarm from the tree to use this hive as a new home. 2008 is our first year as beekeepers. We have set up three honey bee colonies this year. 2 purchased and 1 captured swarm from a friends farm.', '765-427-0247', 'Yes', 226);
INSERT INTO `honeybee1` VALUES ('2008-10-27 13:30:46', 'Butch Adams', -86.964317, 34.807549, 'Hive is in old cedar tree 8ft off ground behind Athens State Univ. Library. Approximately 100 to 150 yards behind building', 'Living Tree', 'Bee Keeper', 'Alabeekeep@yahoo.com', 'AL', '', 'Athens', '35611', '', '', 'Yes', 227);
INSERT INTO `honeybee1` VALUES ('2010-07-04 13:10:59', 'James Wagner', -86.864197, 33.100700, 'Hive is located in a cedar tree in Orr Park in Montevallo AL. In Orr Park cross the footbridge at the far end of the park. The hive is located next to the paved walking trail opposite the artesian well.', 'Living Tree', 'Bee Keeper', 'dixiebooks@juno.com', 'AL', '', 'Montevallo', '35115', '', '865-332-0603', 'Yes', 228);
INSERT INTO `honeybee1` VALUES ('2011-05-14 23:38:34', 'Flint Liddon', -86.771393, 33.519215, 'This hive is at the back of Avondale park. It is right where the old spring used to come out of the ground. The spring has now been capped. Once one of the most important places in Jefferson Countynow it is forgotten and hard to find if you don''t know where it is. Go to Avondale Park the hive located at the baseball field beyond the outfield fence left field. RIght where the spring used to emerge. There is a shallow cave and the hive is right at the entrance. ', 'In the ground', 'Bee Keeper', 'Flint@liddonlaw.com', 'AL', '5th avenuesouth', 'avondale', '35205', '', '205 222-4559', 'Yes', 229);
INSERT INTO `honeybee1` VALUES ('2008-10-27 12:34:16', 'Ray Turner', -86.664940, 36.164974, '20'' off ground in fence row hackberry tree 2''diameter been there 4-5 years rear/right side of lot behind house.', 'Living Tree', 'Bee Keeper', 'rturnerbee@wmconnect', 'TN', '2718 Bluefield', 'Donelson', '37214', '', '615 300 6953', 'Yes', 230);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bobby McKee', -86.633965, 37.185543, 'I a Garage building in the walls. Bees enter in a crack in a window frame. It has been there for around 8-10 years.', 'Manmade structure', 'Bee Keeper', 'flintman1@bellsouth.', 'KY', '113 Wand Cemetery Rd', 'Woodbury', '42288', '', '270-999-4668', 'Yes', 231);
INSERT INTO `honeybee1` VALUES ('2008-10-20 12:39:33', 'Daniel Rohde', -86.395798, 43.955910, 'feral hive in a Maple tree 10 ft off the ground in the middle of motel parking lot', 'Living Tree', 'Bee Keeper', 'danjrohde@yahoo.com', 'MI', '4616 W US 10', 'Ludington', '49431', '', '231 690-2937', 'Yes', 232);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Erin', -86.219780, 39.863491, 'Hive is located inside a plastic compost bin full of sticks. Lots of foraging activity...bees are active and appear very healthy. Want to keep them that was! Everything in the garden gets pollinated.', 'Manmade structure', 'Concerned Citiz', 'erinlisahall@hotmail', 'IN', '6015 Melbourne Rd.', 'Indianapolis', '46228', 'I''m happy to let the bees wel be....but I want to be sure they can overwinter safely here.', '', 'Yes', 233);
