INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'M. Frye', -85.614471, 30.311871, 'In my bay window about 15'' of ground. Returns every year for past 6 years. ', 'Manmade structure', 'Concerned Citiz', 'bsceltic@aol.com', 'FL', '8926 Kingswood Rd', 'Panama City', '32409', '', '', 'Yes', 238);
