INSERT INTO `honeybee1` VALUES ('2010-05-08 09:14:29', 'Chad P.', -85.313591, 35.095314, 'Looks like a very active hive. They have settled in the house. Looks like between the outside/inside walls. Approx. 12-15ft high.', 'Manmade Beehive', 'Bee Keeper', 'chad.poole@ymail.com', 'TN', '237 SWEETLAND DR', 'RED BANK', '37415', '', '', 'Yes', 240);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Chad P.', -85.305435, 35.054996, 'Hive located in the Hunter Mansion been there for several years. ', 'Manmade structure', 'Bee Keeper', 'chad.poole@ymail.com', 'TN', 'High Street', 'Chattanooga', '37406', 'This hive produced several swarms a year great catches.', '', 'Yes', 241);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Chad P.', -85.251534, 35.128632, 'Swarmed today bees likely in floor joists. Residence called said they noticed large amounts of bees on outside oh house. When I got there most of them had made their way into house. Plan to cut-ou this weekend maybe. ', 'Manmade structure', 'Bee Keeper', 'chad.poole@ymail.com', 'TN', '1336 Cloverdale Dr', 'Hixson', '', '', '', 'Yes', 242);
INSERT INTO `honeybee1` VALUES ('2011-07-28 11:06:13', 'Houston Farm', -85.198975, 38.186386, 'underground in a tobacco barn. hive has been here for many years.', 'In the ground', 'Concerned Citiz', 'sam.houston@insightb', 'KY', '3884 mt. eden rd. ', 'shelbyville', '40065', '', '502-682-6321', 'Yes', 243);
INSERT INTO `honeybee1` VALUES ('2009-08-21 07:04:48', 'Nathan Jones', -84.912239, 39.824547, '60 feet up in large Sycamore tree between LBC and Tyler Hall on Earlham College campus. 5/20/08', 'Living Tree', 'Bee Keeper', 'jonesna@earlham.edu', 'IN', '801 National Road We', 'Richmond', '47374', 'Throws a swarm each spring.', '765-983-1221', 'Yes', 244);
INSERT INTO `honeybee1` VALUES ('2011-01-24 01:46:07', 'Terry Williamson', -84.869385, 32.426338, 'Thirty feet off ground on tree limb out in the snow wind sleet and rainy weather. No protection. Residents/People thought it was a hornet nest. The outer (two) combs were white. Eight combs wider than deep hive frame and deeper. Most honey was goldenrod. Extremely smelly. ', 'Living Tree', 'Bee Keeper', 'willita@charter.net', 'GA', '', 'Columbus', '', 'The colony was hived without a single sting. Very gentle. Rescued from being exterminated New Years Eve 2010. Colony w/queen doing great.', '706-302-8886', 'Yes', 245);
INSERT INTO `honeybee1` VALUES ('2008-12-15 08:48:24', 'Richard Stewart', -84.789391, 39.128994, 'Bee Tree approximately 15 feet up.', 'Living Tree', 'Bee Keeper', 'rstewart@zoomtown.co', 'OH', '', 'North Bend', '45052', 'It is a bee tree between the 8th and 9th green of the golf course. Its been there for years off and on.', '513-967-1106', 'Yes', 246);
INSERT INTO `honeybee1` VALUES ('2008-12-15 08:52:29', 'Richard Stewart', -84.782181, 39.133121, 'Bee Tree. Vertical opening heavily propolized about 5 to 7 feet off the ground running 2 feet long.', 'Living Tree', 'Bee Keeper', 'rstewart@zoomtown.co', 'OH', '', 'North Bend', '45052', 'Located on private property. Son showed the tree after a call for a swarm of bees in their back yard turned out to be bees from this hive doing heavy runs on their fountain for water.', '513-967-1106', 'Yes', 247);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Richard Stewart', -84.742188, 39.148735, 'A gluten and brewers grain warehouse.', 'Manmade structure', 'Bee Keeper', 'rstewart@zoomtown.co', 'OH', '', 'North Bend', '45052', '"Multiple hives located here. I have done 3 cutouts personally all but has failed so I stopped culling them. The lower 8 feet of the walls are hollow wood frame and the building contains piles of simple proteins...gluten...thousands of tons of the stuff.\r\rEvery year they have bees there."', '513-967-1106', 'Yes', 248);
INSERT INTO `honeybee1` VALUES ('2010-10-11 11:20:41', 'Toby Diegel', -84.687424, 40.206749, 'About six feet up in a very large pine tree located in the Old tea garden cemetery on state route 49 found while placing geo caches ', 'Living Tree', 'Concerned Citiz', 'diegelt@hotmail.com', 'OH', '', 'Ansonia', '45303', '', '937 564 4132', 'Yes', 249);
INSERT INTO `honeybee1` VALUES ('2008-10-18 12:43:03', 'pete beaver', -84.681419, 42.646568, 'beehive', 'Living Tree', 'Bee Keeper', 'wadebeaver68@aol.com', 'MI', 'windsor highway', 'dimondale', '', '', '5173239470', 'Yes', 250);
INSERT INTO `honeybee1` VALUES ('2008-12-15 08:58:58', 'Richard Stewart', -84.574760, 39.113705, 'Large oak tree approximately 40 feet up in the top.', 'Living Tree', 'Bee Keeper', 'rstewart@zoomtown.co', 'OH', '', 'North Bend', '45052', '"Private property. Family does not want anyone snooping around. Caught a swarm from this colony in May of 2008. Used entire swarm to requeen a hive whose queen I had accidentally killed.\r\rDoing quite well. Very Dark."', '513-967-1106', 'Yes', 251);
INSERT INTO `honeybee1` VALUES ('2008-12-31 15:34:06', 'John Dwyer', -84.490356, 44.123085, '"15 feet above ground. It''s been there off and on for years.\rNorthwest of Gladwin Michigan"', 'Living Tree', 'Bee Keeper', 'jngdwyer@ejourney.co', 'MI', '5053 Gashe', 'Gladwin', '48624', '', '(989) 426-0481', 'Yes', 252);
INSERT INTO `honeybee1` VALUES ('2008-10-20 13:27:25', 'ray babcock', -84.481476, 39.236050, 'Large tree splits into two trunks about 10'' off ground. Hive is in that crotch. Tree is found half way along pedestrian walkway between the west end of forest ave. and brayton rd. Found it Sept. 2008', 'Living Tree', 'Bee Keeper', 'babcockx4@cinci.rr.c', 'OH', 'west end forest ave', 'wyoming', '45215', '', '5132957010', 'Yes', 253);
INSERT INTO `honeybee1` VALUES ('2011-10-13 12:16:35', 'Brutz English', -84.180450, 33.091793, 'Well established colony in the base of an oak tree. Entrance is located approx 1 foot off the ground facing south. Tree is located behind a small storage building on the north side of the property.', 'Living Tree', 'Bee Keeper', 'brutzenglish@gmail.c', 'GA', '308 Old Hwy 41', 'Barnesville', '30204', '', '770-843-2110', 'Yes', 254);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Brutz English', -84.166435, 33.053135, 'Colony of bees inhabiting the boxing on the west side of the house. Hive is approx 15 feet off the ground. Hive entrance is directly above where the electrical wiring enters the house from the power pole.', 'Manmade structure', 'Bee Keeper', 'brutzenglish@gmail.c', 'GA', '609 Zebulon St.', 'Barnesville', '30204', '', '770-843-2110', 'Yes', 255);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Brutz English', -84.135948, 33.153477, 'Established colony (+2 yrs) located in the rafters on southwest corner of the main building. Entrance is located approx 15 ft above the ground facing southwest.', 'Manmade structure', 'Bee Keeper', 'brutzenglish@gmail.c', 'GA', '1696 Hwy 36 E', 'Barnesville', '30204', '', '770-843-2110', 'Yes', 256);
INSERT INTO `honeybee1` VALUES ('2008-10-31 19:11:26', 'Marty', -84.117668, 33.830910, '" There is a clump of 3 trees (around 10 ft away from the house) that are very close together. I''d say that at 10''-12'' up which is where the major bee activity is the trees are only about 3 feet away from each other and all are covered in ivy. The ivy had been covered in a berry bloom so there were a lot - and I mean a lot - of honey bees doing a lot of work in the general area. Very hard to tell exactly.\r "', 'Living Tree', 'Concerned Citiz', 'kenpkr11@yahoo.com', 'GA', 'Pounds Road', 'Stone Mountain', '30087', '', '770-475-2395', 'No', 257);
INSERT INTO `honeybee1` VALUES ('2011-10-13 12:08:39', 'Brutz English', -84.061707, 33.085266, 'Well established hive in a black walnut tree just off the north shoulder of the road. Entrance is about 1 ft off the ground facing south. ', 'Living Tree', 'Bee Keeper', 'brutzenglish@gmail.c', 'GA', '166 Mott Rd.', 'Barnesville', '30204', '', '770-843-2110', 'Yes', 258);
INSERT INTO `honeybee1` VALUES ('2009-06-09 14:58:31', 'George Windle', -83.918945, 36.048012, 'This is an establihed colony that is about 50 feet off of the ground in a live but hollow oak tree size and age are unknown. The tree is in the back yard and when a storm came through it broke a limb out of the tree and brought down a couple of small combs.', 'Living Tree', 'Bee Keeper', 'cas.inc@tds.net', 'TN', '5515 Briercliff Rd.', 'Fountain City', '', '', '865-777-0626', 'Yes', 259);
INSERT INTO `honeybee1` VALUES ('2012-06-10 19:37:39', 'Heather Shepherd', -83.890938, 38.843544, 'I found it in a large blackberry bush in the back field. It''s a beautiful un-disterbed hive on the side of a recentley bushogged field. I noticed that the berries were brighter in that area and when I went to pick them I uncovererd the hive. Wow so cool!', 'Living Tree', 'Concerned Citiz', 'heathershep3029@yaho', 'OH', '60 Stonybrook Dr.', 'Georgetown', '45121', 'In blackberry bush', '9376182896', 'Yes', 260);
INSERT INTO `honeybee1` VALUES ('2009-06-09 21:39:39', 'Fred Wark', -83.829636, 42.577103, 'In large oak tree about 35 feet above ground. Convinced homeowner not to removed the bees or the tree', 'Living Tree', 'Bee Keeper', 'fswark@charter.net', 'MI', 'Hughs road north of ', 'Howell', '', '', '810-231-1189', 'Yes', 261);
INSERT INTO `honeybee1` VALUES ('2009-05-11 12:10:04', 'Britt Wetherington', -83.809502, 30.798290, 'I have know about this hive since 2007. It is in the hollow of a pecan tree in my backdoor neighbors yard about 15 feet up. It seems to be a very strong hive. I have not physically examined the hollow to see how large the hive is but there is a lot of traffic in and out of the hive.', 'Living Tree', 'Bee Keeper', 'bwetherington@wxton-', 'GA', 'US Highway 84', 'Boson', '31626', '', '229-393-5834', 'Yes', 262);
INSERT INTO `honeybee1` VALUES ('2010-03-01 13:55:33', 'Aaron Burns', -83.780685, 35.652119, 'Aaron and Kellie Burns Apiary', 'Manmade Beehive', 'Bee Keeper', 'The_Lorax@animail.ne', 'TN', '909 schoolhouse gap ', 'townsend', '37882', '', '865-235-8553', 'Yes', 263);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jack Broadhurst', -83.747955, 42.170532, 'In an outbuilding on my property for over 25 years.', 'Manmade structure', 'Bee Keeper', 'broadhurst@lycos.com', 'MI', '1380 W Bemis Road', 'Saline', '48176', 'I will move the bees to a managed hive in the spring of 2009', '7344295608', 'Yes', 264);
INSERT INTO `honeybee1` VALUES ('2008-10-19 08:05:22', 'Dean Dolley', -83.650085, 42.375015, 'Living in black walnut tree about 10'' off ground. Has been there about 10 years. In the back yard of a house. CANNOT BE VISITED.', 'Living Tree', 'Bee Keeper', 'dolleyd@comcast.net', 'MI', '', 'south lyon', '', 'Caught a swarm I assume is from the tree using a commercial swarm trap.', '2482106902', 'Yes', 265);
INSERT INTO `honeybee1` VALUES ('2008-10-27 18:30:15', 'Jay Parsons', -83.639648, 34.522736, 'The hive is in a large oak 40 feet up. Tree is approx. 30ft from roadway and on my property line. It has been there for a little over a year.', 'Living Tree', 'Bee Keeper', 'jaybparsons@att.net', 'GA', '380 Rocky Ridge Road', 'Cornelia', '30531', 'I witnessed the colony moving in last June (2007). I was working outside and was first alerted by it''s presence by the sound of the bees as an arriving swarm.', '770-441-2624', 'Yes', 266);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Carol Jones', -83.472061, 42.746002, 'Hive is in an old stone house and has been there at least 4 years.', 'Manmade structure', 'Bee Keeper', 'cjonnes@misd.net', 'MI', 'Dixie Highway at Bri', 'Clarkston', '48348', '', '248-625-4512', 'Yes', 267);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Phoenix Tuttle', -83.437065, 42.473145, 'Business owner called me to see if I could remove a swarm of honeybees that had just swarmed from the colony within the wall of their building the mother colony is still their approximately 18'' off the ground in the NE corner of their cinderblock building. Discovered June 2008. I chose not to remove them.', 'Manmade structure', 'Bee Keeper', 'Great.Lakes.Honey@gm', 'MI', '39600 Grand River Av', 'Novi', '48375', '', '248 343 6140', 'Yes', 268);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Fred Wark', -83.389664, 41.677528, 'Located just off nature trail boardwalk in Maumee Bay State Park. About 10 ft high in and on outside of birdhouse hanging on dead tree. It was active in September 2008. I attempted to get permission from park management to capture it and try to establish it in an unused observation hive which was located in nature center. As of 1-5-09 I do not know the status of it', 'Manmade structure', 'Bee Keeper', 'fswark@charter.net', 'OH', '', 'Oregon', '', '', '810-231-1189', 'Yes', 269);
INSERT INTO `honeybee1` VALUES ('2008-10-28 07:47:29', 'Phoenix Tuttle', -83.369133, 42.657497, 'Resident called me to see if I could remove a swarm that had just entered a knot in her tree approximately 20'' up in her maple in the back yard. I convinced her to let them stay.', 'Living Tree', 'Bee Keeper', 'Great.Lakes.Honey@gm', 'MI', 'Heydan St.', 'Waterford', '48328', '', '248 343 6140', 'Yes', 270);
INSERT INTO `honeybee1` VALUES ('2008-10-28 08:00:25', 'Phoenix Tuttle', -83.350296, 42.581959, 'Resident called me to see if I could remove a colony of honeybees that had just been discovered in a knot in her tree approximately 12'' off the ground in the back yard. Discovered June 2008. I chose not to remove them.', 'Living Tree', 'Bee Keeper', 'Great.Lakes.Honey@gm', 'MI', '3385 W. Long Lake Rd', 'West Bloomfield', '48322', '', '248 343 6140', 'Yes', 271);
INSERT INTO `honeybee1` VALUES ('2011-08-22 20:43:40', 'Don Coble', -83.320312, 40.044437, 'The hive is approximately 5 1/2 feet off the ground in a live tree. I''ve seen the hive for 8 years which is as long as we have lived at the address of where the hive is located. ', 'Living Tree', 'Concerned Citiz', 'doncoble1@live.com', 'OH', '14005 Centerburg rd', 'sunbury', '43074', '', '614-965-8082', 'Yes', 272);
