INSERT INTO `honeybee1` VALUES ('2008-07-29 21:55:23', 'Connie Brown', -82.937164, 35.669567, 'This bee tree was disocvered when winds blew the tree down. The tree is now on the ground hanging off the edge of a rural mountain side road. ', 'Living Tree', 'Bee Keeper', 'mail2thebrowns@juno.', 'NC', '137 Buckeye Branch D', 'Clyde', '28721', 'I collected samples for Debbie', '8282850318', 'Yes', 280);
INSERT INTO `honeybee1` VALUES ('2008-10-08 08:34:39', 'margaret crouch', -82.797256, 36.721001, 'beehive', 'Dead Tree', 'Bee Keeper', 'mfcrouch@mounet.com', 'VA', '997 panoramic ln', 'duffield', '24244', '15-20 ft (? the dead tree is at least that tall; don''t know exactly what part they''re occupying or which hole they use for entry) -- this is at least the second season they''ve been there -- they may be infected with a virus causing deformed wings (I saw 2 or 3 bees without wings crawling on the ground not far from the tree) -- I got a small swarm I assume came from them this spring (it was gathered right below the hive) -- our property is very rural and we''d prefer to be contacted before any visits.', '276 431-1275', 'Yes', 281);
INSERT INTO `honeybee1` VALUES ('2009-07-24 09:25:37', 'Janean', -82.705101, 27.754322, 'The hive is located in an Oak tree facing the street right next to the sidewalk. It can be accessed from the sidewalk with a ladder without going into the fence. I am the owner of the tree and property.', 'Living Tree', 'Concerned Citiz', 'janeaneasley@yahoo.c', 'FL', '1608 53 stree south', 'Gulfport', '33707', 'Not sure what to do about it. It is very close to the sidewalk and kind of affaid the some smart ass kids might mess with it.', '727-321-4621', 'Yes', 282);
INSERT INTO `honeybee1` VALUES ('2008-07-03 23:15:46', 'Connie Brown', -82.647400, 35.556808, 'This colony is in a large old growth Oak tree. Entrance is about 25 feet up at the main fork. Hive swarmed 7/3/08 swarm captured by me.', 'Living Tree', 'Bee Keeper', 'mail2thebrowns@juno.', 'NC', '36 Sand Hill School ', 'Candler', '28715', '', '8282850318', '', 283);
INSERT INTO `honeybee1` VALUES ('2009-04-06 08:05:13', 'Bill Triplett', -82.637764, 35.729462, 'It has been here at least 5 years. It is about 3'' off the ground in a huge Pine tree.I would have to guide someone in to find it.', 'Living Tree', 'Concerned Citiz', 'trip216@msn.com', 'NC', '349 Panther Branch R', 'Weaverville', '28701', '', '828 649 9069', 'Yes', 284);
INSERT INTO `honeybee1` VALUES ('2008-06-25 09:10:47', 'Carl Chesick', -82.623451, 35.586269, 'In the trunk of an old silver maple by my back deck. The opening is at the crown where the main trunk and upper limbs meet about twelve feet above ground. A one and a half inch knothole appears to open into a cavity about 12 x 18. This swarm arrived April 1 2006 . The bees were noticeably smaller and of a darker coloration than locally managed hives (at that time)', 'Living Tree', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'No', 285);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Frank Blount', -82.591904, 27.421602, 'Under corner of shed', 'Manmade structure', 'Concerned Citiz', 'hdson@verizon.net', 'FL', '6728 Northampton Pl', 'Bradenton', '34207', '', '941-751-1845', 'Yes', 286);
INSERT INTO `honeybee1` VALUES ('2008-10-19 11:04:01', 'Bob Williams', -82.576889, 42.605442, 'In a hollow tree. Entrance 20'' off ground. First observed in 2007.', 'Living Tree', 'Bee Keeper', 'Bob@stewartfarm.org', 'MI', '2007 Stewart Rd.', 'Harsens Island', '48028', '', '248-388-0465', 'Yes', 287);
INSERT INTO `honeybee1` VALUES ('2008-10-19 11:07:50', 'Bob Williams', -82.576546, 42.605598, 'In a tree. Entrance at ground level. Observed active 1999 - 2007. During the winter of 07-08 an animal ravaged the hive and no bee activity observed in 2008.', 'Living Tree', 'Bee Keeper', 'Bob@stewartfarm.org', 'MI', '2007 Stewart Rd.', 'Harsens Island', '48028', '', '248-388-0465', 'Yes', 288);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Drew Stephens', -82.532730, 35.526203, '10 years plus thriving feral colony. 15'' off ground in siding along chimney - Private property - ', 'Manmade structure', 'Bee Keeper', 'drew@serviceatsea.or', 'NC', '1 Ridgefield Rd', 'Asheville', '28803', 'I do have access to property and I am very interested in participating in DNA or any feral bee research. Please contact me!', '303 881-1595', 'Yes', 289);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Rob Morris', -82.529846, 35.514492, '20 feet off ground in wooden beam on house. Not that familiar with bees but know it''s not a yellow jacket or hornet''s nest. Many bees around when active. More than one entrance to hive. Owners want bees removed.', 'Manmade structure', 'Concerned Citiz', 'rmorris@deerfieldwnc', 'NC', '8 Valley Springs Roa', 'Asheville', '28803', '', '828.337.0011', 'Yes', 290);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Connie Brown', -82.529297, 35.563511, 'About 15 feet heigh off ground has been there a couple of years', 'Manmade structure', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Maybe', 291);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Connie Brown', -82.529297, 35.563511, 'Colony is the the attic of a 4 story older castle has been then more than 10 years runns the entire lenght of one wall bees are visible in attic and exiting both from both front and back of the house at the eaves. Historically home and does not want them removed. I have catupered two swarms from them very gentle bees', 'Manmade structure', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Yes', 292);
INSERT INTO `honeybee1` VALUES ('2008-10-27 12:35:56', 'Kris', -82.520775, 27.304634, 'Feral bees moved into an outside wall of our house. We have moved them into a beehive where they are thriving. I never planned on becoming a beekeeper but I''ve come to love them. ', 'Manmade Beehive', 'Bee Keeper', 'MsKris941@gmail.com', 'FL', 'Valencia', 'Sarasota', '34239', '', '', 'Yes', 293);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'C Arthur', -82.514931, 38.982136, 'In the gas tank of an old pickup truck. The bees were in the truck when it was moved from McArthur Ohio. They have been there a number of years.', 'Manmade structure', 'Bee Keeper', 'clovett@gmail.com', 'OH', 'Dixon Run Road', 'Winchester', '45640', 'The truck and property are owned by Waterloo Coal Company.', '', 'Yes', 294);
INSERT INTO `honeybee1` VALUES ('2008-10-27 12:21:56', 'PSM', -82.474899, 27.931255, 'In an oak tree. Been there for years.', 'Living Tree', 'Bee Keeper', 'psmaney@gmail.com', 'FL', '1009 S. Oregon ', 'Tampa', '33606', '', '', 'No', 295);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'J. Baran', -82.344849, 40.129951, 'Located in wall of unoccupied rural store building. Hive entrance is located about 7 ft. above ground close to the upper corner of the main entrance under a porch roof. Size of colony is unknown. Has had consistent activity since at least 2002 (when property was acquired by current owner).', 'Manmade structure', 'Bee Keeper', 'boge@blueowlgarden.c', 'OH', '6075 Fallsburg Road', 'Newark', '43055', 'Building is timber frame construction dating from ~1870s and is slated for restoration at a future date funding permitting. At some point the colony will need to be removed when construction begins but is OK for the time-being. Building is located adjacent to a state route with increasing amounts of traffic but is still rural with decent bee forage. The property where hive is located consists of 3 acres and is used for agricultural production (herbs fruits edible flowers). The owner plans to establish managed hives on the property within the next year or two.', '740-345-4689', 'Yes', 296);
INSERT INTO `honeybee1` VALUES ('2012-02-29 21:34:39', 'Karen Flynn', -82.289864, 26.884205, 'About 10 ft off the ground in a semi live oak tree. new this year 2012.', 'Living Tree', 'Concerned Citiz', 'karenflynn@hotmail.c', 'FL', 'Golfview Place', 'Rotunda West', '3947', '', '603-305-6601', 'Yes', 297);
INSERT INTO `honeybee1` VALUES ('2009-05-29 11:44:04', 'Mark Richter', -82.199081, 39.090168, 'Newly establish colony (May 2009) in old hollow oak tree. The entrance is about 30 ft off the ground.', 'Living Tree', 'Bee Keeper', 'rr2trls@yahoo.com', 'OH', '32400 McCumber Rd', 'Rutland', '45775', 'Private property. There are currently five non feral hives on the property.', '740-742-7418', 'Yes', 298);
INSERT INTO `honeybee1` VALUES ('2012-01-08 18:34:14', 'maggie', -82.181252, 28.285809, 'in a tree in the backyard. up about 3 stories highlooks like 8 or 9 layers.reminds me of mushrooms', 'Living Tree', 'Concerned Citiz', 'duncan_maggie@yahoo.', 'FL', '8835 wire rd', 'zephyrhills', '33540', '', '8134826877', 'Yes', 299);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Sandra Ronan', -82.179626, 41.259426, '"known to be active at least 15 years\rlocated in wall of old no longer in use hen house\rlocation is surrounded by corn beans hay fields"', 'Manmade structure', 'Bee Keeper', 'sronan@indiana.edu', 'OH', '15419 West Road', 'Oberlin', '44074', '', '812 824-3696', 'Yes', 300);
INSERT INTO `honeybee1` VALUES ('2011-05-29 09:05:54', 'beekeepinglady', -82.114563, 34.944489, 'in live tree about 15 feet off ground. 4 years now', 'Living Tree', 'Bee Keeper', 'beekeepinglady@yahoo', 'SC', 'Hwy 29', 'Wellford', '', '', '', 'No', 301);
INSERT INTO `honeybee1` VALUES ('2008-10-26 17:17:59', 'Joan Mistur', -82.104950, 40.334507, 'The hive is located in a cavity of a maple tree which is atop a hill. We have been watching it for two years very busy.', 'Living Tree', 'Concerned Citiz', 'jmistur@aol.com', 'OH', '', 'New Castle', '43244', '', '440-933-8770', 'Yes', 302);
INSERT INTO `honeybee1` VALUES ('2011-06-04 20:15:11', 'Scott', -82.006943, 39.084789, '6-8 feet off the ground two entrances in a hollow walnut tree been there for at least 2 years', 'Living Tree', 'Bee Keeper', 'playofafiddle@gmail.', 'OH', 'Rocksprings Rd. ', 'Hemolock Grove ', '45769', '', '740-416-2863', 'Yes', 303);
INSERT INTO `honeybee1` VALUES ('2011-08-17 15:19:17', 'O''s Fruit Farm Ltd.', -81.978027, 39.905972, '2nd Feral Hive in a maple tree 6 ft off ground center of tree slot in tree one year old swarm from 1st hive. About 5000 bees.', 'Living Tree', 'Bee Keeper', 'Bee_Sanctuary@columb', 'OH', 'Dietz lane and Eller', 'Zanesville', '43701', 'Also we have and manage 6 hives on this farm each hive are 10 framestwo deeps for brood chamber.', '740 452 5884', 'Yes', 304);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'O''s Fruit Farm Ltd.', -81.977173, 39.905945, '1st hive 600 ft off roadway from second hive in our old tool shed wall. Has about 15000 bees.', 'Manmade structure', 'Bee Keeper', 'Bee_Sanctuary@columb', 'OH', 'Ellerman Road', 'Zanesville', '43701', 'We manage 6 hives on this farm other then the two Feral hives.', '740 452 5884', 'Yes', 305);
INSERT INTO `honeybee1` VALUES ('2012-06-09 16:25:12', 'Katie Copley', -81.968727, 37.825367, 'beehive', 'Living Tree', 'Concerned Citiz', '', 'WV', '', '', '25646', '', '', 'Yes', 306);
INSERT INTO `honeybee1` VALUES ('2010-05-26 23:13:07', 'S. C. Driscoll', -81.932945, 39.984486, 'Second summer since the colony moved into the tree. Population seems down from last year but building again after a prolonged and cold winter. They enter and leave through a small crack into an interior cavity covered by vines. ', 'Living Tree', 'Concerned Citiz', 'rdrisco1@columbus.rr', 'OH', '3325 Adamsville Road', 'Zanesville', '43701', '', '740-252-3461', 'Yes', 307);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'AB Jones', -81.914902, 33.439587, 'beehive', 'Manmade structure', 'Bee Keeper', '', 'GA', '', 'Augusta', '30909', '', '', 'Yes', 308);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'chad gregory', -81.883331, 34.458622, 'beehive', 'Manmade structure', 'Other', 'gregoryc@prtcnet.com', 'SC', 'chestnut st', 'clinton', '29325', '', '864 6823210', 'Yes', 309);
INSERT INTO `honeybee1` VALUES ('2008-11-12 11:39:37', 'Dale Coates', -81.857353, 40.344761, 'There are 2 colonies of russian bees here that moved into some old bee boxes that were sitting outside of a barn. I was asked if I wanted the bees. The problem was that they were in York Pennsylvania. I had the hives inspected by the York county bee inspector and went over to get the bees. I really wanted some russian bees so I thought that it was worth the journey. The bees are now sitting in my bee yard and are doing really well still in the original boxes that they moved into. ', 'Manmade Beehive', 'Bee Keeper', 'coatesdd@yahoo.com', 'NC', 'TR 198', 'Coshocton', '43824', '', '', 'Yes', 310);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dale Coates', -81.857246, 40.345432, 'My neighbour has a hive in her house between the first and second level. They are nesting in the floor space of the second level. been there 1 year.', 'Manmade structure', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'TR 198', 'Coshocton', '43824', '', '', 'Yes', 311);
INSERT INTO `honeybee1` VALUES ('2008-10-28 19:17:39', 'Dale Coates', -81.857201, 40.345104, '"I was contacted by a local farmer who came across a hie in a cataba tree when he was mowing his pasture. He is very alergic to bees and asked if I could remove the bees. I set a bait hive out in 2007 no luck with that. So the farmer asked if I could cut the tree down and get it out of there. I did just that and you can see the video here. http://www.youtube.com/watch?v=oy-V3u7vSMY\rI took the tree to my bee yard and that is where it is sitting right now. I plan to have the hive draw comb on some hive bodys in 2009 and hopefully draw the queen out. It may take a while we will see."', 'Dead Tree', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'TR 198', 'Coshocton', '43824', '', '', 'Yes', 312);
INSERT INTO `honeybee1` VALUES ('2008-10-28 19:08:03', 'Dale Coates', -81.837502, 40.345760, 'This is a large birch tree that has a hollow V starting at ground level and going up about 2 feet. It is in a very wooded area cool and dark. I was alerted to the tree when a friend said that he heard a loud buzzing noise in that area. I went to invetigate and found the hive. It is very active. dont know how long it has been there.', 'Living Tree', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'TR 198', 'Coshocton', '43824', 'I intend to use this tree to attract swarms in the spring.', '', 'Yes', 313);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dale Bradshaw', -81.796036, 35.356979, 'The bees have built in the front of the church front porch about 12-14 ft off of the ground. This hive has been there for 20+ years. They are weak this year.', 'Manmade structure', 'Bee Keeper', 'dbrad1@nctv.com', 'NC', '747 Pinehurst Rd.', 'Ellenboro', '28040', '', '8282455652', 'Yes', 314);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Desiree Kuri', -81.775360, 26.101189, '10 feet off the ground in attic of built on porch addition--this section of building primarily wood.Been here about 3 years (since 2006) Had some die offs (possibly excessive heat?)but seems healthy and busystrong.basically to find it come to the listed address.Reporter(me) lives there and is property owner(large garden prop. of duplexes). ', 'Manmade structure', 'Concerned Citiz', 'desireekuri@rocketma', 'FL', '2616 Lakeview Drive', 'Naples', '34112', '', '239-775-4885', 'Yes', 315);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Gregory', -81.762611, 36.208374, 'The hive is about 30 Feet from the ground in the side of a house. I found them about 3 weeks ago. I have no idea how long they have been there but they look to be well established. ', 'Manmade structure', 'Bee Keeper', 'wgregory@triad.rr.co', 'NC', 'W28604hite OakTrail', 'Banner Elk', '28604', '', '336-908-5333', 'Yes', 316);
INSERT INTO `honeybee1` VALUES ('2008-10-29 22:29:06', 'Dale Coates', -81.752014, 40.292095, 'I heard about this hive after a wind storm that went throught the area. It brought down a tree in a trailer park. The bee hive was in the tree 8 feet above ground. Dont really know how long it has been there.', 'Living Tree', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'SR 36', 'West Lafayette', '?', '', '', 'Yes', 317);
INSERT INTO `honeybee1` VALUES ('2009-08-04 18:10:38', 'Dale Coates', -81.744942, 40.387184, 'This hive was discovered by a friend that was digging a pond and pushed over a tree that was in the middle of the area that he was digging. the hive was in a soft maple tree and about 25 feet from the ground. I cut the hive from the tree and placed it at this location. Just 200 yards from the first hive another hive was noticed in a tree that was loying down in the woods. that hive was also cut out of the tree and place at this present location. Both hives were very strong. One Italian and the other Carniolan bees.', 'Living Tree', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', '29991 County Road 23', 'Chili', '43824', '', '740 623 8266', 'Yes', 318);
INSERT INTO `honeybee1` VALUES ('2008-10-27 17:20:02', 'gregory putnam', -81.736435, 33.858086, 'in tree', 'Living Tree', 'Bee Keeper', 'greggputt@yahoo.com', 'SC', '111 satcher st', 'ward', '29166', '', '1803-685-6356', 'Yes', 319);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Anne Lattimore', -81.727295, 33.495598, 'They are located on the second floor of our house. The bottom half of the house is brick the second floor is wood the bees have their home between on the outside of course.The first time I noticed them was 2 years ago but they could have been there longer.Seems there are more of them now. I don''t mind them staying there but someone at the farmers market told me they were bad bees well they''ve never misbehaved around me or Mom. ', 'Manmade structure', 'Other', 'art@annelattimore.co', 'SC', '406 Kershaw Pl.S.E.', 'Aiken', '29801', '', '803-648-3564', 'Yes', 320);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dale Coates', -81.697769, 40.314091, 'I was contacted by a painter that was painting this house. Bees have been there 2 years.', 'Manmade structure', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'CR93', 'Fresno', '43824', '', '', 'Yes', 321);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dale Coates', -81.692619, 40.186611, 'The game warden told me that there is a hive in this house. Been there about 4 years. The farmer wants to put new siding on so I will remove them in the spring of 09.', 'Manmade structure', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'SR 541', 'Plainfield', '?', '', '', 'Yes', 322);
INSERT INTO `honeybee1` VALUES ('2011-03-28 22:05:47', 'Citizen Scientist', -81.663803, 30.068333, '50'' off the ground in the leaf canopy of an oak tree. Noticed it about 1 year ago when much of it fell to the ground. The size changes. On private property. ', 'Living Tree', 'Concerned Citiz', 'bobedmazjr@comcast.n', 'FL', '2352-3 State Road 13', 'St. Augustine', '32259', 'We noticed the hive in the tree tops when most of it fell to the ground.It was full of honey and bee larve. The bee''s reclaimed the honey. The hive was small through this past winterit is growing again and getting larger. I''m curious to see if it will fall again this year. It seems the little twigs and leaves cannot hold the weight of the hive. This is in the open in the leaf canopy of a large water oak 50 feet up. Always tons of bee''s in my yard and garden. My friend is a local beekeeper and she looked at what fell.', '904-287-0235', 'Yes', 323);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Adam Brakefield', -81.549171, 35.953815, 'About 1ft above ground in the bottom of a building.its been there for over five years. its out off sight but appers to be a strong hive.', 'Manmade structure', 'Bee Keeper', 'yellowtoy@msn.com', 'NC', '2429 Bill Tuttle Rd', 'Lenoir', '28645', '', '828.312.2653', 'Yes', 324);
INSERT INTO `honeybee1` VALUES ('2008-10-08 16:33:43', 'Carl Smithson Jr.', -81.538811, 39.268410, 'In a huge white oak near the center of Parkersburg City Park about 30'' above ground.', 'Living Tree', 'Bee Keeper', 'carlsmithson@dishmai', 'WV', '', 'Parkersburg', '', '', '304-462-5628', 'Yes', 325);
INSERT INTO `honeybee1` VALUES ('2012-05-02 07:22:00', 'Billiray Armstrong', -81.511749, 37.120052, 'This is a Live Tree between several mail boxes right on Fincastle Street just before you get to Jefferson Street The Entrance is only 2 1/2 feet off the ground. The bee space in the tree is approx. 22 inches straight in 19 inches wide and 3 ft up into the heart of the tree.', 'Living Tree', 'Bee Keeper', 'bgataz@hughes.net', 'VA', '', 'Tazewell', '24651', '', '276-988-2099', 'Yes', 326);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dale Coates', -81.496582, 40.377937, 'My local mail lady saw that I was doing bees and asked if I would remove some bees from her Grandmas house. I went to take a look. They are in an old farm house in the country. They are on the second level going in under the window probably nesting under the floor between the two levels. They have been there at least 7 or 8 years. I plan to extract them in the spring.', 'Manmade structure', 'Bee Keeper', 'coatesdd@yahoo.com', 'OH', 'SR 36', 'Newcommerstown', '?', '', '', 'Yes', 327);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Tobe Knotobee', -81.496048, 28.488533, 'Owl box side of tree 9'' off ground. two years. located on private property. Die off in fall reduces population to minimum spring population explodes. Docile honey bee comb stretching limit of owl box and now pushing open maintenance door.', 'Manmade structure', 'Concerned Citiz', '', 'FL', '', 'Orlando ', '32819', 'do not disturb', '', 'No', 328);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Billiray Armstrong', -81.493317, 37.134781, 'It has been in this concrete wall for 4-6 years by the estimates of business people here. The entrance is 5-6 ft off the ground into a concrete block wall 15-18 ft tall. Back wall of a small mall with businesses in the building.', 'Manmade structure', 'Bee Keeper', 'thompsonvalleybeefar', 'VA', 'Faith Street', 'Tazewell', '24651', 'I am trying to safely remove the hive from the wall with a one way bee escape system that has been modified for this job. The Mayor owns the building and has been protecting the bees from harm by business owners but wants me to attempt to remove them.', '276-988-2099', 'Yes', 329);
INSERT INTO `honeybee1` VALUES ('2011-08-23 08:06:06', 'Stephen Fopeano', -81.457016, 39.845978, '"Found 2009 when swarming (?) Then the entry was covered by bees and I found them by the sound. They seemed to be gone a few days later. The next spring bees were back. The opening to the hive is a foot off the ground obscured by plants in an old locust tree. It is on my property surrounded by rarely mown fields and mixed woodlands. No aggressive behavior I could stand five feet away for hours and watch them. \r"', 'Dead Tree', 'Concerned Citiz', 'fopesteve@att.net', 'OH', '', 'Sarahsville OH', '', '', '216 297 1724', 'Yes', 330);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'JS', -81.419678, 28.993727, 'Approx. 1 year', 'Manmade structure', 'Concerned Citiz', 'theluckie7@aol.com', 'FL', 'Central Blvd', 'Paisley', '32767', '', '', 'Yes', 331);
INSERT INTO `honeybee1` VALUES ('2010-12-05 15:42:04', 'Paul Fudge', -81.411980, 28.690456, 'the hive has been in the water valve box in our front yard for about 18 months. I am trying to move it to the back yard.', 'In the ground', 'Concerned Citiz', 'pfudge@juno.com', 'FL', '211 Lake Gene Dr', 'Longwood', '32779', '', '407-761-4311', 'Yes', 332);
INSERT INTO `honeybee1` VALUES ('2009-07-26 17:13:23', 'Bo Sterk', -81.322861, 29.874811, '"4ft off the ground in a live oak tree.\rTree hole is only 3inch circle. \rLocated in Target store parking lot area.\rNice active hive. Out of the general publics area but can be viewed without getting out of the car. "', 'Living Tree', 'Bee Keeper', 'honeybeeboy@ymail.co', 'FL', 'us 1', 'St. Augustine', '32084', '20ft from US 1 in a small wooded area along the front parking spaces.', '9048241441', 'Yes', 333);
INSERT INTO `honeybee1` VALUES ('2008-10-27 11:00:38', 'Bo Sterk', -81.318077, 29.897350, '"25 feet of the ground. Free form construction on the side of a large Cedar Tree. Size is 12 x 24 \rBee''s are gentle blond Italian. Some drones are solid Black. \rIn front of Kettilinus School on City property.\rA great open air colony. First sighting: 2006\r"', 'Living Tree', 'Bee Keeper', 'barkndog@bellsouth.n', 'FL', '60 Orange St', 'St. Augustine', '32084', '"I was Contacted by the school to remove. A cherry picker is needed no funds. The city and the school board have to work together on the project. Not - The city wants nothing to do with liability of removal. Not a priority.\r"', '904 824-1441', 'Yes', 334);
INSERT INTO `honeybee1` VALUES ('2009-07-26 17:03:36', 'Bo Sterk', -81.311012, 29.876820, '"15ft off the ground in a live oak tree.\rlocated in Willie Gallamor Playground area.\rNice active hive. "', 'Living Tree', 'Bee Keeper', 'honeybeeboy@ymail.co', 'FL', 'Riberia', 'St. Augustine', '32084', '', '9048241441', 'Yes', 335);
INSERT INTO `honeybee1` VALUES ('2010-11-11 09:54:50', 'Karen Riddle', -81.310677, 36.452496, 'Hive has built nest in the summer of 2010 exposed attached to a tree branch of a live tree. ', 'Living Tree', 'Concerned Citiz', 'riddlezoo@yahoo.com', 'NC', '1875 Cranberry Cr Rd', 'LaurelSprings', '28644', 'This is on my farm and I am extremely protective of this beautiful hive. I fear for their survival as I live in the mountains and winters are harsh. It is in the middle of a Christmas Tree field build around a tree branch. I have beautiful pictures. There used to be a hive in an old house nearby. I am interested in any chance of helping this hive survive and fear weather and idiots with guns. I fear there may not be enough honey for their survival as they started late in the summer to early fall. I first found the hive around Oct 15th but it has grown since. The lower half is all that has honey. Is there such a thing as supplemental feeding? Any help would be appreciated. Can this hive be relocated to the old house by cutting off the branch to provide shelter? I have no experience but have always wanted to learn more and would love to become a beekeeper in retirement (soon).', '336-977-3973', 'Yes', 336);
INSERT INTO `honeybee1` VALUES ('2011-05-21 23:34:23', 'Billiray Armstrong', -81.291321, 37.050812, 'There are more than 10 Langstroth BeeHives near this location all doing fine. Elevation is between 2930 ft. and 2980 ft. Excellent Honey with Sourwood Locust Tulip Poplar Apple Basswood Peach Clover and Blueberry present.', 'Manmade Beehive', 'Bee Keeper', 'thompsonvalleybeefar', 'VA', '571 Fernwood Drive', 'Tazewell', '24651', '', '276-988-2099', 'Yes', 337);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Scott L. Bowen', -81.290993, 36.828007, '"This hive covers approximately 15X 20 feet in the back or South wall of an old store and is located about 10 feet above the ground.\r Drive South of Rural Retreat on bike route 76 for 4 miles at which point the road splits left to Speedwell and Rt.21 and right on St Rt. 614 to Sugar Grove. Bear right and the store is 30 yards in and on the left."', 'Manmade structure', 'Bee Keeper', 'abowen13@earthlink.n', 'VA', 'St. Rt. 614', 'Rural Retreat', '24368', '', '276-228-7480', 'Yes', 338);
INSERT INTO `honeybee1` VALUES ('2010-09-27 23:49:20', 'Troy Dere', -81.249069, 28.578756, '35 feet up in a pine tree trunk.', 'Living Tree', 'Bee Keeper', 'troydere@gmail..com', 'FL', '', 'Winter Park', '32817', '', '321-217-5464', 'Yes', 339);
INSERT INTO `honeybee1` VALUES ('2008-09-27 20:53:01', 'Fred Bagley', -81.228607, 41.447742, 'In a hollow pine next to drive way. About 8 feet off ground. Honey bees have used this tree for at least 10 years. Honey bees were first brought to this farm in the 1920''s. ', 'Living Tree', 'Concerned Citiz', 'fmbagley@cox.net', 'OH', '11331 Music Street', 'Newbury', '44065', '', '703-358-1760', 'Yes', 340);
INSERT INTO `honeybee1` VALUES ('2012-03-30 22:43:38', 'Jeff Funderburk', -81.099045, 35.271355, 'In bottom of hollow poplar tree almost ground level immediately adjacent to my driveway. It has been there for about 6 years.', 'Living Tree', 'Bee Keeper', 'jffunderburk@carolin', 'NC', 'Rogosin Blvd.', 'Lowell', '28098', '', '704-824-2816', 'Yes', 341);
INSERT INTO `honeybee1` VALUES ('2009-06-08 11:47:45', 'Scott L. Bowen', -81.084297, 36.944096, '6 feet above the ground level in a pine tree with forked trunk. The pine is in the SW corner of the lot adjacent to a dead pine and is second in line N on the NS boundry', 'Living Tree', 'Bee Keeper', 'abowen13@earthlink.n', 'VA', '515 W. Washington St', 'Wytheville', '24382', '', '276-228-7480', 'Yes', 342);
INSERT INTO `honeybee1` VALUES ('2009-08-16 20:22:30', 'Eleven Oaks Farm', -80.939865, 33.557625, 'The hive is in a large live oak tree 15 ft. off the ground and the swarm located there in April 2009. The tree is at our homeplace at the end of our driveway.', 'Living Tree', 'Concerned Citiz', 'pjnadler@sc.rr.com', 'SC', '4912 North Road', 'Orangeburg', '29118', 'We saw a swarm in April of this year congretating on a Wisteria branch about 4 ft. off the ground. They left and came back then disappeared. A couple of days later we noticed them coming in and out of a hollow in a large live oak tree about 15 ft. off the ground. We''ve never noticed a hive on our 3 acres before and know of no nearby feral or cultivated hives. The previous year we put in an above-ground pool and noticed honey bees drinking near the filter. We think the water source was a factor in the bees locating to our property. I would like information about providing a safer drinking source for the bees. Thanks Peggy Jo Nadler', '803-546-0327', 'Yes', 343);
INSERT INTO `honeybee1` VALUES ('2011-05-04 12:26:03', 'Billiray Armstrong', -80.917030, 37.002914, 'Hive is located in a Large Red Oak Tree approximately 35 ft. off the ground just up hill from a small pond at the left of pasture just in the woods and down hill from last house on the road Property Owner does not want the tree cut down. They are well established for last 4 years. ', 'Living Tree', 'Bee Keeper', 'thompsonvalleybeefar', 'VA', 'Quail Forest Ln', 'Max Meadows', '24360', 'Extracting them has been discussed with the property owner who is cooperative with the idea and wants the bees to live. Only if a way could be devised w/o cutting down the tree.', '276-988-2099', 'Yes', 344);
INSERT INTO `honeybee1` VALUES ('2009-10-12 20:10:48', ' Saunders', -80.915016, 26.751282, '10-15''on Oak tree branch in our back yard noticed a year ago after tropical storm it had 2 cones then and 1 on the groundunknowen how many cones now over foot wide and long maybe 4-6 cones now_. Really don''t want to get up there and exact measure.', 'Living Tree', 'Concerned Citiz', 'slinky@embarqmail.co', 'FL', '437 Redish Circle', 'Clewiston', '33440', 'This hive is thriving always covered with bees every inchUse loud riding lawn mower to cut grass right under hive bees have yet to attach. can stand right under it to look at it but choose not to. Also have a tree Nursery right behind us across our little creek. Would love for someone to move them out with out killing them. ', '863-983-9753', 'Yes', 345);
INSERT INTO `honeybee1` VALUES ('2009-10-12 20:21:19', ' Saunders', -80.915016, 26.751282, '10-15''on Oak tree branch in our back yard noticed a year ago after tropical storm it had 2 cones then and 1 on the groundunknowen how many cones now over foot wide and long maybe 4-6 cones now_. Really don''t want to get up there and exact measure.', 'Living Tree', 'Concerned Citiz', 'slinky@embarqmail.co', 'FL', '437 Redish Circle', 'Clewiston', '33440', 'This hive is thriving always covered with bees every inchUse loud riding lawn mower to cut grass right under hive bees have yet to attach. can stand right under it to look at it but choose not to. Also have a tree Nursery right behind us across our little creek. Would love for someone to move them out with out killing them. ', '863-983-9753', 'Yes', 346);
INSERT INTO `honeybee1` VALUES ('2010-05-05 15:06:21', 'Concerned Citizen', -80.894730, 36.521210, 'beehive', 'Dead Tree', 'Concerned Citiz', 'dcthurber@hotmail.co', 'NC', '223 Baldwin Dr', 'lowgap', '27024', 'population left tree summer 2009 in a swarm. hive was in rotted area of tree where a limb had been. Tree subsequeently blown over 3/10 and 3 sq ft of comb removed. Colony likely reestablished nearby.', '', 'Yes', 347);
INSERT INTO `honeybee1` VALUES ('2008-09-25 08:10:13', 'K Freeman', -80.846497, 35.229633, '10 feet off the ground in a living oak tree. Hive is directly outside the fence of the Federal Courthouse. Standing outside the courthouse looking towards the street the hive is in the first oak tree to the right. Been there about 6 months moved in early summer ''08', 'Living Tree', 'Bee Keeper', 'kfreemannc@mac.com', 'NC', '401 W Trade Street', 'Charlotte', '28202', '', '', 'Yes', 348);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Robert L. Huntley', -80.832443, 35.282112, 'Eight hives on custom made medal stands one foot off ground. I am just now in the process of setting up and establishing.I just read Beekeeping A Practial Guide by Richard E.Bonneyand am now reading a first edition copy of A.I.RootABCandXYZ of Bee Culture given to me by my mentor Mr. Woodrow Trull who gave me all of his bee equipment and supplies to include a complete extracting apparitis. Mr. Trull is 93 yrs.young.', 'Manmade structure', 'Bee Keeper', 'roberthuntley@earthl', 'NC', '3408 Nevin Rd', 'Charlotte', '28269', '', '704-599-2093', 'Yes', 349);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Thresea Ervin', -80.812370, 35.605785, 'I haven''t seen the hive myself it is under my house. The bees come and go under the door to my laundry room.', 'Manmade structure', 'Concerned Citiz', 'malfoystinks@aol.com', 'NC', 'Goodwin Cr', 'mooresville', '28115', 'My sis/roommate is deathly allergic to bees and I would like for them to be removed safely without harm to persons or bees. I just can''t afford for someone to come and have them removed.', '704-819-7903', 'Yes', 350);
INSERT INTO `honeybee1` VALUES ('2009-04-21 22:13:22', 'Wayne Hansen', -80.782288, 35.164913, '6 feet off ground in tree near the road. Easy to see. Issued a swarm this month - 4-2009.', 'Living Tree', 'Bee Keeper', 'waynelisahansen@bell', 'NC', '421 Livingston', 'Charlotte', '28211', '', '704-536-4805', 'Yes', 351);
INSERT INTO `honeybee1` VALUES ('2008-10-28 07:59:33', 'Beth', -80.741158, 34.921673, 'at least 2 years old', 'Living Tree', 'Bee Keeper', 'ecmyles@windstream.n', 'NC', '509 S. Providence St', 'Waxhaw', '28173', 'Hive is located inside the oak tree to the right of the left sidewalk at the front of South Providence School. The hive entrance is approximately 20 feet up. My husband works at the school and collected a swarm from the hive last spring. We combined that swarm with a weaker hive.', '704-843-5433', 'Yes', 352);
INSERT INTO `honeybee1` VALUES ('2010-06-14 14:38:43', 'D.Butler', -80.734062, 43.101482, 'beehive', 'Living Tree', 'Concerned Citiz', 'dbutler@execulink.co', 'AL', '708 Pattullo Ave.W', 'Woodstock', '', '', '519-456-3025', 'Yes', 353);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Renee Garner', -80.718002, 35.111000, 'This hive is between the brick facade and walls of our house approximately 10 feet off the ground. The entrance is a hole in the mortar where the fireplace juts out and the brick meets the upper siding. ', 'Manmade structure', 'Concerned Citiz', 'renee.garner@gmail.c', 'NC', 'Sadie Drive', 'Matthews', '28105', 'This hive is in the side of our house and has been there for 20-something years. The colony splits and swarms annually though I''m not sure how long it has been doing that. We noticed it the summer after the woods that were adjacent to the property were cleared out for additional homes. ', '7043217829', 'Yes', 354);
INSERT INTO `honeybee1` VALUES ('2011-01-07 11:24:56', 'Kristen Yoder', -80.708839, 40.992245, '30 or so feet off the ground has been around for at least the past 4 years size = unknown It is on the property of Mill Creek Preserve next to a small east-west running creek if you climb the hill across the creek and look north for a pair of trees joined at the trunk you will find the hive (well at least the opening in the tree). In the summer the bees can be found collecting water in a rocky bend in the creek and if it is warm enough a large mass of bees can be seen hanging from the entrance. PLEASE NOTE: The preserve is not open to the public in that area...permission may be needed before accessing the hive location. I am willing to show the location of the hive is anyone wants to call or email..', 'Living Tree', 'Bee Keeper', 'bigbluemarble@sbcglo', 'OH', 'Tippecanoe RD', 'Boardman', '44512', '', '330.533.4703', 'Yes', 355);
INSERT INTO `honeybee1` VALUES ('2008-10-03 12:34:48', 'Tim Hambrick', -80.700073, 36.403599, 'Hive is in a hollow oak tree. Entrance hole is approx. 15 feet off the ground.', 'Living Tree', 'Other', 'tim_hambrick@ncsu.ed', 'NC', '611 Gillespie St', 'Dobson', '27017', '', '', 'Yes', 356);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Kristen Yoder', -80.680077, 41.082615, 'Entrance is around 40+ feet off the ground and is at a juncture between the wood siding and the stone chimney of a structure this hive has been around for years and years and is HUGE..It is located on the west side ''Pioneer Pavilion'' of Mill Creek Park. Mill Creek would very much love for this hive to be relocated without too much damage to the structure.', 'Manmade structure', 'Bee Keeper', 'bigbluemarble@sbcglo', 'OH', 'Old Furnace RD', 'Youngstown', '44511', 'One of the gentlemen in the Mill Creek Maintenance Department alerted me to this hive. Very few are aware of it...Mill Creek officials have tried to kill it off without success. The would prefer it not continue living at the Pioneer pavilion.', '330.533.4703', 'Yes', 357);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Breon O''Dell', -80.676727, 37.145199, 'hive is about 10 foot off ground in the south side of old farm house it is at least 10 years old very strong hive.', 'Manmade structure', 'Bee Keeper', 'bodell@vt.edu', 'VA', '', 'Dublin', '24084', '', '(540)231-9433', 'Yes', 358);
INSERT INTO `honeybee1` VALUES ('2010-02-16 11:47:08', 'John hohnerlein', -80.664284, 32.915462, '"Dead hollow tree 30 ft off ground\rdeep in tree"', 'Dead Tree', 'Concerned Citiz', 'Jhohnerlei@aol.com', 'SC', 'Elmwood dr', 'Walterboro', '', '', '843-276-1801', 'Yes', 359);
INSERT INTO `honeybee1` VALUES ('2009-02-17 17:21:11', 'Jerry Nolan', -80.623253, 35.140915, 'It is in a hollow of a tree approx 12-15 feet up next to the parking lot of a daycare', 'Living Tree', 'Concerned Citiz', 'jerry_nolan@danka.co', 'NC', 'Stevens Mill Rd', 'Stallings', '28104', '', '704-882-1630', 'Yes', 360);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'juli', -80.597076, 28.027138, 'hive in cinder blocks with a shed on top it..unsure how long it has been there ... are not aggressive ..smallish bees', 'Manmade structure', 'Other', 'plated.heart@yahoo.c', 'FL', 'route1', 'palm bay', '32950', '', '3213450322', 'Yes', 361);
INSERT INTO `honeybee1` VALUES ('2008-08-28 20:44:37', 'Denise Miller', -80.580597, 36.056595, 'Hive is about three feet off the ground in an oak tree. Tree is adjacent to our driveway. Vertical hole in the tree is about three inches wide and about eighteen inches tall. The bees have been there about four months.', 'Living Tree', 'Concerned Citiz', 'carolinakatie@gmail.', 'NC', '2912 Wyo Rd.', 'Yadkinville', '27055', '', '336 463-2723', 'Yes', 362);
INSERT INTO `honeybee1` VALUES ('2009-11-09 07:37:29', 'bk', -80.538330, 37.105961, 'The colony is about 12 feet off the ground in a knot on the trunk of a black oak tree. Unsure of age of hive. Tree located in old family cemetary at top of hill.', 'Living Tree', 'Other', 'brian.kreowski@vdacs', 'VA', '2525 Wintergreen Dr.', 'Radford', '24141', 'Sample of bees collected 22 October 2009 given to Dr. Debbie Delaney 7 November 2009. ', '276-608-6349', 'Yes', 363);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Webb', -80.486130, 36.856361, 'Located in a thick wall of an old farmhouse. The owner says the colony has been there for many years as reported by his elderly mother. Bees spill over into a recess accesible from the attic. They appear to be Italian race.', 'Manmade structure', 'Bee Keeper', 'jw@virginiamountains', 'VA', '5738 Floyd Hwy S.', 'Willis', '24343', 'Located in a friend''s home', '540-789-8400', 'Yes', 364);
INSERT INTO `honeybee1` VALUES ('2010-03-30 01:56:34', 'Andrew Ratcliffe', -80.420631, 37.235107, 'I found this hive late last Fall walking home from class I haven''t had an opportunity to check on them since it warmed back up though. The hive is in a cavity in a tree immediately adjacent to the sidewalk five feet off the ground at the corner of Main and Prices Fork. ', 'Living Tree', 'Concerned Citiz', 'drewratcliffe@gmail.', 'VA', '', 'Blacksburg ', '24060', '', '828 817 4192', 'Yes', 365);
INSERT INTO `honeybee1` VALUES ('2011-10-13 10:50:53', 'R Reid', -80.412651, 37.268147, 'This is the same hive and log from the tree on Price''s Fork and N Main St. In June 2010 it was cut for road expansion and we moved it to the local community gardens where it is still thriving a year and half later. 7'' tall x 2'' diameter locust log.', 'Dead Tree', 'Bee Keeper', 'rkereid@comcast.net', 'VA', 'Maywood St', 'Blacksburg', '24060', '', '5403200763', 'Yes', 366);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Wayne Hinson', -80.397781, 35.163914, '5 feet off ground 10 years old size unknown side of old abandoned house near Rocky River on Hwy. 200 North of Monroe just inside Union County. ', 'Manmade structure', 'Bee Keeper', 'marie.hinson@ucps.k1', 'NC', '6403 Morgan Academy ', 'Monroe', '28110', '', '704/753-4732', 'Yes', 367);
INSERT INTO `honeybee1` VALUES ('2010-02-06 22:04:46', 'R Reid', -80.384216, 37.246181, 'Two colonies living in stored bee boxes under shed. One has been there since 1997 the other since 2000. Both colonies swarm most years and appear to be very strong. They have had no management from me in the time that they have lived there.', 'Manmade Beehive', 'Bee Keeper', 'rkereid@comcast.net', 'VA', '1706 Harding Rd', 'Blacksburg', '24060', 'I have been inspired to get back in to beekeeping after giving it up because of mites in 1994. I plan to do some splits and raise queens from these two hives.', '5409518342', 'Yes', 368);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Anthony Sharum', -80.304825, 35.502438, 'The hive is located in an abandoned house. entrance is about 5'' off ground in the exterior wall toward the rear of the house. It appears that the hive has been there for some time and had plenty of working bee activity and honey smell during warm weather. The house has been empty for a number of years and appears to be used as storage. Owner should be easily located on county GIS system.', 'Manmade structure', 'Other', 'ncwrc306@aol.com', 'NC', 'Rowan Cabarrus Road', 'Gold Hill', '28071', '', '704-239-0850', 'Yes', 369);
INSERT INTO `honeybee1` VALUES ('2008-11-30 22:22:10', 'Jon Hanna', -80.303413, 36.053783, 'In cavity of large white oak on church grounds. Approximately 20'' off ground. First noticed in 2006. ', 'Living Tree', 'Concerned Citiz', 'ecologic@bellsouth.n', 'NC', '2390 Bethel Church R', 'Winston-Salem', '27103', '', '336.403.3121', 'Yes', 370);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Anna Brown', -80.302116, 35.051571, 'On the ground in what looks like an oil barrel. Active hive found it 3 years ago. Private Property', 'Manmade structure', 'Bee Keeper', 'ambdkf@earthlink.net', 'NC', '6717 S.C. Helms ', 'Marshville', '28103', '', '(704)321-1586', 'Yes', 371);
INSERT INTO `honeybee1` VALUES ('2008-06-24 22:50:07', 'Buddy Marterre', -80.298599, 36.153988, 'beehive', 'Living Tree', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Maybe', 372);
INSERT INTO `honeybee1` VALUES ('2008-12-04 18:05:57', 'Ed Comer', -80.285812, 35.811062, 'This hive is in a hollowed out tree still alive about 20 feet above ground. I think it''s been there for several years with a steady stream of bees during summer-behind field of mobile homes on Sink Inn Rd (Service Recovery Corp)', 'Living Tree', 'Concerned Citiz', 'srcorp@lexcominc.net', 'NC', '375 Sink Inn Rd', 'Lexington', '27292', '', '3362431516', 'Yes', 373);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Charlie Askins', -80.277443, 35.846413, 'The hive is located in an old house. As you look at the house from the front the hive entrance is located in the last pillar on the left. The owner of the property will be accomadating. ', 'Manmade structure', 'Bee Keeper', 'charlieaskins', 'NC', '', 'Lexington', '', '', '336-352-5751', 'Yes', 374);
INSERT INTO `honeybee1` VALUES ('2009-11-13 15:03:41', 'Susan Humeston', -80.262352, 26.016556, 'Hive built in our back yard using a NC gourd as a base to build on. Hive arrived in 3/09 - built up hive to hang off gourd to within 3 feet of ground - about 4 or 5 rows of hive roughly 4 feet from top to bottom. In our back yard on the right by our fence opening toward the back.', 'Living Tree', 'Concerned Citiz', 'susan.humeston@gmail', 'FL', '8810 NW 10th Street', 'Pembroke Pines', '33024', '"The hive lost part of it''s bottom in a wind storm. Lots of bees died on that piece. Ants took up residence underneath hive immediately. Rest of hive looks sickly - a brown substance is covering part of a section of the hive that was uncovered by the big piece that fell.\rI''m very concerned about the health of the remaining bees. The hive has decreased greatly in number and what is left is apathetic. I want to buy medicine and put it out for these bees because I''m afraid they are just spreading the disease they have."', '954-609-5128', 'Yes', 375);
INSERT INTO `honeybee1` VALUES ('2008-11-11 23:26:54', 'Joel Lawrence', -80.225212, 36.541260, 'The hive is located in the hollow of an old oak tree beside Peters Creek Baptist church. The tree is next to the church''s picnic shelter at the edge of the parking area and graveyard and stands over a brick housing for an outdoor water faucet. The bees enter the hollow about 20 - 30 feet above. ', 'Living Tree', 'Bee Keeper', 'jalawrence@alcatel-l', 'NC', '6561 Nc 8 Hwy N', 'Lawsonville', '27022', '"This church is used as a rest stop for an annual bike ride. The last visit was in May 2008 and the bees were active.\r\rI saw 2 large swarms (basketball size) hanging on limbs of the tree in April 2007. "', '336 885 8157', 'Yes', 376);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jerry Johnson', -80.217949, 35.058849, '10 ft off the ground in an old house on private property. The hive has been there 3 years.', 'Manmade structure', 'Concerned Citiz', 'jerry.johnson@hometr', 'NC', '249 johnson cove', 'Burnsville', '28714', '', '828-429-3835', 'Yes', 377);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'michael obrien', -80.187523, 26.311016, 'it has been here for about a month now and set up home in a wooden reel which local code enforcement had just told us that we have to get rid of the reel that the honey bee hive is in. the nest is about 1ft x 1 ft and there is allot of them coming and going it is located at the rear of our building.', 'Manmade structure', 'Concerned Citiz', 'chicago77mike@gmail.', 'FL', '6601 lyons rd suite ', 'coconut creek', '33073', 'please help re-locate them before code enforcement comes back i dont want them to die over this matter .', '954-829-4315', 'Yes', 378);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'brian mcdonald', -80.178391, 26.108549, '"15-20 ft. \rsix months"', 'Manmade structure', 'Bee Keeper', 'btmcd@netzero.net', 'FL', 'riverland road', 'fort lauderdale', '33312', '', '', 'Yes', 379);
INSERT INTO `honeybee1` VALUES ('2009-05-03 21:13:51', 'Ricky Weavil', -80.135910, 36.106297, '30 ft off the ground - in a hole in a living oak tree....very active hive', 'Living Tree', 'Bee Keeper', 'weavilhoney@gmail.co', 'NC', 'Hwy 150', 'Kernersville', '27284', '', '336-462-7094', 'Yes', 380);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'michel gatchell', -80.126556, 26.622908, 'underneath a house large hive extracted for saftey. ', 'Manmade structure', 'Bee Keeper', 'landman66@yahoo.com', 'FL', '', 'greenaceres', '33463', '', '561 662-9140', 'Yes', 381);
INSERT INTO `honeybee1` VALUES ('2008-06-30 23:13:29', 'James H. Dilda', -80.124840, 36.080093, 'The hive is about 10 feet off the ground inside a somewhat enclosed split in a living tulip tree (I believe the scientific name would be tulipfera grandiflora or something like that.) in my back yard. It has been there about three years. I have no way of knowing how large it is. ', 'Living Tree', 'Concerned Citiz', 'jdilda@triad.rr.com', 'NC', '1584 Jubilee Trail', 'Kernersville', '27284', 'To find it just ring the doorbell and my wife will be glad to show you. Feel free to e-mail me as indicated or call 336.287.7708 and we can arrange a get-together....1584 Jubilee Trail Kernersville NC 27284', '336.287.7708 ', '', 382);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'April Morgan', -80.124451, 39.568977, 'A hive we owned swarmed in the spring of 2004 and entered the side of our house through an old small hole once used to run cable TV. They live between the outer and inner wall in our living room. They have been there ever since with no medication no human intervention. They seemed to be very strong this summer and are apparently doing very well - actually better than other hives we manage. They are approximately 3'' from the ground and very gentle. We''ve never been stung although we pass by their entrance often.', 'Manmade structure', 'Bee Keeper', 'amorgansupport@veriz', 'WV', 'RR 2 Box 128 Pharoah', 'Rivesville', '26588', '', '304-278-9855', 'Yes', 383);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Miles', -80.069077, 34.965405, 'In a old out building .2 hives in the walls said have been there for 12 yrs. 12 ft. off the ground.', 'Manmade structure', 'Bee Keeper', 'johnmiles1394@windst', 'NC', 'Wade Street', 'Wadesboro', '28170', '', '704-848-8855', 'Yes', 384);
INSERT INTO `honeybee1` VALUES ('2008-11-03 07:16:51', 'FORREST GOFF', -80.012222, 39.535831, '" height app. 12 feet\r app. 2 years\r large hickory tree"', 'Living Tree', 'Bee Keeper', 'bgshoney@yahoo.com', 'WV', ' Joes Run Road', 'Morgantown', '26508', '', '304-692-1395', 'Yes', 385);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Miles', -79.996994, 34.962406, 'hive in a wall of a old house east of Lilesville on old hwy 74. 1/2 miles east of town. about 5 ft off the ground next to a window.', 'Manmade structure', 'Bee Keeper', 'johnmiles1394@windst', 'NC', 'Old Hwy 74', 'Lilesville', '28091', '', '704-848-8855', 'Yes', 386);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Miles', -79.984909, 34.967457, '20 ft of the ground in a block wall old gas station 1 feral hive. how long it been there is unknown', 'Manmade structure', 'Bee Keeper', 'johnmiles1394@windst', 'NC', 'west wall st', 'Lilesville', '28091', '', '704-848-8855', 'Yes', 387);
INSERT INTO `honeybee1` VALUES ('2008-07-08 18:55:35', 'Brian D. Wright', -79.980469, 35.317368, 'We built our house 2 years ago and the bees were in a hollow tree and we had the land 1 year before that so they have been there at least 3 years. Both of my hives have swarmed this year so I hope the new queen mated with the drones from this colony. I know they have been hearty for at least 3 years but most likely a lot longer. I call them my 3rd hive. I am in Rowan County and am a member of the county club here where I am program Director. Feel free to contact me. As a matter of fact I might call on you to speak at one of our meetings! Thanks.... ', 'Living Tree', 'Bee Keeper', 'britam@windstream.ne', 'NC', '445 Binder Mountain ', 'Faith', '28041', '', '704-279-7133', '', 388);
INSERT INTO `honeybee1` VALUES ('2008-10-28 09:23:04', 'mick madison', -79.953865, 39.622868, 'tree next to sidewalk 10'' high. hive has been active for over 3 years', 'Living Tree', 'Bee Keeper', 'jmmadison@verizon.ne', 'WV', 'n side of jackson st', 'morgantown', '', '', '3042966421', 'Yes', 389);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Rich Miles', -79.882233, 36.061710, 'In the side of an old outside storage building. There are two entrances to the hive. Both about 3 feet off the ground. On private property. No Trespassing.', 'Manmade structure', 'Bee Keeper', '', 'NC', '', 'Greensboro', '27409', 'This hive has been here off and on for about 20 years in the middle of the city.', '3363828404', 'Yes', 390);
INSERT INTO `honeybee1` VALUES ('2008-07-01 10:33:55', 'Brent Brackett', -79.851852, 36.129139, 'The hive is located about 20 feet above the ground in a Sycamore tree. They recently swarmed and divided. This is the third straight year they have lived in the same location.', 'Living Tree', 'Concerned Citiz', 'brent.brackett@green', 'NC', '', '', '', '', '', '', 391);
INSERT INTO `honeybee1` VALUES ('2008-06-30 14:57:03', 'Bruce Loving', -79.851547, 36.068283, '"hive is located in tree behind apartment complex next to fence of office park off Walker Entrance is a cut-off branch stump on trunk about 20'' high. Highly active. Threw several swarms off in April/May 2008.\rSecretary in Councilman''s office can point it out."', 'Living Tree', 'Bee Keeper', 'bruce@lovingscents.c', 'NC', '', '', '', '', '', '', 392);
INSERT INTO `honeybee1` VALUES ('2008-06-30 19:46:17', 'Tommy Hayes', -79.815468, 35.681431, '5 feet off of ground hollow tree---not sure how long its been there--the tree is in front yard of 201 Foster St in Asheboro NC. Very strong colony.', 'Living Tree', 'Bee Keeper', 'ttthay@yahoo.com', 'NC', '', '', '', '', '', '', 393);
INSERT INTO `honeybee1` VALUES ('2009-03-17 14:59:46', 'Stan Styers', -79.801384, 36.093983, 'This hive is located in the seam of the trunk of what I believe to be a variety of oak tree. It is approximately 3-4 feet off the ground on the northwest side of the tree facing Nottingham Road. It is only a few feet from the road and close to a nearby stream. It has been active for at least two years.', 'Living Tree', 'Concerned Citiz', 'ssteton@aol.com', 'NC', '710 Nottingham Road', 'Greensboro', '27408', '', '336.577.1128', 'Yes', 394);
INSERT INTO `honeybee1` VALUES ('2008-06-30 23:55:46', 'Thaxton Richardson', -79.772301, 36.235058, 'Bees in unused hive boxes stored in a shed about eight feet above ground. Hive established about three or four weeks. Size unknown at this time.', 'Manmade Beehive', 'Other', 'trich3629@bellsouth.', 'NC', '', '', '', '', '', '', 395);
INSERT INTO `honeybee1` VALUES ('2008-12-02 10:29:40', 'angela', -79.538834, 36.100471, 'this hive is located in the front yard of our house in a live tree hive is about 25 feet off ground it is at least 2 years old during the warm months there are an extremely large amount of bees surrounding opening my family and I are very excited about the hive', 'Living Tree', 'Concerned Citiz', 'agschick@aol.com', 'NC', '510 cummings st', 'gibsonville', '27249', '', '336-446-0438 or 209-', 'Yes', 396);
INSERT INTO `honeybee1` VALUES ('2008-12-03 19:13:20', 'Fred Weigel', -79.524559, 36.250237, 'beehive', 'Living Tree', 'Concerned Citiz', 'Jfredweigel@aol.com', 'NC', 'Kerr Chapel rd', 'Elon', '27249', '', '336 524 8775', 'Yes', 397);
INSERT INTO `honeybee1` VALUES ('2008-07-03 11:45:07', 'Christina Teague', -79.515610, 35.547314, 'Hive is living in a dead sweetgum tree on the edge of a cornfield using an entrance at ground-level. We have been watching the hive for 4 years now and it is still going strong. ', 'Dead Tree', 'Bee Keeper', 'sweetannie245@hotmai', 'NC', '601 Fall Creek Churc', 'Bennett', '27208', 'The hive is about 50 yards away from the road and you''ll need to ask permission before you go look at it.', '336-581-3703', '', 398);
INSERT INTO `honeybee1` VALUES ('2008-07-03 11:49:42', 'Christina Teague', -79.514923, 35.546196, 'Hive is about 20 feet up a large sweetgum tree. Bees have been seen in this tree for over 10 years but I don''t know if they are the same hive or are recent move-ins.', 'Living Tree', 'Bee Keeper', 'sweetannie245@hotmai', 'NC', 'Fall Creek Church Rd', 'Bennett', '27208', 'I can''t remember the house number of the trailer the tree is growing near. The tree is growing on the edge of the highway right of way.', '336-581-3703', '', 399);
INSERT INTO `honeybee1` VALUES ('2009-06-05 16:50:25', 'Barry Madison', -79.508484, 35.128342, '"First noticed 5 June 2009\rin red oak tree 4 foot circumference\rentrance is 6 inches from ground\rfacing north 20 yards from log barn\r.6 miles from state road"', 'Living Tree', 'Bee Keeper', 'hdpymadison@aol.com', 'NC', '195 Sunny Vue Farm R', 'Aberdeen', '28315', '"this hive is probably a 2009 swarm from\rone of our managed hives"', '910 281 4401', 'Yes', 400);
INSERT INTO `honeybee1` VALUES ('2008-06-30 11:47:28', 'Al Justice', -79.507080, 35.558159, 'Colony in a maple tree about 15 ft. up. They have been there at least 3 years. Another colony was in a old stump near by. They died out this past winter; yet there is a swarm in there now. I captured a swarm from the stump two years ago. They are doing well.', 'Living Tree', 'Bee Keeper', 'flatwoodfarm@interga', 'NC', '', '', '', '', '', '', 401);
INSERT INTO `honeybee1` VALUES ('2009-03-29 14:44:49', 'R.Scott Rivera', -79.501701, 36.102932, 'beehive', 'Living Tree', 'Bee Keeper', 'srivera@elon.edu', 'NC', 'Truit', 'Elon', '27244', '"Located On Private Property Owned By Elon University. Not To Be Disturbed.\rIf there are any questions please contact Scott Rivera @ srivera@elon.edu\ror Phone (336) 684-9161"', '(336) 684-9161', 'Yes', 402);
INSERT INTO `honeybee1` VALUES ('2009-12-30 21:12:16', 'Butch A.', -79.501190, 35.025497, 'Hive is located in a a cut in the tree next to the Air Traffic Control tower. It''s been there approxamently 1.5 years. Personal are instructed to remain clear. Hive is located inside a perimeter gated compound.', 'Living Tree', 'Concerned Citiz', 'Bobbies.books@yahoo.', 'NC', 'Mackall Army Airfiel', 'Aberdeen', '', 'Contact me through email if needed.', '910-396-7308', 'Yes', 403);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Don Paschal', -79.436256, 35.488281, '6 ft off ground in wall of old house been there about 3 yrs', 'Manmade structure', 'Concerned Citiz', 'dpaschal@nc.rr.com', 'NC', '515 Jonah Rd', 'Glendon', '', '', '919.848.8491', 'Yes', 404);
INSERT INTO `honeybee1` VALUES ('2009-04-16 21:06:24', 'Amy C.', -79.296257, 36.507099, 'Bottom of a tree is hollow. Bees are entering at almost ground level.', 'Living Tree', 'Concerned Citiz', 'amy_chandler@uncg.ed', 'NC', 'Murray Road', 'Blanch', '', '', '3363122126', 'Yes', 405);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'David Kopf', -79.285286, 35.713486, 'Five feet up between studs under rotting pine clapboard siding on north wall of old house. Several thousand bees new this year. A larger hive was present in same wall from ~2000 to ~2004. Possibly the old blown insulation has had some protective effect.', 'Manmade structure', 'Bee Keeper', 'dak664@embarqmail.co', 'NC', '', '', '', '', '', 'No', 406);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jeffrey Welch', -79.229538, 35.635674, 'The hive is located in the wall of a smoke house moved from Kernersville. The local colony recolonized an abandoned hive after the building was moved. It has been there 3-4 years.', 'Manmade structure', 'Concerned Citiz', 'Jeff_Welch1@msn.com', 'NC', '', '', '', '', '', '', 407);
INSERT INTO `honeybee1` VALUES ('2008-06-30 10:05:33', 'Colleen Kendrick', -79.214165, 35.761532, 'HIve is in old Oak tree one of few trees left standing in field clear cut for impending development. Brought Don Hopkins and our entymologist friend from Columbia (forgothis name)to see about 3 years ago. Don thinks bees may be Italian descendents of deceased Master beekeeper in area. There is a hole near the ground and at least one more higher up. Discovered ~ 4 yrs.ago by dear friends whose neighbor was caretaking land before owner sold for development. Further clearing of land on hold due do econonmy; have attempted to contact atty''s for developer to no avail. Will be happy to show tree. ', 'Living Tree', 'Bee Keeper', 'shrijardineuse@hotma', 'NC', '', '', '', '', '919-210-4418', '', 408);
INSERT INTO `honeybee1` VALUES ('2008-10-02 16:17:31', 'Janet Langley', -79.189453, 35.483040, '"This is Woodbrige off of Lee Ave Exit.House address is 1309 First Pointe\rSanford N.C. 27332.The hive is in a Big White oak tree about 20 feet off the ground.Its been hear about five or six years.Two diffident times a colony has left the tree.We Found someone to come and get one of them but the lest one got gone before we could get someone to get them.There is a lot of them it looks like."', 'Living Tree', 'Concerned Citiz', 'langleylanet@yahoo.c', 'NC', 'Lee Ave Exit', 'Lee', '27332', '', '919-775-2925', 'Yes', 409);
INSERT INTO `honeybee1` VALUES ('2008-06-30 10:13:12', 'Colleen Kendrick', -79.180519, 35.839428, 'Owner of 81 Oak Bluff Greg Huckabee called to inform of hive in tree next to back deck. On inspection found honeybees entering tiny crack in wounded area about 15ft. off ground. Owner amenable to sampling before trapping out of tree. Mapquest mislabled nearest road is Jones ferry NOT Crawford Dairy.', 'Living Tree', 'Bee Keeper', 'shrijardineuse@hotma', 'NC', '', '', '', '', 'Owner cell is: 919-4', '', 410);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Ralph Shaw', -79.171608, 35.371765, 'Hive is in the exterior walls behind clapboard siding of occupied residence the only two story house on Shaw Pond Road. By my personal knowledge it has been continually active since before 1940 and was still there this spring despite the house having been sandblasted and restored some 8 or 10 years ago.', 'Manmade structure', 'Concerned Citiz', 'ralphshaw@embarqmail', 'NC', '', '', '', '', '', '', 411);
INSERT INTO `honeybee1` VALUES ('2008-09-10 15:09:03', 'Gwendolyn Dusek', -79.164589, 35.820667, 'Hive in a large very old Sweet Gum Tree with hollow cavity from base of ground to about 9 feet that you can see. Cavity in tree suspected to be much larger. Two openings on opposite sides of tree. Strong smell of honey on hot humid day. We do not know how long hive has been here but there are lots of very active bees.', 'Living Tree', 'Concerned Citiz', 'g_dusek@yahoo.com', 'NC', '106 Dorcurt Hills Ro', 'Pittsboro', '27312', 'The tree is dying and will need cut at some point in the next year. We plan to cut top of tree for safety but leave large portion of trunk to protect hive. We have lived here 10 years and are not sure of how long bees have been there. We have always had honey bees around but only noticed hive with in last year. ', '9199323582', 'Yes', 412);
INSERT INTO `honeybee1` VALUES ('2008-06-30 10:22:06', 'Colleen Kendrick', -79.161980, 35.719479, 'Hive is in Sweet Gum located at Circle City Screen Printing 919-542-5512 mgr.''s name is RAy; . Bees were trapped out last year and tree hole boarded up by beekeeper John Strickland; newe hole chewed in by bees this spring. Definately honeybees; told John Strickland 2 weeks ago to see if he was interested in retrapping. Owners do not want to get rid of tree open to sampling.', 'Living Tree', 'Bee Keeper', 'shrijardineuse@hotma', 'NC', '', '', '', '', 'owner''s name is Kevi', '', 413);
INSERT INTO `honeybee1` VALUES ('2009-07-20 22:04:58', 'randy thurman', -79.123878, 37.135139, 'IN A HOLLOW SWEET GUM LOCATED ON A STEEP BLUFF OVERLOOKING SENECA CREEK. VERY LARGE ACTIVE HIVE. AGE ?', 'Living Tree', 'Bee Keeper', 'irekkin@yahoo.com', 'VA', '10 HONE RD ', 'GLADYS', '24554', '', '434-283-1624', 'Yes', 414);
INSERT INTO `honeybee1` VALUES ('2012-06-19 14:51:17', 'Carol Krall', -79.093636, 40.687267, 'In a dead tree about 20 feet off the ground.', 'Dead Tree', 'Concerned Citiz', 'c1234r@hotmail.com', 'PA', '819 Degaetano Road', 'Indiana', '15701', 'Not sure why you want such exact information on how to find the hive---I''d like to see them stick around prefer they be left alone.', '724-840-1979', 'No', 415);
INSERT INTO `honeybee1` VALUES ('2008-07-03 10:48:56', 'Rob Crook', -79.080467, 35.968613, 'In the roots of a tree in the 75 foot buffer of the new Orange County Solid Waste Facility. It is approximately 75 feet to the west of the entrance drive to the new building. It is 50 feet from Eubanks road', 'Living Tree', 'Concerned Citiz', 'crookkohler@bellsout', 'NC', 'Eubanks Road Orange ', 'Chapel Hill', '27517', '', '919-918-7788', '', 416);
INSERT INTO `honeybee1` VALUES ('2008-09-10 08:12:00', 'Doug Shackelford', -79.078926, 35.858013, 'In a crack of an old cedar tree in my yard. Maybe 12 feet high. Has been there for years.', 'Living Tree', 'Concerned Citiz', 'doug_shack@unc.edu', 'NC', '535 Meadow Run Drive', 'Chapel Hill', '27517', '', '9199623197', 'Yes', 417);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Rob Crook', -79.072006, 35.909977, '"Bumble Bees\rUp under a gutter in building.\r8'' off ground\rNear Osmanthus bushes"', 'Manmade structure', 'Concerned Citiz', 'crookkohler@bellsout', 'NC', '', 'Carrboro', '27510', '', '919-918-7788', 'Yes', 418);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'james graves ', -79.060280, 35.479706, '"hive is below the floor of anold pack house \rowner and worker said it has been there 20 years. "', 'Manmade structure', 'Bee Keeper', 'james115@alltel.net', 'NC', 'dalrymple fram rd', 'broadway', '27505', '', '9197709785', 'Yes', 419);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'james graves ', -79.060211, 35.479771, 'hive is below the floor of an old pack house land ower said it has been here for many years ', 'Manmade structure', 'Bee Keeper', 'james115@alltel.net', 'NC', 'dalrymple fram', 'broadway', '27505', '', '9197709785', 'Yes', 420);
INSERT INTO `honeybee1` VALUES ('2008-07-04 11:10:36', 'Margaret Kopp', -79.058281, 35.915485, 'It appears that a smallish colony has made its home in an opening at the very bottom of a tree facing Carr Street. They are active and seem healthy. I have seen activity several times in June while walking my dog. ', 'Living Tree', 'Bee Keeper', 'margaretkopp@gmail.c', 'NC', 'Carr Street and Prit', 'Chapel Hill', '27516', '', '919-619-9190', '', 421);
INSERT INTO `honeybee1` VALUES ('2008-06-29 16:43:51', 'mary voelkel', -79.055222, 35.886547, 'The hive is about 35 feet high up in a hollow tree. It has been there at least 5 years. I am not sure of the size. The tree is located on the edge of our lawn.', 'Living Tree', 'Concerned Citiz', 'maryvoelkel@nc.rr.co', 'NC', '', '', '', '', '', '', 422);
INSERT INTO `honeybee1` VALUES ('2009-05-25 12:18:57', 'Bob R', -79.041138, 35.119629, 'Hive located in tree on 6th fairway of the golf course. Tree is live and grounds staff is aware of and watches the progress of the hive. Ryder Golf Course is a registerd and certified autobon wildlife sanctuary.', 'Living Tree', 'Concerned Citiz', 'bobandsandy@att.ent', 'NC', 'Honeycut Road ', 'Spring Lake', '', 'Discovered hive in tree on 6th fairway of Ryder Golf Course on Fort Bragg while playing golf. ', '910-384-5078', 'No', 423);
INSERT INTO `honeybee1` VALUES ('2011-06-03 07:35:11', 'bridget bobadoye', -79.019302, 35.759575, 'this is a managed hive for the federal college of forestry ibadan it is about 4 feet off the groundit has been there for about 5 years nowthe structure is a kenyan top bar hiveit located behind the ornamental Nursery of the federal college of Forestry', 'Manmade Beehive', 'Bee Keeper', 'aitobridget2000@yaho', 'NC', 'jericho', 'ibadan', '+234', 'they are African honey bees and proper body protection is advised to avoid multiple stings', '+2348054059040', 'Yes', 424);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Debora White', -79.011574, 36.574368, 'People and bees living peacefully together in family home.', 'Manmade structure', 'Bee Keeper', 'deboras.bees@whitebe', 'VA', 'Alton Post Office Ro', 'Alton', '24520', 'Hive has been in home for past 25 years. Only problem is honey coming thru the walls. I hived a swarm most likely from this hive in a tree just east of the main home and about 15ft. up on a limb.(have pictures) The homeowner said the bees had been in the small structure for approx. 5 years although there was no activity in the building that was easily identified.', '919-426-5500', 'Yes', 425);
INSERT INTO `honeybee1` VALUES ('2008-06-24 14:13:25', 'David Tarpy', -78.972000, 35.822319, 'Directly on the left of the path entrance one foot off the ground in a living Sweet Gum tree.', 'Living Tree', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Yes', 426);
INSERT INTO `honeybee1` VALUES ('2008-07-01 21:55:02', 'Larry Henson', -78.958138, 35.754105, 'A large hive . Been here for at least nine years. In a tree trunk. Just on the edge of the game lands at our property.', 'Living Tree', 'Concerned Citiz', 'LarryHenson40@msn.co', 'NC', '816 NC Hwy 751', 'Apex', '27523', '', '', '', 427);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Robert Sears', -78.956268, 35.785271, 'Hive is located in an old potato storage building. One group is in the ceiling and enters at the south gable end. The second group is located on the eastern wall. They have been there ~60 years. The building will fall down soon so we are planning to move to hives by the end of Jun 2009.', 'Manmade structure', 'Concerned Citiz', 'rwsears@bellsouth.ne', 'NC', '338 Lewter Shop Rd.', 'Apex', '27523-5404', '', '919.624.7267', 'Yes', 428);
INSERT INTO `honeybee1` VALUES ('2008-07-01 23:39:10', 'Jeff Applewhite', -78.926529, 36.090187, 'This hive is approximately 2 feet off the ground in a natural split or opening of a double Tulip Poplar tree. The hive is inside the tree and not visible to the eye but many common honey bees come and go and congregate on the outside of the tree.', 'Living Tree', 'Concerned Citiz', 'jeff_app@yahoo.com', 'NC', '25 Ballard Court', 'Durham', '27712', '', '', '', 429);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Chris Benz', -78.917892, 36.106007, 'In the siding of my porch. About 9 feet off the ground. Hive has been there at least three years is very healthy and swarms at least annually. Happy to show interested parties.', 'Manmade structure', 'Concerned Citiz', 'cjbenz@unforgettable', 'NC', '', '', '', '', '', '', 430);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Debora White', -78.910423, 36.405361, 'In soffit at highest point of roofline of log cabin home. At least one year. ', 'Manmade structure', 'Bee Keeper', 'deboras.bees@whitebe', 'NC', 'Hugh Woods Road', 'Roxboro', '27574', 'Home is back off road. Looked at it when it was For Sale by Owner.', '919-426-5500', 'Yes', 431);
INSERT INTO `honeybee1` VALUES ('2008-06-28 17:45:28', 'Samantha Gasson', -78.903809, 36.226551, 'Our feral bee hive is about 30 feet in the air in a sweet gum on our property. It seems to be a large hive that swarmed spring and late summer of 2007 (I have pictures of the first swarm to give an idea of numbers).', 'Living Tree', 'Concerned Citiz', 'gassonstirrup@earthl', 'NC', '', '', '', '', '', '', 432);
INSERT INTO `honeybee1` VALUES ('2009-04-23 08:21:10', 'Ham Morton', -78.898315, 35.986897, '20 foot up in a tree', 'Living Tree', 'Concerned Citiz', '', 'NC', '1201Little Acres', 'Durham', '27713', '', '', 'Yes', 433);
INSERT INTO `honeybee1` VALUES ('2008-07-24 11:26:38', 'Gabrielle Scronce', -78.892822, 35.978004, 'beehive', 'Living Tree', 'Concerned Citiz', 'scronce@gmail.com', 'NC', '190 Carr St', 'Chapel Hill', '27516', '', '919-451-1753', 'Yes', 434);
INSERT INTO `honeybee1` VALUES ('2008-09-10 18:34:14', 'Barrett Richards for', -78.883385, 35.707912, 'Hive in a pine tree about 15 to 20 feet above the ground. Been in tree for about 40 Years.', 'Dead Tree', 'Other', 'richards9199@bellsou', 'NC', '2508 Kelly Road', 'Apex', '27502', 'Need to contact Tony Sears as to exact location. About 200 yards from Kelly Road next to a live steam railroad track.', '919-362-7067', 'Yes', 435);
INSERT INTO `honeybee1` VALUES ('2010-06-03 13:46:38', 'Michael Davis', -78.881470, 35.742916, '2-3 feet high inside a living tree near the greenway and wetlands area. At least 5 years old.', 'Living Tree', 'Concerned Citiz', 'michaelwdavis@nc.rr.', 'NC', '1428 Fairfax Woods D', 'Apex', '27502', 'Typically produces at least 1 swarm in spring. ', '9192496099', 'Yes', 436);
INSERT INTO `honeybee1` VALUES ('2009-04-13 13:46:34', 'Bill Seastrum', -78.880989, 35.742096, 'Half dead treeat base. Can''t miss the flury of bees going to and fro', 'Dead Tree', 'Bee Keeper', '1laurabill@att.net', 'NC', '1428 Fairfax Woods D', 'Apex', '27502', '', '919-800-1912', 'Yes', 437);
INSERT INTO `honeybee1` VALUES ('2010-08-18 16:00:01', 'Geneva Green', -78.873016, 35.985531, 'It is in a Durham Park in a small Oak tree in a 5 branch about 15'' off the ground. This is at Piedmont Wildlife Center. The tree is located in the front yard of the house.', 'Living Tree', 'Bee Keeper', 'gggreen@mindspring.c', 'NC', '364 Leigh Farm Road', 'Durham', '27517', '', '919 475 7668', 'Yes', 438);
INSERT INTO `honeybee1` VALUES ('2008-09-10 12:24:48', 'JDODOM', -78.872032, 36.149220, 'beehive', 'In the ground', 'Concerned Citiz', 'JDODOM3@AOL.COM', 'NC', '6910 BLALOCK RD', 'BAHAMA', '27503', '"FOUND ABOUT 4 WEEKS AGO. \rI HAD FOUND GROUND HIVES WHEN I MOVED TO THE AREA 24 YEARS AGO BUT THEY DISAPPEARED. IN THE LAST YEAR I HAVE SEEN AN INCREASE IN BEES AND JUST FOUND A HIVE.\r"', '919-471-3632', 'Yes', 439);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Steven Voshell', -78.867355, 35.083611, '5-6'' off the ground -unknown how long it has been there but 1 year -3 ~2 holes in a concrete block wall at the abandoned texfi plant in Fayetteville NC. Thousands of bees have been seen entering and exiting the wall. The plant has been abandoned for approx. 9 years. -I have a degree in environmental studies and a minor in biology from Elon University. -I work for an environmental consulting company who has been doing work on the site and noticed the be hive. A coworked had noticed the bee hive last summer and warned me about it. In the next few years the bldg will be demolished and it may be pertinent to remove this behive to save the colony from destruction. ', 'Manmade structure', 'Other', 'steven.voshell@gmail', 'NC', '', '', '', '', '', '', 440);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'marie liebelt', -78.862267, 36.117355, 'One location is in a stone facade.about 10 feet off the ground.It has been here 2+ years.pretty large number of bees.the next colony is in an eave.about 12 feet off the ground it has been here 3+ years.Its a medium size colony', 'Manmade structure', 'Concerned Citiz', 'mliebelt@nc.rr.com', 'NC', '', '', '', '', '', '', 441);
INSERT INTO `honeybee1` VALUES ('2008-06-28 17:11:22', 'KEITH WHITFIELD', -78.856453, 36.016182, '25 FT OFF GROUND IN OAK TREEAT A FRIENDS HOUSE. 1925 WATSON RD. TREE IN BACK YARD. OWNER IS MARK MCCOWAN', 'Living Tree', 'Bee Keeper', 'WHIT4901@YAHOO.COM', 'NC', '', '', '', '', '', '', 442);
INSERT INTO `honeybee1` VALUES ('2008-11-21 18:25:14', 'Larry Williams', -78.855377, 35.580879, 'This is a rescued bee tree that was provided by Nancy Young from Austin TX (originally from Fuquay-Varina. The bee tree was originally located on Ballentine Dairy RD Fuquay-Varina. The tree died and Nancy and her husband paid to have a tree crew disassemble the tree on August 8 2008 and using a crane/truck moved over to our property. The tree originally was probably 60'' tall and the section containing the bees is about 8'' high. It is this section that is on our property. The tree is anchored with stakes and guy wires to keep it stable and from falling over.', 'Dead Tree', 'Bee Keeper', 'lawmsw93@me.com', 'NC', '7105 Starchase LN', 'FUQUAY VARINA', '27526', '', '919-557-6050', 'Yes', 443);
INSERT INTO `honeybee1` VALUES ('2008-06-28 17:30:19', 'KEITH WHITFIELD', -78.845505, 36.207939, 'THIS HIVE WAS CUT DOWN LAST WEEK AT 600 WATTS ST IN DURHAM. I GOT THE WHOLE LOG AT MY HOUSE. I CAPTURED THE BEES AND PUT IN A NEW QUEEN THIS WEEK.', 'Living Tree', 'Bee Keeper', 'WHIT4901@YAHOO.COM', 'NC', '', '', '', '', '', '', 444);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Matt Allen', -78.818230, 35.901340, 'The hive was located in the floor joist of between the first and second floor of a vacant house. The house was being sold to be moved so a local man asked me to remove the hive. The queen survived and the hive is currently living in my backyard. There may be more feral hives in this area.', 'Manmade structure', 'Bee Keeper', 'matt.allen@sunofabee', 'NC', '3440 Page Road', 'Durham', '27560', '', '919-609-4815', 'Yes', 445);
INSERT INTO `honeybee1` VALUES ('2010-04-29 15:43:04', 'M. Elmo Drilling', -78.800407, 42.971470, 'Feral honeybee hive. In branch cavity of silver maple tree in backyard of 255 Ivyhurst Cir along wooden boundary fence. Hive est about 2005. Cavity entrance: 3long2 wide. Ht: 10.5'' Aspect: S60W - excellent for winter sun. At least 2 swarms. ', 'Living Tree', 'Concerned Citiz', 'elmodrill@yahoo.com', 'NY', '255 Ivyhurst Circle', 'Buffalo', '14226-3417', 'Hive is former squirrel den. Foraging activity best if 45oF. But bees active even in winter temps mid30sF if calm sunny; bees feed on sap drips from pruned branches. Foraging bees active all day; pollen sacks full. Bees non-aggressive; no stings yet. Big(?) comb: Honey(?)oozes from cracks between bark. // Have photos of hive. Also video but large 18Mb file. // Plenty of flowers lawns weeds and assoc. trees in area: apple pear crabapple boxelder elm Japanese maple Norway maple silver maple red maple ash aspen locust spruce; and lilac forsythia holly and yew. ', '1-716-834-9957', 'Yes', 446);
INSERT INTO `honeybee1` VALUES ('2008-06-29 11:13:31', 'B McCaig', -78.800117, 36.050194, 'Hive is located in a hole in large Red Oak tree approximately 20-30 ft. high. The hole is not visible from the ground (it apparently points upwards). I just noticed it in Spring 2008 due to numbers of bees flying in and out of tree.', 'Living Tree', 'Concerned Citiz', '3821 E. Geer St. Dur', 'NC', '', '', '', '', '', '', 447);
INSERT INTO `honeybee1` VALUES ('2009-09-26 10:49:35', 'Doug Gravatt', -78.780472, 38.326611, '"TWO COLONIES!!\r#1 Base of dead 20 locust tree 10 feet inside of NE corner of woodlot. Previously a feral colony (3 yrs) did not survive Feb 09. Current colony is swarm arrived Mar/Apr ''09. Entrance is 6 above ground shaded and overgrown. Activity as of Sep 09 is weak.\r#2: Scarlet oak 24alive but dying former squirrel cavity 25'' high open edge of woodlot facing east. Colony is 3rd 2008 (late June) swarm from locust tree #1 above. Cavity is packed with comb. Beginning June 09 colony has ~1000 bees surrounding round entrance hole fanning constantly. Bees remain outside even at night!! Activity as of Sep 09 is strong. Great for observation and photos! 540-249-4063."', 'Living Tree', 'Bee Keeper', 'gravatt06@aol.com', 'VA', '9866 Goods Mill Rd', 'McGaheysville', '22840', '', '540-249-4063', 'Yes', 448);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Sarah Rebar', -78.775322, 39.721809, 'beehive', 'Manmade structure', 'Concerned Citiz', 'sarahebernier@gmail.', 'MD', 'Mason Dixon View', 'Ellerslie', '21529', 'It is inside the second floor house wall of an unheated 1900s era house. According to the occupant the hive has been there as long as she can remember.', '240-522-0922', 'Yes', 449);
INSERT INTO `honeybee1` VALUES ('2008-08-17 20:03:16', 'David', -78.770699, 35.797054, 'The hive is in a curved tree in our backyard. It''s about 30 feet off the ground. It''s been there for at least 3 years. It''s a large colony.', 'Living Tree', 'Concerned Citiz', 'slunecko24@hotmail.c', 'NC', '217 Willoughby Lane', 'Cary', '27513', '', '9194675125', 'Yes', 450);
INSERT INTO `honeybee1` VALUES ('2008-06-28 11:09:05', 'Jill Koethcke Osborn', -78.764084, 35.830029, 'I wish I''d found I hive but I didn''t and I realize bees can travel but at the Umstead Hotel in Cary NC they''ve planted a lot of flowers that are appealing to butterflies and bees. There were honeybees everywhere particularly on some flowering thyme in their herb garden. I asked the hotel if they keep their own hive and they don''t so perhaps this is a wild one. I hope this helps a little!', 'Manmade Beehive', 'Concerned Citiz', 'catherinejill@gmail.', 'NC', '', '', '', '', '', 'Maybe', 451);
INSERT INTO `honeybee1` VALUES ('2008-06-28 13:16:21', 'Nancy Devine', -78.759789, 35.764202, 'I have not located the hive but we have many many honey bees on our cucumbers and Russian sage especially and have for the past couple years. The type of hive is unknown but that is not a choice. I don''t know if this is helpful information or not. At one time there was a beekeeper in our neighborhood (Mr. Turnipseed I believe) but he died several years ago.', 'Living Tree', 'Concerned Citiz', 'ndevine@nc.rr.com', 'NC', '', '', '', '', '', '', 452);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Learn how-to Beeline', -78.749359, 35.867142, 'Look for details on a beelining clinic coming soon!', 'Manmade structure', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'No', 453);
INSERT INTO `honeybee1` VALUES ('2008-06-28 13:21:27', 'Rudy Hines', -78.749283, 35.634750, 'The hive is in a tree and is about 3 feet off the ground. This is the hives 3rd year.', 'Living Tree', 'Concerned Citiz', 'whines1@nc.rr.com', 'NC', '', '', '', '', '', '', 454);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Brian ', -78.742622, 35.762238, '20'' unknown ', 'Manmade structure', 'Concerned Citiz', 'bkroll@ronusproperti', 'NC', 'crossroads blvd.', 'cary', '27518', '', '919.422.4174', 'Yes', 455);
INSERT INTO `honeybee1` VALUES ('2008-06-29 14:12:25', 'Barry Redner', -78.736954, 36.074631, 'The hive is in hole in tree. Second time the hives has returned to this try after leaving.', 'Living Tree', 'Concerned Citiz', 'barry.redner@interme', 'NC', '', '', '', '', '', '', 456);
INSERT INTO `honeybee1` VALUES ('2008-09-10 17:51:33', 'John Wichtrich', -78.720901, 35.522030, 'beehive', 'Living Tree', 'Concerned Citiz', 'jwichtrich@embarqmai', 'NC', '6828 Wimberly Rd.', 'Angier', '27592', 'The hive is in a hollow area at the base of a living tree (on private property). It is next to a pond and has been there at least 10 years...full of bees. There is very little human activity around the tree.', '919.639.5253', 'Yes', 457);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'ken hansford', -78.707985, 35.657192, 'I have 2 colonies living in my house.They enter under the siding and appear to be between the inner and outer wall. One colony has been here for 25 years. The other split from it a year ago.', 'Manmade structure', 'Concerned Citiz', 'khansfor@bellsouth.n', 'NC', '', '', '', '', '', '', 458);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Stephen Davis', -78.699852, 35.685997, 'The hive is under the roof of my house. The entry is in a gap between the roof and chimney where the roofing tar has deteriorated. I haven''t noticed it before this spring. There appears to be a lot of bees. Will they move eventually? Can they be moved without tearing up my roof?', 'Manmade structure', 'Concerned Citiz', 'sfdavis@alum.rpi.edu', 'NC', '', '', '', '', '', '', 459);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Ronnie Bouchon', -78.692795, 35.951496, 'Roseington swarm N. Raleigh. Was found on the side of a garage high on the peak. It was eventually removed by a wake county beekeeper.', 'Manmade structure', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Maybe', 460);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Michael Keen', -78.673309, 35.308578, 'It is in a foundation vent of my fathers home. It has been there over a year.', 'Manmade structure', 'Concerned Citiz', 'mkeen55@embarqmail.c', 'NC', '', '', '', '', '', 'No', 461);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Gordon', -78.672409, 35.905876, 'Located in the eave of our home. Probably 30 feet up. The hive has been present for at least 11 years. ', 'Manmade structure', 'Concerned Citiz', 'drjoe@itbeginswithca', 'NC', '', '', '', '', '', 'No', 462);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bob Edgerton', -78.671371, 35.740311, 'Test: 8 managed hives', 'Manmade structure', 'Bee Keeper', '', 'NC', '', '', '', '', '', 'Yes', 463);
INSERT INTO `honeybee1` VALUES ('2009-09-01 16:18:38', 'Jimmy Chalmers', -78.662292, 36.263020, 'Healthy colony living in a live pin oak tree. The hive is about 18'' off the ground in a hollow.', 'Living Tree', 'Bee Keeper', 'jchalmersnc@gmail.co', 'NC', '4685 Harper Renn Rd', 'Oxford', '27565', 'The tree is about 70yrds from the Tar River. The colony has been in the tree for about three years. The colony created a swarm last fall.', '919.690.0779', 'Yes', 464);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Russ Stephenson', -78.662033, 35.787453, 'Hive is inside the eave return of my house about 18'' above the ground. Hives have come and gone from this location for many decades.', 'Manmade structure', 'Other', 'Russ@RussStephenson.', 'NC', '213 Oberlin Rd', 'Raleigh', '27605-1646', '', '919-828-3699', '', 465);
INSERT INTO `honeybee1` VALUES ('2008-06-28 11:10:28', 'Eric Nordby', -78.652039, 35.749004, 'There is a hive located in the ground where my sidewalk and driveway meet. It''s been there at least 2 months. I have no idea how big the colony is. This is the 3rd colony in three years that I''ve noticed in my yard however they are always in a different part of my yard but always in the ground. I count 15-20 bees per minute leaving the hive.', 'In the ground', 'Concerned Citiz', 'enordby@bellsouth.ne', 'NC', '', '', '', '', '', '', 466);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bryan A.', -78.651604, 35.773056, 'Hive is located under 2nd floor back porch floor of a buddies apartment. It is a huge hive and has been there for way over 5 years. Swarms 2-3 times a year at least.', 'Manmade structure', 'Bee Keeper', 'spamtrash1@earthlink', 'NC', '605 Cutler St.', 'Raleigh', '27603', '', '9198770763', 'Yes', 467);
INSERT INTO `honeybee1` VALUES ('2008-07-07 12:38:10', 'Jan Weems NCMNS', -78.642944, 35.782936, 'This active hive is nestled in an old Black Walnut Tree near the southwest corner of the Old Health Building. The entrance is about 10 feet off the ground and faces east. Look for the walnut tree closest to the building. You can easily see the bees flying from the sidewalk along Jones Street. It has been active for over 5 years and may have origins for the North Carolina Museum of Natural Sciences Discovery Room located three blocks away which maintains an observation hive which swarms from time to time. ', 'Living Tree', 'Bee Keeper', 'jan.weems@ncmail.net', 'NC', '216 West Jones Stree', 'Raleigh', '27601', 'I am the beekeeper and coordinator of the Discovery Room for the Museum of Natural Sciences. This hive seems very vigorous and we noticed it about 5 years ago when it swarmed in a tree hanging over the Jones Street sidewalk. ', '919-7337450 ext. 615', '', 468);
INSERT INTO `honeybee1` VALUES ('2008-06-28 17:50:08', 'Sheila Murrell', -78.638161, 35.955845, 'Ground Level in base of Oak Tree in Back Yard of 6033 Crescent Knoll Drive. We noticed it in the last month...it is probably 1 to 2 months old.', 'Living Tree', 'Concerned Citiz', 'smurrell@mindspring.', 'NC', '', '', '', '', '', '', 469);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dan Mott', -78.637543, 35.822487, 'Located in an old duck house on my property about 12 feet off the ground. Duck house is 15x12x12 cedar boards. Hive has been there since 2004. UPDATE: 3/1/08 Comments : The duck house failed and I could not locate and activity in the hive... just want to keep the data base current. ', 'Manmade structure', 'Concerned Citiz', 'dmott@ncsu.edu', 'NC', '', '', '', '', '', '', 470);
INSERT INTO `honeybee1` VALUES ('2008-06-28 14:23:36', 'Suzanne Carver', -78.637039, 35.913479, 'Hive is 40ft from ground in the trunk of a living oak tree. It has been there at least two years. We cannot tell the size but the bees are always swarming around the hole in the tree. It is visible from our kitchen.', 'Living Tree', 'Concerned Citiz', 'carversf@ix.netcom.c', 'NC', '', '', '', '', '', '', 471);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Rick Bordeaux', -78.636551, 35.784946, 'Colony is in the north wall of the house located on the NW corner of Blount St.& North St. Entrance is approximately 12 ft above the ground.', 'Manmade structure', 'Bee Keeper', 'rickbordeaux@bellsou', 'NC', 'Blount St. & North S', 'Raleigh', '', '', '919-790-9046', 'Yes', 472);
INSERT INTO `honeybee1` VALUES ('2008-09-11 11:41:51', 'Concerned Citizen', -78.631210, 35.691322, 'in the ground', 'In the ground', 'Concerned Citiz', 'MsBobbiW2@Yahoo.com', 'NC', '801 Creech Rd.', 'Garner', '27529', 'I am interested in finding someone who wants to come get the bees. They are under my flower bed that is made over a big old stump. The only thing I wold like is a quart or 2 of honey as I have heard that it is good for allergies to pollins in my area. Please contact me by email if anyone would like to take the bees away. Thanks Bobbi Whitten', '321-258-8411', 'Yes', 473);
INSERT INTO `honeybee1` VALUES ('2008-09-10 09:35:47', 'Amy Axon', -78.624825, 35.843708, 'The honey bees are in a crack of the hickory tree in the far southwest corner of my property. They are about 10'' up in the trunk of the tree. We discovered them in the Spring of 2008 but have no idea how long they have been there.', 'Living Tree', 'Concerned Citiz', '800 Hemingway Dr', 'NC', '800 Hemingway Dr', 'Raleigh', '27609', '', '919-247-7109', 'Yes', 474);
INSERT INTO `honeybee1` VALUES ('2008-06-28 08:24:52', 'Charles E. Wallace', -78.618164, 35.782169, 'Hive is in a beech tree in our yard about 20 feet off ground in a split in the trunk. We''ve lived here 2 1/2 years and neighbors say it has been here for some time. A local beekeeper tried to use a vaccum contraption to get them out but was unsuccessful.', 'Living Tree', 'Concerned Citiz', 'cwallace32@nc.rr.com', 'NC', '', '', '', '', '', 'Yes', 475);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jimmy Chalmers', -78.576859, 36.274796, 'A colony had been in the exterior wall of this house for about four years. Comb was in cavity 9'' high X 16'' wide. There was about 20lbs of honey and four combs of brood. The contractor had destroyed many of the bees before he called me.', 'Manmade structure', 'Bee Keeper', 'jchalmersnc@yahoo.co', 'NC', 'State Rd 1609 and Hw', 'Oxford', '27565', '', '919.690.0779', 'Yes', 476);
INSERT INTO `honeybee1` VALUES ('2008-06-28 07:28:44', 'David Ellis', -78.575935, 35.961056, 'Hive is in a large oak tree in my yard. It has been there at least 4 yrs. It is about 12-14ft off the ground in the forks of the tree.My address is 6200 Rocky Creek way Wake Forest 27587 ', 'Living Tree', 'Concerned Citiz', 'djevet@aol.com', 'NC', '', '', '', '', '', 'Maybe', 477);
INSERT INTO `honeybee1` VALUES ('2012-01-20 15:29:25', 'Rick Bordeaux', -78.552704, 35.832916, 'Honeybees are in a partially dead tree in the front yard of the property on Castlebrook Dr. The entrance is at the base of the tree. Discovered in 2011.', 'Living Tree', 'Bee Keeper', 'rickbordeaux@bellsou', 'NC', '6502 Castlebrook Dr.', 'Raleigh', '27604', '', '919-790-9046', 'Yes', 478);
INSERT INTO `honeybee1` VALUES ('2012-05-09 19:14:01', 'Joe Conti', -78.552330, 35.963428, 'Hanging from a live tree about 5'' off the ground. I just noticed it. It looks big to me and may have honey on it.', 'Manmade Beehive', 'Concerned Citiz', 'conti-19@nc.rr.com', 'NC', '3215 Imperial Oaks D', 'Raleigh', '27614', 'Can some one please take it away. I don''t want it to be destroyed.', '919-376-0706 ', 'Yes', 479);
INSERT INTO `honeybee1` VALUES ('2008-06-28 11:56:40', 'Cecil Shearon', -78.546471, 36.016808, 'Found hive when our home was under construction 3 years ago. Hollow places in tree. Hive has grown in size. Bees cover approx. 3/4 Square Foot on outside of tree. about 6 feet above ground.', 'Living Tree', 'Concerned Citiz', 'candjan@aol.com', 'NC', '', '', '', '', '', '', 480);
INSERT INTO `honeybee1` VALUES ('2008-07-17 22:02:45', 'Bill Thering', -78.532082, 35.558300, 'There are 7 hives at this location that have not been tended for the past 2 years. The owner wants to keep them but has no knowledge of beekeeping. They were her husbands. They look pretty good at this time.', 'Manmade Beehive', 'Bee Keeper', '', 'NC', 'Mc Lemore Rd', 'Smithfield', '', '', '', 'Yes', 481);
INSERT INTO `honeybee1` VALUES ('2008-07-08 22:51:38', 'Leah', -78.531097, 35.464550, '3 feet off ground inside a tree tree is in the edge of woods surrounding my home. Hive has been here at least 4 years', 'Living Tree', 'Concerned Citiz', 'leahkauppi@msn.com', 'NC', '1310 Federal Rd', 'Benson', '27504', '', '919-207-1374', '', 482);
INSERT INTO `honeybee1` VALUES ('2008-07-21 12:59:20', 'Barry Pulley', -78.509163, 35.888371, 'Hive is in my backyard about 12ft off the ground in a hollow tree. Hive has been there for a least 3 yrs.', 'Living Tree', 'Bee Keeper', 'bpulley@nc.rr.com', 'NC', '3200 Forestville Rd.', 'Raleigh', '27616', '', '919-266-2543', 'Yes', 483);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Chip Braswell', -78.503624, 35.566147, 'The hive is at the farm where I live. It was removed from inside the wall of a house in Clayton NC in late May. There were 3 seperate areas of comb and brood in the wall. One queen was located and all the bees were combined in one hive when I moved them to my property. ', 'Manmade structure', 'Bee Keeper', 'barbermillbees@hotma', 'NC', '', '', '', '', '', '', 484);
INSERT INTO `honeybee1` VALUES ('2008-08-08 12:29:50', 'Debbie Delaney', -78.482933, 35.346760, 'Nest is in normal hive body now in the exact spot where the tree it used to reside in was cut down. ', 'Living Tree', 'Other', 'dadelane@ncsu.edu', 'NC', 'Wake Med hospital', 'Fuquay VArina', '', 'Sampled 7/31/08 Old oak tree', '919-995-2596', 'Yes', 485);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Steve Hildebrand', -78.481133, 35.786785, 'This hive is located in the north gable of a brick home on the corner of Smithfield Rd. and Park Ave. in Knightdale. This location is across the street from a hobby beekeeper who has kept bees for 4 years. The occupant of the house has considered having the bees removed because she had honey running down her dining room wall after that hot spell of June 2008.', 'Manmade structure', 'Bee Keeper', 'stevesbeesr2cool@bel', 'NC', '301 N. Smithfield Rd', 'Knightdale', '27545', '', '9192669464', 'Yes', 486);
INSERT INTO `honeybee1` VALUES ('2008-07-20 21:41:27', 'm pyle', -78.478256, 36.072548, '20 foot high17 years.size unknownin huge beech tree at spring house.', 'Living Tree', 'Concerned Citiz', 'mtpyle@aol.com', 'NC', '2402 us 1 hwy', 'franklinton', '27525', '', '', 'Yes', 487);
INSERT INTO `honeybee1` VALUES ('2008-07-20 21:48:58', 'm pyle', -78.473511, 36.067787, '6foot #13 years; 8 foot high #2 5 yearsdeclining number bees seen. wonder if relocating to tree #1.', 'Living Tree', 'Concerned Citiz', 'mtpyle@aol.com', 'NC', '2402 us 1 hwy', 'franklinton', '27525', '', '', 'Yes', 488);
INSERT INTO `honeybee1` VALUES ('2009-03-23 13:47:45', 'M Pyle', -78.473412, 36.067787, 'Update 3-23-09. No activity seen since Dec. Animal has enlarged opening in upper enterance this winter and appears to have taken over. Lower enterance shows no signs of life at this time. Hive in beech at well still active.', 'Living Tree', 'Concerned Citiz', 'mtpyle@aol.com', 'NC', '', '', '27525', '', '', 'Yes', 489);
INSERT INTO `honeybee1` VALUES ('2008-06-28 05:10:25', 'M Pyle', -78.468735, 36.071026, 'About 5 feet off ground. Between railroad and pasture. We moved the fence back so it no longer includes the tree. Discovered when doing repairs to fence after hurricane in 1996. Have been watching it and the activity on the upper opening has almost stopped The one on the lower part of v is still active.', 'Living Tree', 'Concerned Citiz', 'mtpyle@aol.com', 'NC', '', '', '', '', '', 'Yes', 490);
INSERT INTO `honeybee1` VALUES ('2008-08-08 12:33:10', 'Debbie Delaney', -78.464767, 35.372940, 'Found at the base of large Oak tree', 'Living Tree', 'Other', 'dadelane@ncsu.edu', 'NC', '6621 Whitted', 'Fuquay VArina', '', 'Sampled 7/31/08 The tree is at the intersection of Sunset and Whitted. The nest is at the base of a large oak with two big swings on either side of the tree. It has been there for at least five years.', '919-995-2596', 'Yes', 491);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Ed Harris', -78.453369, 36.102375, 'approx. 35 feet off ground in the eaves of the Franklinton Methodist Church in Franklinton. Been there for about 50 years when I was in the first grade.', 'Manmade structure', 'Bee Keeper', 'edwh14@hotmail.com', 'NC', '', '', '', '', '', '', 492);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Chip Braswell', -78.431999, 35.446415, 'At the top of s two story column. Bees have beenpresent in this column for about 25 years. Linwood and Sandra Allen home.', 'Manmade structure', 'Bee Keeper', 'barbermillbees@hotma', 'NC', 'N Church Street', 'Four Oaks', '', '', '919-810-7547', 'Yes', 493);
INSERT INTO `honeybee1` VALUES ('2008-09-12 21:41:14', 'david neville', -78.424187, 35.911575, 'located about 5 feet off the ground in a hollow in the trunk of a living oak standing alone beside a dirt path. Found Oct ''08', 'Living Tree', 'Other', 'dwn20984@gsk.com', 'NC', '3636 Quarry Rd', 'Rolesville', '27587', '', '9195562662', 'Yes', 494);
INSERT INTO `honeybee1` VALUES ('2008-06-29 01:40:17', 'Gil Johnson', -78.408531, 36.057407, 'Hive discovered in hollow live oak tree when cut down.', 'Living Tree', 'Bee Keeper', 'giljohnson@nc.rr.com', 'NC', '', '', '', '', '', '', 495);
INSERT INTO `honeybee1` VALUES ('2008-08-08 12:22:10', 'Debbie Delaney', -78.394257, 35.349098, 'In old tree stump about 5 ft off the ground.', 'Dead Tree', 'Other', 'Dadelane@ncsu.edu', 'NC', '', 'Fuquay Varina', '', 'This nest was removed from downtown Cary and the remainder of the tree was brought to Danny Jaynes house. Sampled 7/31/08', '919-995-2596', 'Yes', 496);
INSERT INTO `honeybee1` VALUES ('2008-08-08 12:25:37', 'Debbie Delaney', -78.378738, 35.380322, 'Nest is located at the very bottom of a large old maple tree. Very gentle bees.', 'Living Tree', 'Other', 'dadelane@ncsu.edu', 'NC', 'Hunter Rd.', 'Raleigh', '', '', '919-995-2596', 'Yes', 497);
INSERT INTO `honeybee1` VALUES ('2009-03-30 17:29:21', 'Steve Hildebrand', -78.375175, 35.890579, 'This hive is in a very old oak with the entrance about 10 feet above Mike and Mari''s deck. These bees have been there since spring 2008.', 'Living Tree', 'Bee Keeper', 'stevesbeesr2cool@bel', 'NC', 'Doyle Rd.', 'Zebulon', '27597', '', '919 266 9464', 'Yes', 498);
INSERT INTO `honeybee1` VALUES ('2008-11-29 23:01:56', 'Neal Daughtry', -78.363647, 34.795841, 'Hive is 15-20 ft off the ground in a 100+ year old oak that is hollow. Bees can be seen swarming in and out of hollows in the tree. The tree is behind my home.', 'Living Tree', 'Concerned Citiz', 'ndaughtry@intrstar.n', 'NC', '3129 Lamb Rd', 'Garland', '28441', '', '910-532-4705', 'Yes', 499);
INSERT INTO `honeybee1` VALUES ('2009-02-24 09:30:04', 'John ', -78.346725, 35.399055, 'beehive', 'Living Tree', 'Concerned Citiz', '', 'NC', '', '', '', '', '', 'Yes', 500);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Lampe', -78.346596, 35.399124, 'Found in barn wall in 2oo7. Moved to hive box about 300 ft away from orginal location. Been using Bees for fun/hobbist. Have given no pest treatments of any type. They are untouched except for modern hive box', 'Manmade structure', 'Concerned Citiz', 'jhlampe2@hotmail.com', 'NC', 'Box 4230', 'Four Oaks', '27524', 'I digitally filmed bees when moving .If you want to see contact me. It''s on my facebook page', '919-938-4888', 'Yes', 501);
INSERT INTO `honeybee1` VALUES ('2010-07-23 13:33:15', 'Bee Keeper', -78.346252, 38.023212, 'Locally captured swarm of feral bees set up in beehive', 'Manmade Beehive', 'Bee Keeper', '', 'VA', 'Bunker Hill Lane', 'Keswick', '22947', '', '', 'No', 502);
INSERT INTO `honeybee1` VALUES ('2011-11-06 11:00:31', 'jim wilson', -78.332520, 35.460670, '25ft up in my house. Its been there fof over 16 yrs', 'Living Tree', 'Bee Keeper', 'theartifactor@aol.co', 'NC', '331wwilsonst', 'smithfield', '27577', '"I have removed several hives from trees\rhouses swarms and have over 30 hives in langstrom equipment. I also have 2\rcut bee trees on pallets and know of a \rfew more bee trees "', '9199156721', 'Yes', 503);
INSERT INTO `honeybee1` VALUES ('2009-07-11 19:07:45', 'Casey Snook', -78.314987, 35.830376, 'This is a hive that was in a tree that fell through my house on Jan. 7th 2009... Hive is in a log about 6 feet long and about a foot in diameter... ', 'Dead Tree', 'Other', 'casey@inthegrits.com', 'NC', '900 N. Lee St', 'Zebulon', '27597', 'I was aware of them in the tree before it fell and had grown concerned about how some of the bees were acting... The tree fell and as part of the clean up the section of branch was cut out and left in my backyard... Since then the log has continued to lay in my backyard and the bees have really come into their own... The sick bees seem to have died off and the remaining bees are very active and allow me to get very close to them while taking pictures. ', '919-219-3957', 'Yes', 504);
INSERT INTO `honeybee1` VALUES ('2012-05-13 23:28:38', 'Will White', -78.218369, 34.359947, 'In a large oak 7 feet off the ground.', 'Living Tree', 'Bee Keeper', 'wdw12741@yahoo.com', 'NC', 'Riegel Course Road', 'Riegelwood', '28456', '', '910-655-3288', 'Yes', 505);
INSERT INTO `honeybee1` VALUES ('2008-06-29 20:41:52', 'Steve Sherwood', -78.187225, 36.003609, '8 feet up in a cedar tree. age unknown.', 'Living Tree', 'Bee Keeper', 'mullismillworks@bell', 'NC', '', '', '', '', '', '', 506);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jimmy Chalmers', -78.161652, 36.164948, 'The hives are 18-20ft above ground in the soffit/ceilings of the building. To date there are four small colonies and one large colony. The color of the comb indicates many years of use and reuse by feral swarms. The colonies are being removed and relocated. According to members of the church bees have been coming and going for 25+ years.', 'Manmade structure', 'Bee Keeper', 'jchalmersnc@yahoo.co', 'NC', '4160 NC 561 Hwy', 'Louisburg', '27549', 'By the amount of deadout debris we have found in the cavities many hives have come and gone through the years.', '919.690.0779', 'Yes', 507);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'C. Jody Britt', -78.134766, 35.227673, 'The hive is located in between the walls of old hog house. 8-10 years', 'Manmade structure', 'Concerned Citiz', 'cjodybritt@aol.com', 'NC', '919-222-7826', '', '', '', '', 'Yes', 508);
INSERT INTO `honeybee1` VALUES ('2009-05-27 16:51:57', 'Bob Kemper', -78.102356, 35.421745, 'Tree in back yard of home near the garden height off ground-8 feet three foot gap opening in side of tree age of colony- unknown size estimate- small. Homeowner said that a swarm was removed from a bench near the tree this spring.', 'Living Tree', 'Bee Keeper', '4kemper@bellsouth.ne', 'NC', '506 Parkwood Lane.', 'Goldsboro', '27530', '"078 05.736'' W 35 24.761'' N\r"', '919-731-2146', 'Yes', 509);
INSERT INTO `honeybee1` VALUES ('2008-06-30 13:43:46', 'James Hays', -78.101639, 36.642166, 'appro. 3'' off the ground in a living tree. The tree has a ''split'' going up the trunk ~ 3'' long. No idea how long it''s been there. To find please contact me.', 'Living Tree', 'Concerned Citiz', 'jhays@encolabs.com', 'VA', '', '', '', '', '', '', 510);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bob Crenshaw', -78.099876, 35.408703, '4 feet off ground in the top of a stone column at the driveway entrance on the SW corner of the front yard. The hive is 18 months old started about april 2007.', 'Manmade structure', 'Concerned Citiz', 'twc9197781684@earthl', 'NC', '115 Susan Circle', 'Goldsboro', '27530', '', '919-734-8590', 'Yes', 511);
INSERT INTO `honeybee1` VALUES ('2009-05-27 16:45:04', 'Bob Kemper', -78.099419, 35.401543, 'Oak tree near ditch height off ground-15 feet top opening of two openings on side of tree facing a field Age of colony- unknown Size estimate- small. The inactive lower hole of the two holes has staining.', 'Living Tree', 'Bee Keeper', '4kemper@bellsouth.ne', 'NC', '412 Hwy. 581 S.', 'Goldsboro', '27530', '"078 03.864'' W 35 24.908'' N\r"', '919-731-2146', 'Yes', 512);
INSERT INTO `honeybee1` VALUES ('2010-04-05 20:30:02', 'harold langley', -78.080177, 35.580685, 'in an old milk del truck', 'Living Tree', 'Concerned Citiz', '', 'NC', '400langleydanielrd', 'kenly', '27542', '', '9192844866', 'Yes', 513);
INSERT INTO `honeybee1` VALUES ('2008-07-13 16:59:38', 'Bill Thering', -78.079811, 35.196705, 'This Colony is living in the large oak tree in the back yard. It is about 26 feet above the ground and has been there about two years. ', 'Living Tree', 'Bee Keeper', '', 'NC', 'Smith Chapel Road', 'Mt. Olive', '', '', '', 'Yes', 514);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Dan Murray', -78.001183, 34.941288, 'There are two hives located inside the north wall of an old farm house on private property behind a locked gate. Approx. 6 to 10 ft. above ground. Access must be obtained from Murray Agriculture LLC by contacting either Dan Murray at (919) 880-5885 or Bill Murray at (434) 977-7046. These hives have been at this location for at least 20 or 30 years.', 'Manmade structure', 'Concerned Citiz', 'danmurray07@yahoo.co', 'NC', 'SR 1900 Lanefield Rd', 'Kenansville', '28349', '', '(919) 880-5885', '', 515);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.994408, 35.382015, 'This colony is in the eave of the county courthouse and has been for several years.', 'Manmade structure', 'Bee Keeper', '', 'NC', 'East Walnut Street', 'Goldsboro', '27530', '', '', 'Yes', 516);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.947716, 35.576447, 'There is a colony in the North East corner of this house. The house has not been used in 20 years but the grass is kept up by the owner. He claims that the bees have been in the wall by the chimney about 5''above the ground for the last dozen years or so.', 'Manmade structure', 'Bee Keeper', '', 'NC', 'Old Black Creek Rd.', 'Fremont', '', '', '', 'Yes', 517);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.927162, 35.468899, 'There is a colony of bees in the south east side of the abandoned house. The farmer that tends the land found them last summer (2008) No idea on how long they have been there.', 'Manmade structure', 'Bee Keeper', '', 'NC', '200 Lancaster Road', 'Pikeville', '27863', '', '', 'Yes', 518);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.916046, 35.320473, 'These bees are in a cinder block auto center wall about 14 feet above the ground floor. They ahve been there about 10 years according to the owner.', 'Manmade structure', 'Bee Keeper', '', 'NC', 'Dollard town Road', 'Elroy', '27530', '', '', 'Yes', 519);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Don Beaver', -77.912125, 36.430813, 'Hive is at least 4 years old located in a old man made structure', 'Manmade structure', 'Concerned Citiz', 'dbeaver@schoollink.n', 'NC', ' Mosby Ave', 'Littleton', '27850', '', '252-586-2014', 'Yes', 520);
INSERT INTO `honeybee1` VALUES ('2012-06-08 16:01:05', 'jesse bowles', -77.898560, 34.043556, 'beehive', 'Living Tree', 'Concerned Citiz', '', 'NC', 'sedgley drive', 'wilmington ', '28412', 'WE Saved THe hive!!!!', '', 'Yes', 521);
INSERT INTO `honeybee1` VALUES ('2009-08-11 16:36:52', 'Stephanie Avery', -77.887230, 34.195122, 'This honey bee tree is located in the YWCA Outback property inside a large Quercus nigra (water oak). The opening is at ground level. This hive has been active for at least 2 years.', 'Living Tree', 'Concerned Citiz', 'specpro@ywca-lowerca', 'NC', '2815 South College R', 'Wilmington', '28412', 'This hive is located in an area that has been recently ''developed'' and used as an environmental education site for the YWCA. ', '9107996820', 'Yes', 522);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.887177, 35.539909, 'This colony is living in the transmission of a old yellow backhoe. The owner reports having seen the bees for about three years possibly longer.', 'Manmade structure', 'Bee Keeper', '', 'NC', 'NC 222 East', 'Eureka', '', '', '', 'Yes', 523);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jimmy Watson', -77.885170, 36.338360, 'old church bldg- years', 'Manmade structure', 'Bee Keeper', 'jimmywatson50@yahoo.', 'NC', '', '', '', '', '', '', 524);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'jesse bowles', -77.882080, 34.052658, 'The hive is in a water meter box in the ground and is fulll of honey!', 'Manmade structure', 'Concerned Citiz', 'capehomeassoc@bellso', 'NC', ' sedgely drive', 'wilmington nc', '28412', 'The hive is in an active water meter box and will have to be destroyed if it is not moved', '910-395-0081', 'Yes', 525);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.872612, 35.308651, 'Colony is in the back left corner of the residence about 8 feet above the ground behind the fascia board. Owner says that they have been there about three years and there was another colony in the peak of this house in previous years.', 'Manmade structure', 'Bee Keeper', 'x8x8p2gb@coastalnet.', 'NC', '607 Lake Shore Drive', 'Walnut Creek', '27534', '', '919-735-1983', 'Yes', 526);
INSERT INTO `honeybee1` VALUES ('2009-08-11 04:05:09', 'Carie Hett', -77.871307, 34.223335, 'This honey bee hive is inside the trunk of a large tree. The opening is at ground level. The hive has been active for at least 3 years. This bee tree is located beside the trail inside the Bluethenthal Wildflower Preserve on the campus of UNCW.', 'Living Tree', 'Other', 'cjh1643@uncw.edu', 'NC', 'Bluethenthal Wildflo', 'Wilmington', '28403', 'You may view a video of this hive on my facebook wall: Carie Hett', '19107913767', 'Yes', 527);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Hamilton', -77.871094, 38.132397, 'Hive is located in wall of a structure. Said to have been present for 10 years. Will be doing extraction in spring 2010.', 'Manmade structure', 'Bee Keeper', 'johnrhamilton@hughes', 'VA', 'Lake Anna', 'Fredericksburg', '22407', 'Pastor of church were hive is located agrees to wait until spring to do extraction. It is located next to electrical panel and they want to do some rewiring so colony needs to be removed.', '540-898-4398', 'Yes', 528);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Bill Thering', -77.864014, 35.547905, 'Colony is inside an old bulldozer on the ground in a junkyard. They were first seen in March of 2007 but this is a large old yard and could easily have been there for years.', 'Manmade structure', 'Bee Keeper', '', 'NC', '222 East ', 'Eureka', '', '', '', 'Yes', 529);
INSERT INTO `honeybee1` VALUES ('2009-08-11 04:14:36', 'Carie Hett', -77.836502, 34.210419, 'This honey bee hive is located inside a large branch of a large tree in the New Hanover County Arboretum/Cooperative Extension Center. Not sure how long it has been there but it is active and producing honey. Enter the Arboretum by the main front gate. Turn right through the rose garden pass through the Ability Garden turn right up the trail toward the Vegetable Garden. Look for a large deck to the left of the path. Look for a puddle of honey that has dripped from the hive. Look above your head to find the hive inside the branch of the large tree. ', 'Living Tree', 'Other', 'cjh1643@uncw.edu', 'NC', '6206 Oleander Dr.', 'Wilmington', '28403', '', '9107913767', 'Yes', 530);
INSERT INTO `honeybee1` VALUES ('2008-09-21 10:55:04', 'Nancy Farmer', -77.803413, 34.512943, 'In hole in oak tree about 10'' feet above ground on private land in deer hunting woods. Don''t know how long its been there newly made road beside it. .', 'Living Tree', 'Bee Keeper', 'ppbnfarm@yahoo.com', 'NC', 'Shaw Highway', 'Rocky Point', '28457', 'Bees larger than my bees at home', '910 686-9387', 'Yes', 531);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'david batts', -77.755310, 35.767548, 'there are 3 hives on all.2 of the hives are located in a old white house. those bee hives were in that house when my grandfather and father both lived in the house.so that hive has been there for close to 100 yrs. the other hive is in a tree 30ft. away.', 'Manmade structure', 'Bee Keeper', 'dbatts508@nc.rr.com', 'NC', '7315a batts rd.', 'wilson', '27852', '', '252-291-5007', 'Yes', 532);
INSERT INTO `honeybee1` VALUES ('2008-10-28 08:24:47', 'Jonathan Duffy', -77.752151, 38.864140, 'Third year we have been aware of this hive five feet off the ground inside a hollow tree. Second feral hive found on the farm. We moved one out of a barn wall into a hive this spring. It is doing well so far (2008)and will see if the girls make it through the winter.', 'Living Tree', 'Bee Keeper', 'jrd.kinloch@verizon.', 'VA', 'P.O. Box 406', 'The Plains', '20198', '', '5402535236', 'Yes', 533);
INSERT INTO `honeybee1` VALUES ('2008-09-10 14:03:42', 'Bob Gaddis', -77.677322, 35.300961, 'In Detas Fields Subdivision. Located in hollow oak tree on cul-de-sac. 3'' off ground. Trapping attempt unsuccessful. Bees absconded.', 'Living Tree', 'Bee Keeper', 'bee.gee@embarqmail.c', 'NC', 'Brer Rabbit Pl', 'grifton', '28530', '', '252-527-3760', 'Yes', 534);
INSERT INTO `honeybee1` VALUES ('2011-07-25 18:42:48', 'Robert Andrus', -77.636536, 37.483635, 'Located in a large oak tree approximately 12 feet above the ground in a hole on the back side of the tree towards the woods and is approximately 2 to 2 1/2 inches in diameter. It started near the end of May or the beginning of June it appears to have several hundred bees. ', 'Living Tree', 'Concerned Citiz', 'rwandrus65@hotmail.c', 'VA', '12902 Watch Point Ea', 'Midlothian', '23114-3061', '', '804 349-7792', 'Yes', 535);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Scott Kiser', -77.604759, 35.779804, 'Hive is locaed in an abondoned farm house. It is 10 ft off the ground in the rear wall of the house. Known to have been present for 3 years. House is located on Hwy 258 abput 100 yards from intersection with Hwy 42.', 'Manmade structure', 'Bee Keeper', 'gameonmgmt@aol.com', 'NC', '', 'Pinetops', '27864', '', '252-5314-3149', 'Yes', 536);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jack Anglin', -77.580711, 35.272671, 'NOT LOOKING TO HAVE THE BEES REMOVED!!   We live in a large two story mansion that was built in 1904 with six white 25 foot west facing columns and we have two hives -the oldest active for 40 years or so is in the top of the north column a second newer hive is in the top of the third column from the north. The north column hive died out last fall and has been slow to recover or find new bees but seems to now (5/25/2011) be going gangbusters as usual. The bees are not aggressive. An old pest control man in town reported to me that he had seen them there 30 years ago (said that in 2001). We rent the home so I have no authority to remove or repair damage from a removal project. We are happy to share the building and the homeowners aren''t anxious about it either. Our yard always has one of the first blooming azaleas in town. http://digital.lib.ecu.edu/192', 'Manmade structure', 'Other', 'zeefineartist@gmail.', 'NC', '1201 North Queen Str', 'Kinston', '28501', '', '252 361-5905', 'Yes', 537);
INSERT INTO `honeybee1` VALUES ('2008-06-29 01:28:33', 'Gil Johnson', -77.557915, 34.937359, 'Hive in live tree in cemetery.', 'Living Tree', 'Bee Keeper', 'giljohnson@nc.rr.com', 'NC', '', '', '', '', '', '', 538);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Gil Johnson', -77.555344, 34.942158, 'Hive in wall of abandoned house.', 'Manmade structure', 'Bee Keeper', 'giljohnson@nc.rr.com', 'NC', '', '', '', '', '', '', 539);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John Newton', -77.544907, 35.904747, 'This wild colony is located in the residence on the second floor near the window. It is reported to have been there 10 years. ', 'Manmade structure', 'Concerned Citiz', 'art_bradley@ncsu.edu', 'NC', '500 W. Walnut Street', 'Tarboro', '27886', 'Contact extension agent Art Bradley at the e-mail address for more information. The home is at the intersection of W. Walnut Street and Poplar Street and the hive is on the Poplar Street side of the residence.', '', '', 540);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joel Bourne', -77.535751, 35.898731, 'This colony is between the walls of the Colonial Theater and the Constantine building. Accessible from the roof of the Constantine building. This colony is reported to have been present for 7-8 years.', 'Manmade structure', 'Concerned Citiz', 'art_bradley@ncsu.edu', 'NC', '514 Main Street', 'Tarboro', '27886', 'Contact extension agent Art Bradley at the e-mail address for more information.', '', '', 541);
INSERT INTO `honeybee1` VALUES ('2008-06-28 21:52:15', 'Jimmy Watson', -77.531548, 36.393307, 'approx 7-8ft off ground in old cedar tree-at least 2 years', 'Living Tree', 'Bee Keeper', 'jimmywatson50@yahoo.', 'NC', '', '', '', '', '', '', 542);
INSERT INTO `honeybee1` VALUES ('2008-09-10 13:58:09', 'Bob Gaddis', -77.527313, 35.317139, 'Colony is hollow gum tree blown over in tropical storm 09/05/08 absconded 09/06/08', 'Living Tree', 'Bee Keeper', 'bee.gee@embarqmail.c', 'NC', 'Tilghman Mil Rdl', 'grifton', '28530', '', '252-527-3760', 'Yes', 543);
INSERT INTO `honeybee1` VALUES ('2008-09-10 14:00:42', 'Bob Gaddis', -77.492455, 35.326050, 'Colony formerly in small hollow gum tree about 5'' off ground near small ditch. Bees died or absconded sometime around 2004', 'Living Tree', 'Bee Keeper', 'bee.gee@embarqmail.c', 'NC', '3936 NC Hwy 11', 'grifton', '28530', '', '252-527-3760', 'Yes', 544);
INSERT INTO `honeybee1` VALUES ('2009-09-27 10:40:48', 'David Wright', -77.482452, 38.741062, 'Old termite/ant destroyed tree. Hollowed out. Height of tree was about 9 feet. Hole in side of tree (3incharound) is entrance. Tree/bees has since been cut and moved to my local apiary (four miles away)', 'Dead Tree', 'Bee Keeper', 'novabeeguy@gmail.com', 'VA', '8002 Hillcrest Drive', 'Manassas', '20111', 'I was asked by the homeowners association to remove this colony of bees. Due to the time of year and several other factors I decided that the best course of action was to cut the top of the tree off place wire mesh over it to contain the bees cut the bottom of the tree wire it shut wrap the entrace area to again contain the bees and move the entire tree whole to my apiary. This is where it is located at this time and next spring I will remove the colony and dispose of the log.', '703-587-8323', 'Yes', 545);
INSERT INTO `honeybee1` VALUES ('2010-07-05 21:41:35', 'Susan', -77.466614, 37.522388, '15-20 feet off the ground in the hole of a tree in our backyard close to our shed. Noticed it yesterday for the first time. ', 'Living Tree', 'Concerned Citiz', 'twinswim@hotmail.com', 'VA', '2904 riverside dr', 'richmond', '23225', '', '8042300561', 'Yes', 546);
INSERT INTO `honeybee1` VALUES ('2008-10-22 16:24:48', 'David Stover', -77.455505, 37.537090, '20 ft. off ground in large living tree. Swarmed from an existing hobbyist hive. Followed into cemetery where we saw the bees go into the tree. It was established in May of 2008. Last time I looked at it was August of 2008 and is still there. ', 'Living Tree', 'Bee Keeper', 'david@davidstover.co', 'VA', '', 'Richmond', '23219', '', '804-782-0988', 'Yes', 547);
INSERT INTO `honeybee1` VALUES ('2010-04-22 13:53:44', 'David Wright', -77.445915, 38.722855, 'Old tree leaning up against large live pine tree', 'Dead Tree', 'Bee Keeper', 'novabeeguy@gmail.com', 'VA', 'Lake Jackson Drive', 'Manassas', '20111', 'Old log that I cut last fall and moved to the very back of my property. I will be removing the bees to relocate them soon into a Langstroth hive for management.', '703-587-8323', 'Yes', 548);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Keltsie Kellum', -77.432587, 34.781101, 'Height of entrance is about 10 ft off ground in an exterior wall of my home I just moved in late last summer neighbors tell me the hive has been around quite some time despite previous owners attempts to be rid of them. ', 'Manmade structure', 'Concerned Citiz', 'rkellum@ec.rr.com', 'NC', '100 Ramona Ave', 'Jacksonville', '28540', 'The hive reportedly was located in the attic of home previous owner sprayed them they swarmed to neighbors yard only to return to an exterior wall. Home is landscaped with multiple flowering bushes plants muscadine grapes as well as mature peach pear and apple trees.', '9109890581', 'Yes', 549);
INSERT INTO `honeybee1` VALUES ('2008-07-18 20:27:38', 'Peter Lamb', -77.432526, 36.413490, 'This hive is only a foot or two off the ground. I don''t know how long it has been there but I have know about it for at least 3 years. The size is hard to judge but there always some bees around the opening. This hive is in a mostly blown over tree beside the road.', 'Living Tree', 'Bee Keeper', 'plamb914@gmail.com', 'NC', '305', 'Jackson', '', '', '9104700836', 'Yes', 550);
INSERT INTO `honeybee1` VALUES ('2008-09-10 13:55:00', 'Bob Gaddis', -77.399727, 35.393528, 'Colony in the base of 100-year-old oak tree south side of house', 'Living Tree', 'Bee Keeper', 'bee.gee@embarqmail.c', 'NC', 'Marvin Taylor Rd', 'grifton', '28530', '', '252-527-3760', 'Yes', 551);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Al Overby', -77.337646, 36.513775, 'North East corner 2nd floor of the house', 'Manmade structure', 'Concerned Citiz', 'al1over@embarqmail.c', 'NC', '232 Mt Carmel Rd', 'Margarettsville ', '27853', '', '919 603 0966', 'Yes', 552);
INSERT INTO `honeybee1` VALUES ('2008-09-19 12:04:49', 'North and Andrews', -77.258308, 42.919193, '7'' off the ground in the trunk of a catalpa tree. There have been bees in this tree every summer for the 6 years I''ve lived here. The current colony came in the spring of ''06 and is entering it''s third winter. There is also another colony in the tree next to this one but they have not survied any winters.  This is on private property. No tresspassing please.', 'Living Tree', 'Bee Keeper', 'phendershot@frontier', 'NY', 'North and Andrews', 'Canandaigua', '14424', '', '', 'Yes', 553);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Denise Shreeve', -77.215431, 38.958607, 'Colony nesting in exterior wall of home a few feet off ground; homeowner just noticed it this year so it must be relatively new; Master beekeeper advised homeowners to leave colony alone to see if it survives over the winter. If so he will remove it in the spring.', 'Manmade structure', 'Concerned Citiz', 'dbshreeve@gmail.com', 'VA', ' Centrillion Drive', 'McLean', '22102', '', '703.893.2247', 'Yes', 554);
INSERT INTO `honeybee1` VALUES ('2008-12-26 19:01:45', 'Mike Krempasky', -77.118576, 40.177364, 'The hiveis in an old blacj cherry tree and is about breast height in a tree which is appx 14-18 inches in diameter. Hive has been there at least two years.', 'Living Tree', 'Concerned Citiz', 'mknal@comcast.net', 'PA', 'PA Rte 74 Southeast ', 'Carlisle', '17013', 'Hive is along the appalachian trail a short (about ten minute walk) from the intersection of the Appalachian Trail and PA Rte 74 at a point southeast of Carlisle. From the parking area walk north along the trail thru a wooded area across a horse pasture and then into a woods. Continue walking through woods til the trail nears a fence line of a dairy farm on the left. About midway along the fence row there is a small trail relocation at a blowdown of several trees. The base of the largest downed tree is near the black cherry with the hive. My wife is a beekeeper. I''m willing to help a researcher find the hive.', '7175743229', 'Yes', 555);
INSERT INTO `honeybee1` VALUES ('2009-03-24 19:01:41', 'Betty Rovins', -77.045235, 35.052063, 'What I think are bees are flying in and out of a cavity in the main trunk of an old Spanish Red Oak (Quercus falcata)The cavity is between 30 and 35 feet off the ground. The cavity is old and the bees could have been there unnoticed for years as it can only be seen from one area in the yard. Two years ago there was a swarm collected by bee keepers in the same yard. Bees are often seen in the garden', 'Living Tree', 'Concerned Citiz', 'bbmj@embarqmail.com', 'NC', '119 Lugano Road', 'New Bern', '28562', '', '252 634 9757', 'Yes', 556);
INSERT INTO `honeybee1` VALUES ('2011-08-23 21:53:36', 'Charlie Brandts', -77.037659, 38.899117, '"Hive is in a big live cypress tree located in the SW corner of Lafayette Park. The entrance is about 15ft off the ground and faces north.\rIt appears to have a strong population judging by flight activity at the entrance."', 'Living Tree', 'Bee Keeper', 'cmfbrand@yahoo.com', 'DC', '1600 Penn. Ave', 'it''s in Washington D', '20500', '', '202-497-7842', 'Yes', 557);
INSERT INTO `honeybee1` VALUES ('2008-10-28 01:35:57', 'Art Halstead', -76.875282, 37.171124, 'Abandoned standard double deep at least 5yr...in headrow weeds and vines. surviving with out top. Found Oct 2008 very heavy with stores.', 'Manmade Beehive', 'Bee Keeper', 'artthebeekpr@yahoo.c', 'VA', '6477 Beaver Dam Rd', 'Surry', '23881', '', '757-488-7617', 'Yes', 558);
INSERT INTO `honeybee1` VALUES ('2008-06-28 03:51:49', 'Gayle Smy', -76.763161, 34.723854, 'Inside the branch of a Live Oak tree. Had a swarm arrive in April 2007. This seemed to slowly disappear in the early spring of 2008 then in April 2008 had another swarm arrive. The tree is in my front yard; the branch is about 10'' above the ground. The swarm may have split again recently as there seem to be fewer bees as of about mid-June. There are always bees outside the hive--could it be getting full and too crowded?', 'Living Tree', 'Concerned Citiz', 'gsmy@ec.rr.com', 'NC', '', '', '', '', '', 'Maybe', 559);
INSERT INTO `honeybee1` VALUES ('2008-10-11 19:57:54', 'Jeremy Barnes', -76.737099, 39.861790, '4'' off the ground in a black walnut tree behind the large white barn. Been there for at least two years.', 'Living Tree', 'Bee Keeper', 'babathemba@mac.com', 'PA', '1722 Union Church Rd', 'York', '17360', '', '717 428 1144', 'Yes', 560);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Sara Silver', -76.635559, 39.423637, 'Approx. 10 feet off the ground wooden structure.', 'Manmade structure', 'Concerned Citiz', 'mar_tini78@yahoo.com', 'MD', '627 W Seminary Ave', 'Lutherville ', '21093', 'Bees are actually located in the open space between our sloped front porch roof and ceiling.', '443-695-6147', 'Yes', 561);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Jonathan Hollands', -76.634918, 39.341198, 'The hive entrance is located within the wall of the historic Roland Park Water Tower. The entrance is approx. 20 feet off the ground on the north east facing side (building is octagonal) of the building. ', 'Manmade structure', 'Concerned Citiz', 'sjbackstrom@cavtel.n', 'MD', '4210 Roland Ave', 'Baltimore', '21210', '', '443-763-6480', 'Yes', 562);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Andrew Marani', -76.629517, 39.350494, 'In the north wall of a house about 15 feet above the ground. Been there at least since summer of 2009.', 'Manmade structure', 'Bee Keeper', 'andrewmarani@armaran', 'MD', '4721 East Lane', 'Baltimore', '21210', '', '410-977-2022', 'Yes', 563);
INSERT INTO `honeybee1` VALUES ('2008-11-01 22:47:56', 'Andrew Marani', -76.629013, 39.350319, '25'' above ground in a 24 diam. living tree entrance is a split in the trunk. ', 'Living Tree', 'Bee Keeper', 'andrewmarani@armaran', 'MD', 'Wilmslow Road', 'Baltimore', '21210', 'Tree is located in a public park just west of the trail. I found it today by back tracking bees drinking in the stream. Don''t know how long it has been there. Temperature around 70 degrees bees very active.', '', 'Yes', 564);
INSERT INTO `honeybee1` VALUES ('2010-03-17 17:23:04', 'Tom Loughran', -76.623848, 36.960968, 'This hive is located on the 10th Hole at Cypress Creek Golf Course in SmithfieldVirginia. The hive is in a tree about 10 feet to the right of the cartpath about 125 yds. from the green. The hive access is about 3 feet off the ground. There are a limited number of trees in the area of the hive and isn''t hard to find. If one follows the cartpath from the teeing area you will for about 150 yds go through an open area. The golf hole makes a small turn to the right and there are trees lining the right hand side of the hole. From the first trees that one encounters on the cartpath the bee tree is at most 20 trees from the beginning of the stand of trees.', 'Living Tree', 'Bee Keeper', 'tloughran@cox.net', 'VA', '10 Lockerbie Rd.', 'Smithfield', '', '', '7578791826', 'Yes', 565);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Elizabeth Cummings', -76.604919, 35.180542, 'hive is very large and has been there a long time - years?? hive is located in a house outer wall. ', 'Manmade structure', 'Concerned Citiz', 'bakerb721@yahoo.com', 'NC', '427 pennsylvania ave', 'vandemere', '', 'We had an experienced bee keeper come and take a look at it and he said it was the largest hive he had ever seen. He estimated that he had gotten some 40 thousand bees from the hive and there was a lot more. we don''t know what to do with these bees don''t want to exterminant but how do we get rid of them??', '252-626-3405', 'Yes', 566);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Elizabeth Cummings', -76.604919, 35.180542, 'hive is very large and has been there a long time - years?? hive is located in a house outer wall. ', 'Manmade structure', 'Concerned Citiz', 'bakerb721@yahoo.com', 'NC', '427 pennsylvania ave', 'vandemere', '', 'We had an experienced bee keeper come and take a look at it and he said it was the largest hive he had ever seen. He estimated that he had gotten some 40 thousand bees from the hive and there was a lot more. we don''t know what to do with these bees don''t want to exterminant but how do we get rid of them??', '252-626-3405', 'Yes', 567);
INSERT INTO `honeybee1` VALUES ('2010-02-15 14:04:38', 'Russ Lewis', -76.571487, 34.727222, 'IT''S BEEN IN THE TREE FOR A FEW YEARS', 'Living Tree', 'Bee Keeper', 'russlewis6@live.com', 'NC', 'Harkers Island Road', 'Straits', '28531', '', '252-808-5277', 'Yes', 568);
INSERT INTO `honeybee1` VALUES ('2010-11-22 08:58:09', 'Tia Douglass', -76.557983, 34.775700, '5'' off ground in tree. It''s been there for at least two years and the opening faces Otway Hardware. Everyone knows it''s there and are pleased to have it! If you can''t find it ask anyone at Otway Hardware; they''ll help you.', 'Living Tree', 'Bee Keeper', 'tdouglass@ec.rr.com', 'NC', '589 Hwy 70 E', 'Otway', '28516', '', '252-729-5491', 'Yes', 569);
INSERT INTO `honeybee1` VALUES ('2010-09-15 07:07:06', 'Jeremy Ketchum', -76.521286, 43.427490, 'Hive is at ground level in a maple tree previously occupied by carpenter ants. Swarmed into the tree this past May.', 'Living Tree', 'Bee Keeper', 'jketchu@twcny.rr.com', 'NY', 'Rathburn Road', 'Oswego', '13126', '', '315-532-6864', 'Yes', 570);
