INSERT INTO `honeybee1` VALUES ('2009-06-29 09:28:55', 'Joe Nicolay', -76.428192, 36.450562, 'Bees are located in a large Oak tree in the front yard of a residential home. Bees are about fourteen feet off the ground and have been in this tree for several years according to homeowner. ', 'Living Tree', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '369 Long Lane', 'Elizabeth City', '27909', '', '757-482-2018', 'Yes', 572);
