INSERT INTO `honeybee1` VALUES ('2009-01-16 12:24:32', 'linda murphy', -76.342430, 41.857307, '"sycamore tree approx. 15 ft. above ground\r(photo available)\rLast visit revealed that it had been removed from location"', 'Living Tree', 'Concerned Citiz', 'orwell@cableracer.co', 'PA', '', 'Rome', '18837', '', '', 'Yes', 574);
INSERT INTO `honeybee1` VALUES ('2009-06-29 08:50:58', 'Joe Nicolay', -76.331291, 36.243027, 'Hive is located in the base of a walnut tree along the side of a creek. According to landowner bees have been there several years. ', 'Living Tree', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '1777 Ocean Hwy. (Rt.', 'Elizabeth City', '27909', '', '757-482-2018', 'Yes', 575);
INSERT INTO `honeybee1` VALUES ('2009-06-29 08:57:04', 'Joe Nicolay', -76.330948, 36.242889, 'Hive is located in a fallen tree due to hurricane Isabel in 2003. It is located in deep underbrush in a swamp. This is the second hive located on farmers property of 20 acres. Farmer does not want it removed.', 'Living Tree', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '1777 Ocean Hwy. (Rt.', 'Elizabeth City', '27909', '', '757-482-2018', 'Yes', 576);
INSERT INTO `honeybee1` VALUES ('2010-07-28 22:30:09', 'John Bishop', -76.329041, 42.922478, '10 feet high in a hickory tree 5 yearsswarms every year', 'Living Tree', 'Bee Keeper', 'jlbishop@twcny.rr.co', 'NY', 'schuyler rd.', 'syracuse', '13110', '', '315-263-3056', 'Yes', 577);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -76.323914, 36.245796, 'Homeowner said bees showed up summmer of 2008. A colony of bees were removed by me in summer of 2007 at same location. Homeowner would like them removed once samples are taken. Bees are located B/T first and second floor of a two story house. ', 'Manmade structure', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '808 Okisko Road', 'Elizabeth City', '27909', '', '757-482-2018', 'Yes', 578);
INSERT INTO `honeybee1` VALUES ('2009-07-01 20:53:39', 'Lin. Potter', -76.315147, 36.274422, 'Colony located 2ft. from ground in the base of a live tree. It''s been there for 3-4 yrs.', 'Living Tree', 'Bee Keeper', 'tarheellin@yahoo.com', 'NC', '906 Foreman-Bundy Ro', 'Elizabeth City', '27909', '', '2522323095', 'Yes', 579);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Barbra H', -76.305672, 36.835735, '"2 colonies are located within the structure of the apartment building.\rOne very large colony is located within a decorative pediment above the glassed in main entrance bees can be heard in the wall of the stairwell between 1st and 2nd floor. The 2nd colony is in a 3rd floor outer wall and enter thru mortar on Green St. One colony is believed to have been there perhaps 5 years."', 'Manmade structure', 'Bee Keeper', 'swansong65@yahoo.com', 'VA', '454 Green St', 'Portsmouth', '23704', '"Apartment owner has sprayed the colonies several times with pestacides in an effort to get rid of the hives.\rUnable to remove colonies at this time because apartment is a crime scene still under investigation."', '757-228-1702', 'Yes', 580);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Barbra H', -76.301506, 36.838451, 'If standing on Court St facing the appartment building there will be an alley way to the right side of the building. Within the alley you will find porches/decks accedded from the alley. The bees are located within the deck floor of the 3rd floor appartment above the second floor deck. Bees can be seen coming and going from the decking while standing at ground level.', 'Manmade structure', 'Bee Keeper', 'swansong65@yahoo.com', 'VA', '344 Court St', 'Portsmouth', '23704', 'Realtor is a jerk who has angered every area beekeeper so no one will remove the bees for her.', '757-228-1702', 'Yes', 581);
INSERT INTO `honeybee1` VALUES ('2011-07-02 11:35:17', 'Barbra Hickey', -76.283401, 36.862694, 'Hive located in large live pin oak along main drive toward the back wall within Elmwood Cemetary. Colony is perhaps 15 to 20 feet from the ground and bees enter thru large knot hole. Appears to be very large active colony that has probably been there for years and years. ', 'Living Tree', 'Bee Keeper', 'swansong65@yahoo.com', 'VA', '238 E Princess Anne ', 'Norfolk', '23517', '', '757-228-1702', 'Yes', 582);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -76.225700, 36.300529, 'hive is located in the sofit area of the east side of the house approx. 30ft off the ground. This house is the oldest registered home in the city dated 1853. ', 'Manmade structure', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '400W. Main St.', 'Elizabeth City', '27909', 'The homeowners are requesting a removal to be done the weekof July 21st 2008. I first investigated the hive in August of 2007. The third floor attic space disclosed a hive that appears to have been there a long time. ', '757-651-6543', 'Yes', 583);
INSERT INTO `honeybee1` VALUES ('2011-10-27 19:31:52', 'Donna Stickrod', -76.225258, 36.640652, 'The hive is in a living tree it has two entrances. The bottom entrance is about 3 feet off the ground and the upper entrance is about 12 feet off the ground. Bees have been in that tree for nearly 20 years according to reports.', 'Living Tree', 'Bee Keeper', 'yellowrock60@yahoo.c', 'VA', '225 Sign Pine Road', 'Chesapeake', '23322', 'It is located on a commercial nursery. It is about 5 feet off one of the roads in the nursery facing the road (Southeast). ', '7575361174', 'Yes', 584);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'mike martino', -76.213692, 43.060905, 'sw corner of home 12 ft 3yrs', 'Manmade structure', 'Bee Keeper', '', 'NY', '113 e 2nd st', 'e. syracuse ', '13057', '', '315 4639582', 'Yes', 585);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -76.210793, 36.274864, 'Hive was located 20ft off the ground in the A frame pitch of the roof line structure of the contemporary home. It was removed by the request of the homeowner July 2 2008. ', 'Manmade structure', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '1806 Hedgewood Dr.', 'Elizabeth City', '27909', ' It currently resides in a bee yard. The queen was not recovered. ', '757-651-6543', 'Yes', 586);
