INSERT INTO `honeybee1` VALUES ('2009-08-18 22:00:32', 'Lin. Potter', -76.175713, 36.250801, 'Located in a 92 acre logging operation. Bees were in an old rotten Oak. Nest about 2''X5''. Tree cut down broke apart bees and combs scattered.', 'Dead Tree', 'Bee Keeper', 'tarheellin@yahoo.com', 'NC', '1108 Hwy. 343 North', 'South Mills', '27976', '', '2522323095', 'Yes', 591);
INSERT INTO `honeybee1` VALUES ('2009-06-09 09:49:23', 'Lin. Potter', -76.160957, 36.521210, 'Small swarm about 1 1/2 lbs. located in the ground in a water meter box. Bees removed joined with another swarm and requeened.', 'In the ground', 'Bee Keeper', 'tarheellin@yahoo.com', 'NC', '107 Tabby St.', 'Moyock', '27958', '', '2522323095', 'Yes', 592);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -76.150536, 36.482174, 'Hive was located in a birdhouse nailed on a tree limb approx. 14ft up. Bees have been in the birdhouse for two years. Customer wanted it removed because bees were getting into her house. Birdhouse was removed Sep. 14th. ', 'Manmade structure', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '174 Ranchland Drive', 'Moyock', '27958', 'Birdhouse was removed from the tree and taken to apiary yard but will be left in the birdhouse until next spring. There is an additional birdhouse located in the same tree that has bees in it too. The customer said she wanted to keep that one for the time being. She felt the one closest to the house was where the bees were coming from that were getting into her home. She has my phone number! ', '757-482-2018', 'Yes', 593);
INSERT INTO `honeybee1` VALUES ('2009-06-29 09:11:09', 'Joe Nicolay', -76.147873, 36.488110, 'beehive', 'Living Tree', 'Concerned Citiz', 'jnicolay@cox.net', 'NC', '', '', '', '', '', 'Yes', 594);
