INSERT INTO `honeybee1` VALUES ('2008-10-27 16:00:50', 'Bob Evans', -76.025391, 42.488300, 'Open!Hanging on the branch of a maple tree.Can see 6-7 combs about 10 depth.22-26'' from ground. No one noticed it until the leaves fell.', 'Living Tree', 'Bee Keeper', 'livetrappingbymatt@c', 'NY', 'Sandhill Rd', 'Oneida', '13421', 'Yes it''s honey bees you can see them and count the wax combs!This will be interesting to track as the weather gets colder. ', '315-893-7526', 'Yes', 605);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -76.009941, 36.198158, 'Bees are located behind the back of a house where an addition had been put on the house. Appears they are located in the wall about seven feet. Homeowner wants them removed. Bees were checked in late summer of 2008. ', 'Manmade structure', 'Bee Keeper', 'jnicolay@cox.net', 'NC', '172 Texas Road', 'Shilo', '27909', '', '757-482-2018', 'Yes', 606);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Joe Nicolay', -75.949432, 36.350250, 'Hive is located about 2-feet off the ground inside a 6inch wood lapsided structure. The structure is an old Coast Guard Building built in 1880 and had been moved to the current location in 1959. Homeowner thinks the bees arrived in the spring of this year 2009 and wants the bees removed. Work on removal will begin mid August. ', 'Manmade structure', 'Bee Keeper', 'jjnicolay@cox.net', 'NC', '181 Coinjock Canal R', 'Coinjock', '27929', '', '757-482-2018', 'Yes', 607);
INSERT INTO `honeybee1` VALUES ('2008-10-30 17:44:54', 'Mark Emerson', -75.947113, 39.220284, 'Large Treewas cut by tree service and brought here. No idea of age. 4''x 18''. Very healthy and well populated. Began feeding to support for winter. Calm Bees. Many signs of another feral hive nearby.', 'Dead Tree', 'Bee Keeper', 'unbelizeablecat22@ya', 'MD', '120 Twin Oaks Farm L', 'Chestertown', '21620', 'Have 3 hives of my own and have seen many very dark smaller bees feeding at an open feeder.', '41007780409', 'Yes', 608);
INSERT INTO `honeybee1` VALUES ('2010-07-19 16:50:37', 'Patrick', -75.860123, 44.117264, 'It is about 6 feet off the ground we noticed it about 3 days ago. It is a little larger than a 2 liter bottle. It is hanging from a Blue Spruce tree.', 'Living Tree', 'Other', 'patrick.danforth@gma', 'NY', '25650 Keyser Rd', 'Evans Mills', '13637', '', '', 'Yes', 609);
