INSERT INTO `honeybee1` VALUES ('2010-03-07 17:38:47', 'Bill Wagner', -75.605080, 39.300964, 'In the backyard. there for over 5 years - after bees vacated the walls of the historic home. In a large tree about 8 feet from ground', 'Living Tree', 'Concerned Citiz', 'luluwagner4@aol.com', 'DE', '21 East Commerce Str', 'Smyrna', '19977', '', '3026530363', 'Yes', 620);
INSERT INTO `honeybee1` VALUES ('2010-05-22 15:25:24', 'Joshua Best', -75.555496, 41.622364, 'Tree colony. Entrance is approx. 7-8 ft. above ground. I believe this colony to be a swarm cast from one of my hives. It has been observed here since 2007.', 'Living Tree', 'Bee Keeper', 'melliphile@yahoo.com', 'PA', '123 Pierce Rd.', 'Greenfield Twp.', '18407', '', '570-877-8598', 'Yes', 621);
INSERT INTO `honeybee1` VALUES ('2010-07-01 15:22:48', 'Kevin Hansen', -75.516174, 39.164211, 'Colony in an old tree mostly dead in a hole/rotten spot about 2 meters off the ground. The tree was inside the grounds of the factory but right against the highway - very noisy! Colony was very active (2008).', 'Dead Tree', 'Concerned Citiz', 'hankaiwen@gmail.com', 'DE', 'Old Factory on highw', 'Dover', 'unknown', '', '505-818-7217', 'Yes', 622);
INSERT INTO `honeybee1` VALUES ('2010-05-22 15:50:30', 'Joshua Best', -75.498848, 41.571861, 'Living tree. Approx 15 ft. above ground. Homeowner reports observing hive since about 2006.', 'Living Tree', 'Bee Keeper', 'melliphile@yahoo.com', 'PA', '', 'Carbondale', '18407', '', '570-877-8598', 'Yes', 623);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Debra Goerger', -75.426804, 39.080772, 'A moderate sized hive is found in the north end of the Kingston Upon Hull historical building.It is approx. 12 ft. off the ground between the first and second story of the building. We have noticed the hive for the past year. It seems very well established. ', 'Manmade structure', 'Bee Keeper', 'bee-charmer@comcast.', 'DE', 'Kitts Hummock Road', 'Kitts Hummock', '', 'To get to Kingston Upon Hull take rt 113 southbound (from Dover) past Dover Air Force Base. Take the Rte 9 ramp. Drive approx .5 miles and turn right on Kitts Hummock Road. Pass the St Jones Reserve and the Dickinson Plantation on the right. Take a right at the Harvey Nature/Wildlife Reserve. Follow the gravel/dirt road straight back (do NOT take the left fork in the road)until it ends. The road ends at Kingston Upon Hull. ', '302-270-0706', 'Yes', 624);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Debra Goerger', -75.426804, 39.080772, 'A moderate sized hive is found in the north end of the Kingston Upon Hull historical building.It is approx. 12 ft. off the ground between the first and second story of the building. We have noticed the hive for the past year. It seems very well established. ', 'Manmade structure', 'Bee Keeper', 'bee-charmer@comcast.', 'DE', 'Kitts Hummock Road', 'Kitts Hummock', '', 'To get to Kingston Upon Hull take rt 113 southbound (from Dover) past Dover Air Force Base. Take the Rte 9 ramp. Drive approx .5 miles and turn right on Kitts Hummock Road. Pass the St Jones Reserve and the Dickinson Plantation on the right. Take a right at the Harvey Nature/Wildlife Reserve. Follow the gravel/dirt road straight back (do NOT take the left fork in the road)until it ends. The road ends at Kingston Upon Hull. ', '302-270-0706', 'Yes', 625);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Phil Youngs', -75.305786, 42.313877, 'Hive is 15 foot from ground in the side of a building. We use the building for a club. I am considering replacing the panaling inside and replacing it with plexiglass. Bees have been here for at least 10 years. The hive will swarm and split at least once a year.', 'Manmade structure', 'Concerned Citiz', 'darlin840@frontierne', 'NY', '840 county hwy.2', 'unadilla', '13849', '', '607-563-1710', 'Yes', 626);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'D Goerger', -75.254288, 39.045322, 'Hive is located 18 ft above ground in the walls of the abandoned Kingston Upon Hull building located at the end of the drive of the Ted Harvey Wildlife Area off of Kitts Hummock Rd.', 'Manmade structure', 'Bee Keeper', 'bee-charmer@comcast.', 'DE', 'Logan Lane ', 'Magnolia', '19901', 'This area is fenced in to protect the remains of the building and is listed with no tresspassing signs. ', '302-270-0706', 'Yes', 627);
INSERT INTO `honeybee1` VALUES ('2010-05-12 10:12:32', 'Vince E Camiolo', -75.050003, 40.289444, 'In a hole of a tulip poplar tree about 25 feet off the ground. It''s been in our backyard for 3 years.', 'Living Tree', 'Concerned Citiz', 'vcamiolo@yahoo.com', 'PA', '140 Vista Dr', 'Warminster', '18974-2325', '', '215-674-1113', 'Yes', 628);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'George Sereduk', -74.975533, 40.404743, '"Bees are in a hive located in the eaves above the 3rd floor of the Parsonage of the Stockton Presbyterian Church. Church members have estimated the bees to be residents there for 20 years.\rI''m a friend of the Pastor family but I have their permission to contact you with this info re: your project"', 'Manmade structure', 'Bee Keeper', 'wooduk@optonline.net', 'NJ', '22 South Main St', 'Stockton', '8559', '', '609-954-4232', 'Yes', 629);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'John C.', -74.323265, 40.625214, 'Obtained two honeybee colonies from a beekeeper that passed away in 2007. These hives were acquired during Sept. 2010. They have not had any human interaction since at least 2007. The one colony is very strong for not having any human assistance. I have not treated them with any chemicals and will only feed them sugar water this fall.', 'Manmade structure', 'Bee Keeper', '67corvette427@comcas', 'NJ', '', 'Clark', '7066', '', '908-420-4718', 'Yes', 630);
INSERT INTO `honeybee1` VALUES ('2010-04-12 12:01:07', 'Laura Nywening', -74.259041, 41.381413, 'The hive is at least 15 feet up in a Walnut Tree that has been partially cut down. It''s been there for as long as I can remember.', 'Living Tree', 'Other', 'LNywening@gmail.com', 'NY', '113 Johnson Road', 'Chester', '10918', 'The hive is at my grandparents'' house. I do not live there anymore but would like someone with a little more information to check them out. There are commercial hives not far away and I would hate for these bees to be carrying diseases that are making their jobs more difficult.', '845-913-6187', 'Yes', 631);
INSERT INTO `honeybee1` VALUES ('2009-08-31 14:20:33', 'Kim Pfeiffer', -74.174568, 43.101933, 'In a very large old tree in the back yard there''s a hole about 3inch to 5 in diameter and about 12'' or so off the ground. The tree is very large maybe 100'' tall with two 3'' to 4'' diameter trunks. I am not a bee person but it seems like there are a lot of bees in this tree.', 'Living Tree', 'Concerned Citiz', 'kimpfeiff@aol.com', 'NY', '666 Lakeview Road', 'Broadalbin', '12025', '', '203-723-2902', 'Yes', 632);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Sandra Eckler', -74.005997, 40.714401, 'In wall of building 8 feet from ground is entrance of hive facing North. At least 20 years in same location. Several years ago raided by squirrels thought they died out but they rebounded. Healthy nest now. They have a home as long as they want it.', 'Manmade structure', 'Other', 'JECKLER@roadrunner.c', 'NY', '1822 Wagners Hollow ', 'Fort Plain', '13339', '', '518-993-2883', 'Yes', 633);
INSERT INTO `honeybee1` VALUES ('2008-10-09 08:22:09', 'Jennifer Ford', -73.992279, 42.733932, '"40 feet off of the ground. Cannot tell size. Unsure as to how long it has been there but found one year ago. Older comb found at site would indicate it is more than one year old.\r"', 'Living Tree', 'Bee Keeper', 'jsf@nycap.rr.com', 'NY', 'State Route 158', 'Guilderland', '12009', 'In an old oak tree in the woods behind our house. Difficult to get to or find. Would need our help to locate.', '518-861-1019', 'Yes', 634);
INSERT INTO `honeybee1` VALUES ('2010-06-19 17:51:58', 'Matthew Wills', -73.991798, 40.654999, 'Nest/hive is entered through a hole facing east 25-30 ft up in a mature (red or black) oak tree in Green-Wood Cemetery Brooklyn; first noticed earlier this spring (2010). Location by cemetery roads: intersection of Green-Bough Ave. and Fern Ave by Holly Path.', 'Living Tree', 'Concerned Citiz', 'matthewwills@earthli', 'NY', '500 25th Street', 'New York (Brooklyn)', '11232', '', '718.237.2964', 'Yes', 635);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'B. Melon', -73.982018, 42.612991, 'Inside wall of abandoned summer camp. Swarm captured from this hive 6/10/2010', 'Manmade structure', 'Bee Keeper', 'bills@soundingstone.', 'NY', '90 Indian Ledge Rd', 'Voorheesville', '12186', '', '6666666666', 'Yes', 636);
INSERT INTO `honeybee1` VALUES ('2010-09-21 13:49:47', 'Matthew Wills', -73.976334, 40.690578, 'White ash tree (tree is IDed with stand-alone sign part of old tree ID program) just to west of tennis courts in Fort Green Park. Tree is between courts and path. Hive entrance is in obvious slit in wood about 6 feet up bole east side of tree.', 'Living Tree', 'Concerned Citiz', 'matthewwills@earthli', 'NY', 'DeKalb Ave. & S. Ell', 'Brooklyn', '', '', '', 'Yes', 637);
INSERT INTO `honeybee1` VALUES ('2008-10-28 19:31:34', 'Gus Ose', -73.969391, 41.726448, 'Hive is in a live pine tree. About twenty feet up. Three inch hole can be seen from the road. On private property.Has been there at least five years.', 'Living Tree', 'Bee Keeper', 'gusjeose@aol.com', 'NY', 'New Paltz Road', 'Highland', '12528', '', '845-691-8069', 'Yes', 638);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Gus Ose', -73.961617, 41.787197, 'This hive is ten feet up in the wall of a building. Looks very busy.Cannot tell how big it is. Has been there at least three years.', 'Manmade structure', 'Bee Keeper', 'gusjeose@aol.com', 'NY', 'Route 9 W', 'West Park', '12493', 'Hive is on private property belonging to an the order of Christian Brothers.I removed one large hive from this building.', '845-691-8069', 'Yes', 639);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Christopher Smart', -73.895119, 41.686172, '15 feet off ground in brick wall south side of Main Building at Vassar College (approximately second floor level). Hive has been in apparent good health for several years and has spawned swarms every spring I have been observing it.', 'Manmade structure', 'Bee Keeper', 'chsmart@vassar.edu', 'NY', '124 Raymond Avenue', 'Poughkeepsie', '12604', '', '845-416-4060', 'Yes', 640);
INSERT INTO `honeybee1` VALUES ('2011-06-26 17:13:52', '', -73.718178, 42.783180, 'beehive', 'Living Tree', 'Concerned Citiz', '', 'NC', '', '', '', '', '', 'Yes', 641);
INSERT INTO `honeybee1` VALUES ('2012-04-28 10:30:27', 'M. J. Dore', -73.509521, 43.052834, 'The hive is about 10 feet off the ground. It is in a decaying tree with an open hollow facing the road. I noticed the hive April 23 2012 while walking my dogs. I heard a lot of buzzing and noticed a lot of bee traffic in and out of the opening. ', 'Living Tree', 'Concerned Citiz', 'doremarilyn@yahoo.co', 'NY', '291 Ryan Rd.', 'Greenwich', '12834', '', '518-692-3304', 'Yes', 642);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'James Ballard', -73.463776, 43.070518, 'entry hole at 6'' above the ground in the wall cavity of an abandoned barn. approximately there one tear. Dark and aggressive bees may be russian or hybrid carnolian but definitely not italian. They appear healthy and actively foraging. Structural removal in progress attempting to rehive the bees. Owner does not want to be stung and they are very defensive about lawnmowing.', 'Manmade structure', 'Bee Keeper', 'jamesballard.archite', 'NY', 'Tabor Road', 'Greenwich', '', '', '9176588113', 'Yes', 643);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Peaked Hill Apiary', -71.559715, 43.231365, 'Newly developed hive located in a two story house. Hive consisted of several (4) elephant ear combs at the header of first story wall approx. 10 feet of the ground. Three pounds of bees were taken via bee vac and relocated at apiary north of Concord.', 'Manmade structure', 'Bee Keeper', 'PeakedHillApiary@gma', 'NH', '', 'Newmarket', '', '', '603-361-6212', 'Yes', 644);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Peaked Hill Apiary', -71.558998, 43.230999, 'Hive was located 20 feet of ground. It was within the confines of the gabel end of a roof next to a rock chimney in a log home. The hive was approximately 10 years of age. ', 'Manmade structure', 'Bee Keeper', 'Peaked Hill Apairy', 'VT', '', '', '', ' no location give - ronnie ', '603 361 6212', 'No', 645);
INSERT INTO `honeybee1` VALUES ('2008-12-01 18:35:26', 'AG', -71.478859, 42.522980, 'In a hole about 15 feet up a tree next to the road on the right hand side as you go between Harwood Ave and Foster Street. I first noticed it in 2007 but may have been there before. ', 'Living Tree', 'Bee Keeper', 'rospletha@gmail.com', 'MA', '#? Tahattawan Road', 'Littleton', '1460', 'Entered by Ann Grace', '978-952-6753', 'Yes', 646);
INSERT INTO `honeybee1` VALUES ('2009-06-10 16:16:56', 'Robert McHenry', -71.472832, 43.238174, 'Beehives next to house.', 'Manmade Beehive', 'Bee Keeper', 'robertmchenry@comcas', 'NH', '2 Autumn Dr', 'Concord', '3301', '', '6032270225', 'Yes', 647);
INSERT INTO `honeybee1` VALUES ('2008-10-04 07:51:57', 'Jamie McNamee', -71.462997, 42.776443, '20'' off the ground in a live Oak on the left at the end of the dead end street just before the driveway begins. About 2 years old. Has swarmed at least once.', 'Living Tree', 'Bee Keeper', 'jamiemcnamee@gmail.c', 'NC', '53 Chester Street', 'Nashua', '3064', '', '603-566-2526', 'Yes', 648);
INSERT INTO `honeybee1` VALUES ('2009-04-05 17:26:24', 'Marlene Bishop', -71.347748, 42.879929, 'The hive is about 2 feet off the ground in a hollow tree. it is right in the middle of a new building project.It has been there for at least two years that I know of. ', 'Living Tree', 'Bee Keeper', 'crzybishma@yahoo.com', 'NH', 'Hovey Road', 'Londonderry', '3053', '', '6034900826', 'Yes', 649);
INSERT INTO `honeybee1` VALUES ('2012-03-12 18:49:45', 'Marty Jessel Hive On', -71.115448, 42.748020, '2 feet off ground live willow tree. Deas end raod near farm field. Hive has been there at least 2 years. Managed hives with in eye shot. Map shows Haverhill as location but Bradford is a part of Haverhill', 'Living Tree', 'Bee Keeper', 'm.jessel@comcast.net', 'MA', '318 Ferry rd', 'Bradford', '1835', '', '978-994-0884', 'Yes', 650);
INSERT INTO `honeybee1` VALUES ('2009-08-24 07:53:49', 'Cameron Barth', -71.004379, 43.092834, 'The hive is located in a hole in a live healthy tree 10 feet off the ground. There are three entrances and the largest is about 18 inches long. It''s located behind the second house on the right on Hobbs Road between the house and the river. It''s hard to tell how long it has been there but it is very active and you can smell the honey as you as you approach.', 'Living Tree', 'Other', 'nadeau.t@comcast.net', 'NH', 'Hobbs Road', 'Lee', '3861', '', '603-659-4181', 'Yes', 651);
INSERT INTO `honeybee1` VALUES ('2009-08-24 07:54:07', 'Cameron Barth', -71.004379, 43.092834, 'The hive is located in a hole in a live healthy tree 10 feet off the ground. There are three entrances and the largest is about 18 inches long. It''s located behind the second house on the right on Hobbs Road between the house and the river. It''s hard to tell how long it has been there but it is very active and you can smell the honey as you as you approach.', 'Living Tree', 'Other', 'nadeau.t@comcast.net', 'NH', 'Hobbs Road', 'Lee', '3861', '', '603-659-4181', 'Yes', 652);
INSERT INTO `honeybee1` VALUES ('2008-10-10 21:46:23', 'James Koester', -70.938019, 42.814285, 'The hive is in an old oak tree about 20 feet above the ground. It is on the left hand side of Emery Lane almost at the foot bridge going over the Artichoke River. The hive has been there for at least 3 years (as of the summer of 2008).', 'Living Tree', 'Bee Keeper', 'jameskoester@ssje.or', 'MA', '21 Emery Lane', 'West Newbury', '1985', '', '978-853-1109', 'Yes', 653);
INSERT INTO `honeybee1` VALUES ('2012-08-02 23:12:34', 'Philip''s House', -70.925034, 42.818203, 'These bees are in my wall in the kitchen south side of the house. I''ve been in contact with the local beekeeper association in Essex County and they are going to help me move them in the spring to a new home.', 'Manmade structure', 'Concerned Citiz', 'pcootey@hotmail.com', 'MA', '22 Phillips Drive', 'Newburyport', '1950', 'There are a couple of farms in the area (couple miles away) who are raising honey bees. These fellas might be cousines from the farm.', '978-462-4970', 'Yes', 654);
INSERT INTO `honeybee1` VALUES ('2008-12-22 20:30:54', 'Erin Forbes', -70.314857, 43.676254, 'Swarm issued from backyard beekeeper (first year) colony. Issuing colony was an overwintered nuc purchased from New England beekeeper.', 'Living Tree', 'Bee Keeper', 'queenbee@overlandhon', 'ME', '144 Devon Street', 'Portland', '4102', '', '2078384046', 'Yes', 655);
