INSERT INTO `honeybee1` VALUES ('2012-10-25 04:14:54', 'Bonnita Wilson Claus', -112.283951, 33.564129, '7 to 8 month old hive under my Tuffshed.  Believe \r\nare Erupean Bees.   Have stood very close to \r\nwatch them, yrd men cleaned around them.  \r\nIncluding a man that forgot that they were there \r\nan whacked weeds up tp the entrance.  Plan to \r\nstart looking for old dead Bees near rhe entrance, \r\nto make sure they are not Afrencan Bees.  I woul \r\nbe surprised if they are.  One got in my house, \r\nroad outside on my finger.  Wish to keep updated.', 'Manmade structure', '', 'bonnitaclaus@me.com', '', '', '', '', '', '', '', 778);
